function metaScopesForPlatform(platform = "meta") {
  if (platform === "instagram") return metaInstagramScopes;
  return metaScopes;
}

function metaOAuthScopesForRequest(platform = "meta", options = {}) {
  if (options.testingPages && platform !== "instagram") return metaFacebookTestingScopes;
  return metaScopesForPlatform(platform);
}

