function servicePortalAuditForReadiness(serviceId = "", auditById = new Map()) {
  if (auditById.has(serviceId)) return auditById.get(serviceId);
  if (serviceId === "google_growth") return auditById.get("youtube") || null;
  return null;
}

function serviceReadinessRows(stack, auditById = new Map()) {
  return stack.map(service => {
    const missingEnv = service.env.filter(name => !envPresent(name));
    const optionalMissingEnv = (service.optionalEnv || []).filter(name => !envPresent(name));
    const portalAudit = servicePortalAuditForReadiness(service.id, auditById);
    const configured = Boolean(service.configured());
    const envReady = missingEnv.length === 0 && configured;
    const portalReady = portalAudit ? Boolean(portalAudit.ready) : true;
    return {
      id: service.id,
      name: service.name,
      purpose: service.purpose,
      configured,
      ready: envReady && portalReady,
      missingEnv,
      optionalMissingEnv,
      acceptedEnv: envAcceptedMap([...service.env, ...(service.optionalEnv || [])]),
      firstUse: service.firstUse,
      portalStatus: portalAudit?.status || "",
      portalReady,
      portalBlocker: portalAudit?.blocker || "",
      nextAction: portalAudit?.nextAction || "",
      callback: portalAudit?.callback || "",
      portalRoute: portalAudit?.portalRoute || providerPortalRoute(service.id)
    };
  });
}

function publicServiceReadiness() {
  return [...serviceReadinessRows(coreServiceStack), ...serviceReadinessRows(providerServiceStack)];
}

function serviceCredentialUnlocks(providerRows = []) {
  return providerRows
    .flatMap(service => {
      const missingRequired = service.missingEnv || [];
      const missingOptional = service.optionalMissingEnv || [];
      const required = missingRequired.map(name => ({
        providerId: service.id,
        provider: service.name,
        kind: "required",
        env: name,
        acceptedNames: service.acceptedEnv?.[name] || envAcceptedNames(name),
        priority: missingRequired.length === 1 ? 100 : 90,
        nextAction: `Add ${name} to Vercel production, redeploy, then test ${service.firstUse}.`,
        statusRoute: service.firstUse,
        portalRoute: service.portalRoute || providerPortalRoute(service.id)
      }));
      const optional = missingOptional.map(name => ({
        providerId: service.id,
        provider: service.name,
        kind: "optional",
        env: name,
        acceptedNames: service.acceptedEnv?.[name] || envAcceptedNames(name),
        priority: 35,
        nextAction: `Add optional ${name} when the base OAuth/read lane is working.`,
        statusRoute: service.firstUse,
        portalRoute: service.portalRoute || providerPortalRoute(service.id)
      }));
      return [...required, ...optional];
    })
    .sort((a, b) => b.priority - a.priority || a.provider.localeCompare(b.provider) || a.env.localeCompare(b.env));
}

