function providerPortalRoute(providerId = "") {
  return providerPortalRoutes[providerId] || "";
}

function platformDisplayName(platformId = "") {
  return platforms.find(item => item.id === platformId)?.name || platformId || "Provider";
}

function platformServiceId(platformId) {
  return providerTruthServiceMap[platformId] || platformId;
}

function providerCredentialFamily(accountOrPlatform = {}) {
  const account = typeof accountOrPlatform === "string" ? { platform: accountOrPlatform } : accountOrPlatform || {};
  const provider = String(account.oauthProvider || account.provider || account.platform || "").toLowerCase();
  if (["meta", "facebook"].includes(provider)) return "meta";
  if (provider === "google" || ["youtube", "google_growth", "google_business"].includes(account.platform)) return "google";
  return provider || String(account.platform || "").toLowerCase();
}

function providerIdentityEvidence(account = {}) {
  const platform = canonicalProviderAssetPlatform(account.platform || account.provider || account.oauthProvider || "");
  const providerAccountId = String(account.providerAccountId || account.provider_account_id || "").trim();
  const syntheticLocalIdentity = runtimeMode !== "vercel" && /^(?:test|fake)-/i.test(providerAccountId);
  if (!providerAccountId) return { verified: false, reason: "missing-provider-identity", platform, providerAccountId };
  if (syntheticLocalIdentity) return { verified: true, reason: "synthetic-test-identity", platform, providerAccountId };
  if (/^(?:acct|account|placeholder)(?:-|$)/i.test(providerAccountId)) {
    return { verified: false, reason: "placeholder-identity", platform, providerAccountId };
  }
  const validators = {
    meta: value => /^\d{5,}$/.test(value),
    facebook: value => /^\d{5,}$/.test(value),
    instagram: value => /^\d{5,}$/.test(value),
    threads: value => /^\d{5,}$/.test(value),
    x: value => /^\d{5,}$/.test(value),
    youtube: value => /^UC[\w-]{8,}$/.test(value),
    twitch: value => /^\d{5,}$/.test(value),
    discord: value => /^\d{5,}$/.test(value),
    etsy: value => /^\d{5,}$/.test(value),
    patreon: value => /^[A-Za-z0-9_-]{2,}$/.test(value),
    manychat: value => /^\d{5,}$/.test(value),
    shopify: value => /^[a-z0-9][a-z0-9-]*\.myshopify\.com$/i.test(value)
  };
  const verified = validators[platform] ? validators[platform](providerAccountId) : true;
  return { verified, reason: verified ? "verified-provider-identity" : "invalid-provider-identity", platform, providerAccountId };
}

function providerAssetKey(account = {}) {
  const platform = canonicalProviderAssetPlatform(account.platform || account.provider || "account");
  const identity = providerIdentityEvidence(account);
  return identity.providerAccountId ? `${platform}:${identity.providerAccountId}` : `${platform}:unverified`;
}

function providerAccountEvidenceTime(account = {}) {
  for (const value of [account.lastSyncedAt, account.updatedAt, account.connectedAt, account.createdAt]) {
    const parsed = Date.parse(value || "");
    if (Number.isFinite(parsed)) return parsed;
  }
  return 0;
}

function bestProviderAccountFromList(accounts = [], platform = "") {
  const candidates = accounts.filter(account => account.platform === platform);
  return [...candidates].sort((left, right) => {
    const leftState = providerAccountConnectionState(left);
    const rightState = providerAccountConnectionState(right);
    const score = state => state.connected ? 1000
      : state.identityVerified && state.tokenStored && state.refreshStored ? 850
      : state.identityVerified && state.tokenStored && !state.expired ? 700
      : state.identityVerified && state.tokenStored ? 550
      : state.identityVerified ? 300
      : state.tokenStored ? 100
      : 0;
    return score(rightState) - score(leftState)
      || providerAccountEvidenceTime(right) - providerAccountEvidenceTime(left)
      || String(left.providerAccountId || left.id || "").localeCompare(String(right.providerAccountId || right.id || ""));
  })[0] || null;
}

const selectableProviderPlatforms = new Set([
  "facebook", "instagram", "threads", "youtube", "x", "tiktok", "pinterest",
  "twitch", "discord", "etsy", "shopify", "canva", "manychat", "linkedin", "patreon",
  "google_business"
]);

function canonicalProviderAssetPlatform(platform = "") {
  if (platform === "google_growth") return "youtube";
  return String(platform || "").trim().toLowerCase();
}

function selectableProviderAsset(account = {}, platform = "") {
  if (platform !== "google_business") return true;
  return account.accountType === "google_business_location" || account.profile?.assetType === "location";
}

function providerAccountSelectionGroups(model = {}, platform = "", user = null) {
  const canonical = canonicalProviderAssetPlatform(platform);
  const candidates = (model.connectedAccounts || []).filter(account =>
    account.platform === canonical
    && (!user?.id || ownedByUser(account, user.id))
    && providerAccountConnectionState(account).connected
    && account.providerAccountId
    && selectableProviderAsset(account, canonical)
  );
  const groups = new Map();
  for (const account of candidates) {
    const key = providerAssetKey(account);
    const group = groups.get(key) || [];
    group.push(account);
    groups.set(key, group);
  }
  return [...groups.entries()].map(([assetKey, accounts]) => ({
    assetKey,
    accounts,
    account: bestProviderAccountFromList(accounts, canonical)
  })).filter(group => group.account);
}

function providerAccountsForSelection(model = {}, platform = "", user = null) {
  return providerAccountSelectionGroups(model, platform, user).map(group => group.account);
}

function selectedProviderAccount(model = {}, platform = "", user = null) {
  const canonical = canonicalProviderAssetPlatform(platform);
  const accounts = providerAccountsForSelection(model, canonical, user);
  const selectedId = String(model.activeProviderAccounts?.[canonical] || "");
  return accounts.find(account => String(account.providerAccountId) === selectedId)
    || bestProviderAccountFromList(accounts, canonical);
}

function ensureSelectedProviderAccount(model = {}, platform = "", user = null) {
  const canonical = canonicalProviderAssetPlatform(platform);
  const selected = selectedProviderAccount(model, canonical, user);
  model.activeProviderAccounts = model.activeProviderAccounts || {};
  if (selected?.providerAccountId && model.activeProviderAccounts[canonical] !== selected.providerAccountId) {
    model.activeProviderAccounts[canonical] = selected.providerAccountId;
  }
  return selected;
}

function providerAccountSelectionPayload(model = {}, user = null, platform = "") {
  const requested = canonicalProviderAssetPlatform(platform);
  const platforms = requested
    ? [requested]
    : [...selectableProviderPlatforms].filter(id => providerAccountsForSelection(model, id, user).length);
  const rows = platforms.map(id => {
    const groups = providerAccountSelectionGroups(model, id, user);
    const accounts = groups.map(group => group.account);
    const selected = selectedProviderAccount(model, id, user);
    return {
      platform: id,
      selectedProviderAccountId: selected?.providerAccountId || null,
      selectedAccount: selected ? publicAccount(selected) : null,
      accounts: groups.map(group => ({
        ...publicAccount(group.account),
        alternateCredentialFamilies: [...new Set(group.accounts.map(providerCredentialFamily))],
        credentialPathCount: group.accounts.length
      })),
      credentialPathCount: groups.reduce((total, group) => total + group.accounts.length, 0)
    };
  });
  return {
    ok: true,
    rows,
    selections: Object.fromEntries(rows.map(row => [row.platform, row.selectedProviderAccountId])),
    selectedCount: rows.filter(row => row.selectedProviderAccountId).length,
    assetCount: rows.reduce((total, row) => total + row.accounts.length, 0)
  };
}

function accountForTruth(platformId, accounts = [], model = {}) {
  const canonical = canonicalProviderAssetPlatform(platformId);
  const selectedId = String(model.activeProviderAccounts?.[canonical] || "");
  const selected = accounts.find(account =>
    account.platform === canonical
    && String(account.providerAccountId || "") === selectedId
    && (providerIdentityEvidence(account).verified || hasStoredToken(account))
  );
  const fallback = bestProviderAccountFromList(accounts, canonical);
  return selected || fallback || null;
}

function normalizedScopes(account = {}) {
  return (account.scopes || []).map(scope => String(scope).toLowerCase());
}

function hasAnyScope(account = {}, scopes = []) {
  const granted = normalizedScopes(account);
  return scopes.some(scope => granted.includes(String(scope).toLowerCase()));
}

function hasAllScopes(account = {}, scopes = []) {
  const granted = normalizedScopes(account);
  return scopes.every(scope => granted.includes(String(scope).toLowerCase()));
}

function providerTruthCapabilities(platformId, account = null) {
  if (!account || !providerAccountConnectionState(account).connected) return { canPublish: false, canReadAnalytics: false };
  const canPublish = {
    facebook: () => hasAnyScope(account, ["pages_manage_posts"]),
    instagram: () => hasAnyScope(account, ["instagram_content_publish", "instagram_business_content_publish"]),
    threads: () => hasAnyScope(account, ["threads_content_publish"]),
    youtube: () => hasAnyScope(account, ["https://www.googleapis.com/auth/youtube.upload", "youtube.upload"]),
    x: () => hasAnyScope(account, ["tweet.write"]),
    tiktok: () => hasAnyScope(account, ["video.upload", "video.publish"]),
    pinterest: () => hasAnyScope(account, ["pins:write"]),
    shopify: () => hasAnyScope(account, ["write_products", "write_marketing_events"]),
    etsy: () => hasAnyScope(account, ["listings_w"]),
    linkedin: () => linkedInAccountCanPublishOrganizationPost(account),
    twitch: () => hasAnyScope(account, ["clips:edit"]),
    discord: () => Boolean(
      discordBotToken
      && account.profile?.discordSelectedGuildId
      && account.profile?.discordSelectedChannelId
      && hasAnyScope(account, ["identify", "guilds"])
    ),
    canva: () => hasAnyScope(account, ["design:content:write", "asset:write"])
  }[platformId]?.() || false;
  const canReadAnalytics = {
    facebook: () => hasAnyScope(account, ["pages_read_engagement", "read_insights"]),
    instagram: () => hasAnyScope(account, ["instagram_manage_insights", "instagram_business_manage_insights"]),
    threads: () => hasAnyScope(account, ["threads_manage_insights"]),
    youtube: () => hasAnyScope(account, ["https://www.googleapis.com/auth/yt-analytics.readonly", "yt-analytics.readonly"]),
    x: () => hasAnyScope(account, ["tweet.read", "users.read"]),
    tiktok: () => hasAnyScope(account, ["video.list"]),
    pinterest: () => hasAnyScope(account, ["pins:read", "boards:read", "ads:read"]),
    shopify: () => hasAnyScope(account, ["read_products", "read_marketing_events"]),
    etsy: () => hasAnyScope(account, ["listings_r", "shops_r"]),
    linkedin: () => hasAnyScope(account, ["r_organization_social", "r_member_profileanalytics", "r_member_postanalytics"]),
    patreon: () => hasAnyScope(account, ["campaigns.members", "campaigns.posts"]),
    twitch: () => hasAnyScope(account, ["analytics:read:extensions", "analytics:read:games", "channel:read:subscriptions", "user:read:broadcast"]),
    discord: () => hasAnyScope(account, ["identify", "guilds"]),
    canva: () => hasAnyScope(account, ["design:meta:read", "asset:read"])
  }[platformId]?.() || false;
  return { canPublish, canReadAnalytics };
}

