function providerTruthActionForRow(row = {}) {
  if (!row.configured) {
    return {
      id: row.id,
      name: row.name,
      phase: "Configure",
      priority: 90,
      status: row.status,
      why: row.blockers?.[0] || "Developer credentials, callback, or portal setup is missing.",
      nextAction: row.nextAction,
      routes: row.routes
    };
  }
  if (!row.connected) {
    return {
      id: row.id,
      name: row.name,
      phase: "Connect",
      priority: 100,
      status: row.status,
      why: row.blockers?.[0] || "Credentials exist, but this workspace does not have a connected user/account asset yet.",
      nextAction: row.nextAction,
      routes: row.routes
    };
  }
  if (!row.canPublish || !row.canReadAnalytics) {
    const missing = [
      row.canPublish ? "" : "publish",
      row.canReadAnalytics ? "" : "analytics"
    ].filter(Boolean).join(" and ");
    return {
      id: row.id,
      name: row.name,
      phase: "Expand",
      priority: 75,
      status: row.status,
      why: `${missing} capability is not available from the stored account evidence yet.`,
      nextAction: row.nextAction,
      routes: row.routes
    };
  }
  if (row.blockers?.length) {
    return {
      id: row.id,
      name: row.name,
      phase: "Review",
      priority: 55,
      status: row.status,
      why: row.blockers[0],
      nextAction: row.nextAction,
      routes: row.routes
    };
  }
  return null;
}

function providerTruthActionRows(rows = []) {
  return rows
    .map(providerTruthActionForRow)
    .filter(Boolean)
    .sort((a, b) => b.priority - a.priority || a.name.localeCompare(b.name))
    .slice(0, 8);
}

function providerProbeAccount(providerId, model = {}, session = null) {
  const user = session?.user || null;
  const accounts = visibleConnectedAccounts(model)
    .filter(account => !user || !hasOwnerMarker(account) || ownedByUser(account, user.id));
  if (providerId === "google_growth") return accountForTruth("youtube", accounts, model);
  if (providerId === "google_business") return accountForTruth("google_business", accounts, model);
  return accountForTruth(providerId, accounts, model);
}

function compactProbeError(error) {
  return String(error?.message || error || "Provider read failed.").replace(/\s+/g, " ").slice(0, 220);
}

function providerProbeSkipped(providerId, summary) {
  return {
    attempted: false,
    ok: false,
    provider: providerId,
    endpoint: "",
    summary,
    evidence: {}
  };
}

function syntheticProbeToken(token = "") {
  return /^(fake|test|demo)[-_]/i.test(String(token || ""));
}

async function providerLiveProbe(providerId, model = {}, session = null, row = {}) {
  const account = providerProbeAccount(providerId, model, session);
  if (!account || !providerAccountConnectionState(account).connected) return providerProbeSkipped(providerId, "Live probe skipped until this workspace has a usable connected provider account.");
  if (!hasStoredToken(account)) return providerProbeSkipped(providerId, "Live probe skipped because no server-side token is stored.");
  try {
    if (providerId === "twitch") {
      const accessToken = decryptedToken(account.credential || account.token);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const users = await twitchApi("/users", {}, accessToken);
      const broadcaster = users?.data?.[0] || {};
      const channel = broadcaster.id ? await twitchApi("/channels", { broadcaster_id: broadcaster.id }, accessToken).catch(() => ({ data: [] })) : { data: [] };
      const clips = broadcaster.id ? await twitchApi("/clips", { broadcaster_id: broadcaster.id, first: "10" }, accessToken).catch(() => ({ data: [] })) : { data: [] };
      const channelRow = channel?.data?.[0] || {};
      return {
        attempted: true,
        ok: Boolean(broadcaster.id),
        provider: providerId,
        endpoint: "GET /helix/users",
        summary: broadcaster.display_name || broadcaster.login ? `Twitch responded for ${broadcaster.display_name || broadcaster.login}.` : "Twitch responded to the user probe.",
        evidence: {
          broadcasterId: broadcaster.id || account.providerAccountId || "",
          login: broadcaster.login || "",
          displayName: broadcaster.display_name || account.displayName || account.handle || "",
          channelTitle: channelRow.title || "",
          gameName: channelRow.game_name || "",
          clipCount: Array.isArray(clips?.data) ? clips.data.length : 0
        }
      };
    }
    if (providerId === "google_business") {
      let businessAccount = googleBusinessAccountWithScope(model, session?.user || null);
      if (!businessAccount) return providerProbeSkipped(providerId, "Connect Google Business Profile and approve business.manage before running a live location probe.");
      if (tokenExpiresSoon(businessAccount.tokenExpiresAt) || !tokenForYouTubeAccount(businessAccount)) {
        businessAccount = await refreshYouTubeAccount(model, businessAccount, session?.user || null);
      }
      const accessToken = tokenForYouTubeAccount(businessAccount);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const locationResource = safeGoogleBusinessLocationResource(account.providerAccountId || account.googleBusinessLocationResource);
      if (!locationResource) return providerProbeSkipped(providerId, "Select a discovered Google Business Profile location before running a live probe.");
      const location = await googleApi("https://mybusinessbusinessinformation.googleapis.com", `/v1/${locationResource}`, {
        readMask: googleBusinessLocationReadMask
      }, accessToken);
      return {
        attempted: true,
        ok: Boolean(location?.name),
        provider: providerId,
        endpoint: `GET /v1/${locationResource}`,
        summary: location?.title ? `Google Business Profile responded for ${location.title}.` : "Google Business Profile returned the selected location.",
        evidence: {
          locationResource: safeGoogleBusinessLocationResource(location?.name) || locationResource,
          title: location?.title || account.name || "",
          storeCode: location?.storeCode || "",
          websiteUri: location?.websiteUri || "",
          mapsUri: location?.metadata?.mapsUri || "",
          placeId: location?.metadata?.placeId || "",
          canOperateLocalPost: Boolean(location?.metadata?.canOperateLocalPost),
          hasVoiceOfMerchant: Boolean(location?.metadata?.hasVoiceOfMerchant)
        }
      };
    }
    if (providerId === "youtube" || providerId === "google_growth") {
      const youtubeAccount = await usableYouTubeAccount(model, { refresh: true, user: session?.user || null });
      const accessToken = tokenForYouTubeAccount(youtubeAccount);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const body = await youtubeData("/channels", {
        part: "id,snippet,statistics,status",
        mine: "true",
        fields: "items(id,snippet(title,customUrl),statistics(viewCount,subscriberCount,videoCount),status/privacyStatus)"
      }, accessToken);
      const channel = body?.items?.[0] || {};
      return {
        attempted: true,
        ok: Boolean(channel.id),
        provider: providerId,
        endpoint: "GET /youtube/v3/channels?mine=true",
        summary: channel.snippet?.title ? `YouTube responded for ${channel.snippet.title}.` : "YouTube responded to the channel probe.",
        evidence: {
          channelId: channel.id || account.providerAccountId || "",
          title: channel.snippet?.title || account.displayName || "",
          customUrl: channel.snippet?.customUrl || "",
          privacyStatus: channel.status?.privacyStatus || "",
          subscriberCount: channel.statistics?.subscriberCount || "",
          videoCount: channel.statistics?.videoCount || "",
          viewCount: channel.statistics?.viewCount || ""
        }
      };
    }
    if (providerId === "facebook") {
      const accessToken = tokenForMetaAccount(account);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const page = await metaGraph(`/${account.providerAccountId}`, { fields: "id,name,category,link,fan_count,followers_count" }, accessToken);
      return {
        attempted: true,
        ok: Boolean(page.id),
        provider: providerId,
        endpoint: "GET /{page-id}",
        summary: page.name ? `Meta responded for Facebook Page ${page.name}.` : "Meta responded to the Facebook Page probe.",
        evidence: {
          pageId: page.id || account.providerAccountId || "",
          name: page.name || account.displayName || "",
          category: page.category || "",
          followersCount: page.followers_count ?? "",
          fanCount: page.fan_count ?? ""
        }
      };
    }
    if (providerId === "instagram") {
      const accessToken = tokenForMetaAccount(account);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const fields = account.oauthProvider === "instagram" ? "id,user_id,username,account_type,media_count" : "id,username,name,media_count,followers_count";
      const ig = await instagramAccountGraph(account, "", { fields });
      return {
        attempted: true,
        ok: Boolean(ig.id),
        provider: providerId,
        endpoint: "GET /{ig-user-id}",
        summary: ig.username ? `Instagram responded for @${ig.username}.` : "Instagram responded to the account probe.",
        evidence: {
          instagramUserId: ig.id || account.providerAccountId || "",
          username: ig.username || account.handle || "",
          name: ig.name || account.displayName || "",
          accountType: ig.account_type || account.accountType || "",
          mediaCount: ig.media_count ?? "",
          followersCount: ig.followers_count ?? ""
        }
      };
    }
    if (providerId === "threads") {
      const accessToken = decryptedToken(account.credential || account.token);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const me = await threadsApi("/me", { fields: "id,username,name" }, accessToken);
      return {
        attempted: true,
        ok: Boolean(me.id),
        provider: providerId,
        endpoint: "GET /threads/me",
        summary: me.username ? `Threads responded for @${me.username}.` : "Threads responded to the account probe.",
        evidence: {
          accountId: me.id || account.providerAccountId || "",
          username: me.username || account.handle || "",
          name: me.name || account.displayName || ""
        }
      };
    }
    if (providerId === "discord") {
      const accessToken = tokenForDiscordAccount(account);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const user = await discordApi("/users/@me", {}, accessToken);
      const guilds = await discordApi("/users/@me/guilds", { limit: "20" }, accessToken).catch(() => []);
      return {
        attempted: true,
        ok: Boolean(user.id),
        provider: providerId,
        endpoint: "GET /users/@me",
        summary: user.username ? `Discord responded for @${user.username}.` : "Discord responded to the user probe.",
        evidence: {
          userId: user.id || account.providerAccountId || "",
          username: user.username || account.handle || "",
          globalName: user.global_name || account.displayName || "",
          guildCount: Array.isArray(guilds) ? guilds.length : account.profile?.guildCount ?? ""
        }
      };
    }
    if (providerId === "x") {
      const xAccount = await usableXAccount(model, { refresh: true, user: session?.user || null });
      const accessToken = tokenForXAccount(xAccount);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const body = await xApi("/users/me", { "user.fields": "id,name,username,verified,public_metrics" }, accessToken);
      const user = body?.data || {};
      return {
        attempted: true,
        ok: Boolean(user.id),
        provider: providerId,
        endpoint: "GET /2/users/me",
        summary: user.username ? `X responded for @${user.username}.` : "X responded to the user probe.",
        evidence: {
          userId: user.id || account.providerAccountId || "",
          username: user.username || account.handle || "",
          name: user.name || account.displayName || "",
          verified: Boolean(user.verified),
          followersCount: user.public_metrics?.followers_count ?? "",
          tweetCount: user.public_metrics?.tweet_count ?? ""
        }
      };
    }
    if (providerId === "tiktok") {
      const accessToken = tokenForTikTokAccount(account);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const scopeString = (account.scopes || []).join(" ");
      const body = await tiktokApi("/v2/user/info/", { fields: tiktokUserInfoFields(scopeString).join(",") }, accessToken);
      const user = body?.data?.user || {};
      return {
        attempted: true,
        ok: Boolean(user.open_id),
        provider: providerId,
        endpoint: "GET /v2/user/info",
        summary: user.display_name ? `TikTok responded for ${user.display_name}.` : "TikTok responded to the user probe.",
        evidence: {
          openId: user.open_id || account.providerAccountId || "",
          displayName: user.display_name || account.displayName || "",
          username: user.username || account.handle || "",
          followerCount: user.follower_count ?? "",
          videoCount: user.video_count ?? "",
          verified: Boolean(user.is_verified)
        }
      };
    }
    if (providerId === "pinterest") {
      const accessToken = decryptedToken(account.credential || account.token);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const boards = await pinterestApi("/boards", { page_size: "10" }, accessToken);
      const items = boards?.items || [];
      return {
        attempted: true,
        ok: true,
        provider: providerId,
        endpoint: "GET /v5/boards",
        summary: `Pinterest responded with ${items.length} board${items.length === 1 ? "" : "s"}.`,
        evidence: {
          boardCount: items.length,
          firstBoardId: items[0]?.id || "",
          firstBoardName: items[0]?.name || ""
        }
      };
    }
    if (providerId === "etsy") {
      const accessToken = decryptedToken(account.credential || account.token);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const userId = account.providerAccountId || account.userId;
      const shops = userId ? await etsyApi(`/application/users/${userId}/shops`, {}, accessToken) : { results: [] };
      const items = shops?.results || [];
      return {
        attempted: true,
        ok: true,
        provider: providerId,
        endpoint: "GET /v3/application/users/{user_id}/shops",
        summary: `Etsy responded with ${items.length} shop${items.length === 1 ? "" : "s"}.`,
        evidence: {
          shopCount: items.length,
          firstShopId: items[0]?.shop_id || "",
          firstShopName: items[0]?.shop_name || "",
          activeListingCount: items[0]?.listing_active_count ?? ""
        }
      };
    }
    if (providerId === "canva") {
      const accessToken = decryptedToken(account.credential || account.token);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const designs = await canvaApi("/designs", { limit: "10" }, accessToken);
      const items = designs?.items || [];
      return {
        attempted: true,
        ok: true,
        provider: providerId,
        endpoint: "GET /rest/v1/designs",
        summary: `Canva responded with ${items.length} design${items.length === 1 ? "" : "s"}.`,
        evidence: {
          designCount: items.length,
          firstDesignId: items[0]?.id || "",
          firstDesignTitle: items[0]?.title || ""
        }
      };
    }
    if (providerId === "shopify") {
      const accessToken = decryptedToken(account.credential || account.token);
      if (syntheticProbeToken(accessToken)) throw new Error("Synthetic test token; provider network probe intentionally skipped.");
      const shop = normalizeShopifyShop(account.providerAccountId || account.shop || account.handle || account.name || shopifyShopDomain);
      const body = await shopifyGraphql(shop, `query SocialCuesShopProbe { shop { id name myshopifyDomain } }`, {}, accessToken);
      const shopData = body?.data?.shop || {};
      return {
        attempted: true,
        ok: Boolean(shopData.id || shopData.myshopifyDomain),
        provider: providerId,
        endpoint: `POST /admin/api/${shopifyApiVersion}/graphql.json`,
        summary: shopData.name ? `Shopify responded for ${shopData.name}.` : "Shopify responded to the store probe.",
        evidence: {
          shopId: shopData.id || "",
          shopName: shopData.name || account.name || "",
          myshopifyDomain: shopData.myshopifyDomain || shop
        }
      };
    }
    return providerProbeSkipped(providerId, "No live read probe has been mapped for this provider yet.");
  } catch (error) {
    return {
      attempted: true,
      ok: false,
      provider: providerId,
      endpoint: providerTruthRoutes[providerId]?.status || "",
      summary: compactProbeError(error),
      evidence: {
        accountId: account.providerAccountId || "",
        displayName: account.displayName || account.name || account.handle || ""
      },
      error: compactProbeError(error)
    };
  }
}

function providerTruthCheckResult(row = {}, action = null, liveProbe = null) {
  const banked = Boolean(row.connected && row.tokenStored);
  const configured = Boolean(row.configured);
  const probe = liveProbe || providerProbeSkipped(row.id, "Live provider probe was not run.");
  const live = Boolean(banked && row.canPublish && row.canReadAnalytics && probe.attempted && probe.ok);
  const status = live ? "banked-live" : banked && row.canPublish && row.canReadAnalytics ? "banked-scope-ready" : banked ? "banked" : configured ? "ready-to-connect" : "needs-config";
  const probeSuffix = probe.attempted
    ? probe.ok
      ? ` Live probe passed: ${probe.summary}`
      : ` Live probe warning: ${probe.summary}`
    : ` ${probe.summary}`;
  return {
    at: new Date().toISOString(),
    id: row.id,
    label: `${row.name || row.id} provider action`,
    route: "/api/provider/action-check",
    ok: banked,
    status,
    phase: action?.phase || (banked ? "Banked" : configured ? "Connect" : "Configure"),
    summary: banked
      ? `${row.name || row.id} is banked: token stored, asset discovered${row.canPublish ? ", publish lane" : ""}${row.canReadAnalytics ? ", analytics lane" : ""}.${probeSuffix}`
      : `${row.name || row.id} is not banked yet: ${(row.blockers || [action?.why || "Next action required."])[0]}`,
    nextAction: banked ? "Keep this lane healthy; run provider-specific read/publish checks before live use." : action?.nextAction || row.nextAction,
    signals: {
      configured: row.configured,
      connected: row.connected,
      tokenStored: row.tokenStored,
      assetDiscovered: row.assetDiscovered,
      canPublish: row.canPublish,
      canReadAnalytics: row.canReadAnalytics
    },
    liveProbe: probe,
    blockers: row.blockers || []
  };
}

function providerTruthRows(model = {}, session = null) {
  const user = session?.user || null;
  const serviceRows = serviceReadinessRows(providerServiceStack);
  const serviceById = new Map(serviceRows.map(service => [service.id, service]));
  const portalAudit = developerPortalAudit();
  const portalById = new Map(portalAudit.rows.map(row => [row.id, row]));
  const accounts = visibleConnectedAccounts(model)
    .filter(account => !user || !hasOwnerMarker(account) || ownedByUser(account, user.id));
  const rows = platforms.map(platform => {
    const serviceId = platformServiceId(platform.id);
    const service = serviceById.get(serviceId) || null;
    const portal = portalById.get(platform.id) || portalById.get(serviceId) || null;
    const account = accountForTruth(platform.id, accounts, model);
    const connectionState = providerAccountConnectionState(account);
    const connected = connectionState.connected;
    const tokenStored = connectionState.tokenStored;
    const configured = Boolean(service?.configured || service?.ready);
    const missingEnv = service?.missingEnv || [];
    const capability = providerTruthCapabilities(platform.id, account);
    const blockers = [];
    if (!configured) blockers.push(missingEnv.length ? `Missing ${missingEnv.join(", ")}` : "Developer credentials are not configured.");
    if (configured && !connected) blockers.push("User OAuth/account asset is not connected for this workspace.");
    if (account && !tokenStored) blockers.push("No server-side token evidence is stored.");
    const supersededPortalBlocker = Boolean(
      connected
      && platform.id === "threads"
      && /1349168|callback URL is not saved/i.test(portal?.blocker || "")
    );
    if (!supersededPortalBlocker && portal?.blocker && (!portal.ready || /approval|review|gated|audit|blocked|missing|pending/i.test(portal.blocker))) blockers.push(portal.blocker);
    const status = connected
      ? "connected"
      : configured
      ? "needs-oauth"
      : "needs-config";
    const truthRow = {
      id: platform.id,
      name: platform.name,
      serviceId,
      status,
      configured,
      connected,
      tokenStored,
      assetDiscovered: connected,
      canPublish: capability.canPublish,
      canReadAnalytics: capability.canReadAnalytics,
      account: account ? publicAccount(account) : null,
      connectionState,
      missingEnv,
      blockers: [...new Set(blockers)].slice(0, 4),
      nextAction: connected
        ? "Run Check setup, then test the safest read/publish lane for this account."
        : configured
        ? "Connect this provider from Accounts while signed into the intended workspace."
        : portal?.nextAction || "Finish the developer app credentials, callback URL, and review fields.",
      routes: providerTruthRoutes[platform.id] || { status: service?.firstUse || "" }
    };
    truthRow.permissionExplainer = providerPermissionGapExplainer(platform.id, truthRow, account);
    return truthRow;
  });
  const nextProviderActions = providerTruthActionRows(rows);
  const bankedSuccesses = rows
    .filter(row => row.connected && row.tokenStored)
    .map(row => ({
      id: row.id,
      name: row.name,
      handle: row.account?.handle || row.account?.displayName || row.account?.name || "",
      canPublish: row.canPublish,
      canReadAnalytics: row.canReadAnalytics
    }));
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: user ? workspaceIdForUser(user) : model.workspace?.id || "public",
    summary: {
      total: rows.length,
      configured: rows.filter(row => row.configured).length,
      connected: rows.filter(row => row.connected).length,
      canPublish: rows.filter(row => row.canPublish).length,
      canReadAnalytics: rows.filter(row => row.canReadAnalytics).length,
      blocked: rows.filter(row => row.blockers.length).length,
      nextActionCount: nextProviderActions.length,
      banked: bankedSuccesses.length
    },
    nextProviderActions,
    bankedSuccesses,
    rows
  };
}

function providerFunctionCheck(model = {}, providerId = "") {
  const checks = model.functionChecks || {};
  if (providerId === "google_growth") return checks.google_growth || checks.youtube || checks.google || null;
  if (providerId === "google_business") return checks.google_business || checks.google || null;
  return checks[providerId] || null;
}

function providerPublishCheck(model = {}, providerId = "") {
  const checks = model.functionChecks || {};
  if (providerId === "google_growth") return checks.google_growth?.publishProbe || checks.youtube?.publishProbe || checks.google?.publishProbe || null;
  if (providerId === "google_business") return checks.google_business?.publishProbe || checks.google?.publishProbe || null;
  return checks[providerId]?.publishProbe || null;
}

function contentVariantBatches(model = {}) {
  return [
    ...(Array.isArray(model.campaigns) ? model.campaigns : []),
    ...(Array.isArray(model.quickPosts) ? model.quickPosts : [])
  ];
}

function latestProviderPublishAttempt(model = {}, provider = "") {
  let latest = null;
  for (const campaign of contentVariantBatches(model)) {
    for (const variant of campaign.variants || []) {
      if (variant.platform !== provider) continue;
      const attempt = variant.lastPublishAttempt || (Array.isArray(variant.publishAttempts) ? variant.publishAttempts[0] : null);
      if (!attempt) continue;
      if (!latest || Date.parse(attempt.at || "") > Date.parse(latest.at || "")) {
        latest = {
          at: attempt.at || "",
          provider,
          campaignId: campaign.id || "",
          campaignTitle: campaign.title || "",
          variantId: variant.id || "",
          ok: Boolean(attempt.ok),
          status: attempt.status || (attempt.ok ? "dry-run" : "blocked"),
          live: Boolean(attempt.result?.live),
          dryRun: attempt.result?.dryRun !== false,
          error: attempt.error || attempt.result?.error || "",
          nextAction: attempt.result?.nextAction || ""
        };
      }
    }
  }
  return latest;
}

function syntheticProviderPublishItem(providerId = "") {
  const platformId = providerId === "google_growth" ? "youtube" : providerId;
  const now = new Date().toISOString();
  const variant = {
    id: `provider-publish-check-${platformId}`,
    platform: platformId,
    status: "approved",
    scheduledFor: now,
    queuedAt: now,
    copy: "Social Cues provider acceptance dry-run. This is not a live post.",
    title: "Social Cues provider acceptance dry-run",
    tags: ["social-cues", "acceptance-check"],
    media: {},
    source: "provider-acceptance-ledger"
  };
  if (platformId === "instagram") {
    variant.imageUrl = `${brandHomeUrl}/sc-icon-512.png`;
    variant.media = { type: "image", hostedUrl: variant.imageUrl };
  }
  if (platformId === "youtube" || platformId === "tiktok") {
    variant.videoUrl = `${brandHomeUrl}/media/provider-acceptance-smoke.mp4`;
    variant.media = { type: "video", hostedUrl: variant.videoUrl };
  }
  return {
    campaign: {
      id: `provider-acceptance-${providerId}`,
      title: "Provider acceptance dry-run",
      brief: "Validate provider publishing payload construction without sending a live post.",
      createdAt: now,
      updatedAt: now,
      variants: [variant]
    },
    variant,
    scheduledAt: now
  };
}

function providerPublishProbeSkipped(providerId = "", summary = "") {
  return {
    at: new Date().toISOString(),
    providerId,
    ok: false,
    attempted: false,
    status: "skipped",
    summary,
    result: null
  };
}

async function providerPublishDryRunProbe(providerId, model = {}, session = null, row = {}) {
  if (!row.connected || !row.tokenStored) return providerPublishProbeSkipped(providerId, "Publish dry-run skipped until OAuth and token storage are proven.");
  if (!row.canPublish) return providerPublishProbeSkipped(providerId, "Publish dry-run skipped until the provider grants the publish scope/lane.");
  if (providerId === "google_business") return providerPublishProbeSkipped(providerId, "Google Business Profile publish checks need business.manage consent, an approved Google Cloud project, and a selected discovered location.");
  const item = syntheticProviderPublishItem(providerId);
  const providerAccount = providerProbeAccount(providerId, model, session) || row.account || null;
  const result = await attemptQueuedVariantPublish(model, item, { live: false, user: session?.user || null, providerAccount });
  const ok = Boolean(result.ok && result.dryRun === true);
  return {
    at: new Date().toISOString(),
    providerId,
    ok,
    attempted: true,
    status: ok ? "dry-run-proven" : "blocked",
    summary: ok
      ? `${row.name || providerId} dry-run publish payload is valid without sending a live post.`
      : result.error || `${row.name || providerId} dry-run publish payload is blocked.`,
    result: {
      provider: result.provider,
      platform: result.platform,
      dryRun: Boolean(result.dryRun),
      status: result.status || (ok ? "dry-run" : "blocked"),
      error: result.error || "",
      requiredAsset: result.requiredAsset || "",
      connectRoute: result.connectRoute || "",
      gate: result.gate ? {
        id: result.gate.id,
        status: result.gate.status,
        requiredScopes: result.gate.requiredScopes || []
      } : null,
      wouldPost: result.wouldPost || result.wouldUpload || result.wouldSubmit || result.wouldCreateListingDraft || result.wouldCreateCreativeHandoff || null
    }
  };
}

function providerPortalAuditForTask(row = {}, auditById = new Map()) {
  if (auditById.has(row.id)) return auditById.get(row.id);
  if (row.id === "facebook" || row.id === "instagram") return auditById.get("meta") || null;
  if (row.id === "google_growth" || row.id === "google_business") return auditById.get("youtube") || null;
  return null;
}

function providerLedgerTaskForRow(row = {}, auditById = new Map()) {
  const gate = (row.missing || [])[0] || "";
  const audit = providerPortalAuditForTask(row, auditById);
  const gateLabels = {
    devConfigured: "finish developer configuration",
    oauthConnected: "connect OAuth account",
    liveReadProven: "prove live read access",
    publishLaneReady: "unlock publish permission",
    publishDryRunProven: "prove safe publish dry-run",
    analyticsLaneReady: "unlock analytics/read metrics",
    reviewClear: "clear provider review"
  };
  const highPriority = new Set(["devConfigured", "oauthConnected", "liveReadProven", "publishLaneReady", "publishDryRunProven"]);
  return {
    gate,
    title: `${row.name || row.id}: ${gateLabels[gate] || "finish provider acceptance"}`,
    priority: highPriority.has(gate) ? "High" : "Medium",
    connectRoute: row.routes?.connect || "",
    statusRoute: row.routes?.status || "",
    portalRoute: audit?.portalRoute || providerPortalRoute(row.id),
    callbackUrl: audit?.callback || "",
    portalStatus: audit?.status || "",
    portalNextAction: audit?.nextAction || "",
    checkRoute: "/api/provider/action-check",
    publishCheckRoute: "/api/provider/publish-check",
    sweepRoute: "/api/provider/acceptance-sweep",
    signal: [
      row.nextAction || "Run the next provider check.",
      audit?.callback ? `Callback: ${audit.callback}.` : "",
      audit?.nextAction ? `Portal: ${audit.nextAction}` : "",
      row.missing?.length ? `Missing gates: ${row.missing.join(", ")}.` : "",
      row.blockers?.length ? `Blocker: ${row.blockers[0]}` : "",
      row.status ? `Current status: ${row.status}.` : ""
    ].filter(Boolean).join(" ")
  };
}

function materializeProviderLedgerActions(model = {}, ledger = {}, session = null) {
  const userId = session?.user?.id || "alpha";
  const workspaceId = session?.user ? workspaceIdForUser(session.user) : "local-dev-workspace";
  model.actions = model.actions || [];
  const rows = ledger.rows || [];
  const auditRows = developerPortalAudit().rows || [];
  const auditById = new Map(auditRows.map(row => [row.id, row]));
  const synced = [];
  for (const row of rows) {
    const sourceKey = `provider-ledger:${row.id}`;
    const existing = model.actions.find(item =>
      item.sourceKey === sourceKey
      && (!session?.user || !hasOwnerMarker(item) || ownedByUser(item, session.user.id))
    );
    if (row.owned) {
      if (existing && !["won", "dropped"].includes(existing.status)) {
        existing.status = "won";
        existing.signal = `${row.name} is owned in the provider acceptance ledger.`;
        existing.updatedAt = new Date().toISOString();
        existing.completedAt = existing.updatedAt;
        synced.push({ id: row.id, action: "won", title: existing.title });
      }
      continue;
    }
    const task = providerLedgerTaskForRow(row, auditById);
    if (existing) {
      if (existing.status !== "won") existing.status = "active";
      existing.type = "Provider task";
      existing.priority = task.priority;
      existing.title = task.title;
      existing.signal = task.signal;
      existing.providerId = row.id;
      existing.providerGate = task.gate;
      existing.connectRoute = task.connectRoute;
      existing.statusRoute = task.statusRoute;
      existing.portalRoute = task.portalRoute;
      existing.callbackUrl = task.callbackUrl;
      existing.portalStatus = task.portalStatus;
      existing.portalNextAction = task.portalNextAction;
      existing.checkRoute = task.checkRoute;
      existing.publishCheckRoute = task.publishCheckRoute;
      existing.sweepRoute = task.sweepRoute;
      existing.updatedAt = new Date().toISOString();
      synced.push({ id: row.id, action: "updated", title: existing.title, gate: task.gate });
      continue;
    }
    const action = {
      id: uid("act"),
      type: "Provider task",
      priority: task.priority,
      status: "active",
      title: task.title,
      signal: task.signal,
      source: "provider-acceptance-ledger",
      sourceKey,
      providerId: row.id,
      providerGate: task.gate,
      connectRoute: task.connectRoute,
      statusRoute: task.statusRoute,
      portalRoute: task.portalRoute,
      callbackUrl: task.callbackUrl,
      portalStatus: task.portalStatus,
      portalNextAction: task.portalNextAction,
      checkRoute: task.checkRoute,
      publishCheckRoute: task.publishCheckRoute,
      sweepRoute: task.sweepRoute,
      createdAt: new Date().toISOString(),
      ownerUserId: userId,
      workspaceId
    };
    model.actions.unshift(action);
    synced.push({ id: row.id, action: "created", title: action.title, gate: task.gate });
  }
  const rowsById = new Map(rows.map(row => [row.id, row]));
  for (const action of model.actions) {
    if (action.type !== "Provider task" || !action.providerId) continue;
    if (session?.user && hasOwnerMarker(action) && !ownedByUser(action, session.user.id)) continue;
    const row = rowsById.get(action.providerId);
    if (!row) continue;
    const staleConnectTask = row.connected && (
      action.providerGate === "oauthConnected"
      || /connect (?:oauth|account|provider)/i.test(String(action.title || ""))
    );
    const duplicate = action.sourceKey !== `provider-ledger:${row.id}`
      && model.actions.some(other => other !== action && other.sourceKey === `provider-ledger:${row.id}` && (!session?.user || !hasOwnerMarker(other) || ownedByUser(other, session.user.id)));
    if ((staleConnectTask || duplicate) && !["won", "dropped"].includes(action.status)) {
      action.status = staleConnectTask ? "won" : "dropped";
      action.completedAt = new Date().toISOString();
      action.updatedAt = action.completedAt;
      action.signal = staleConnectTask
        ? `${row.name} OAuth connection is satisfied by the current provider ledger.`
        : `${row.name} task was superseded by the authoritative provider-ledger action.`;
      synced.push({ id: row.id, action: action.status, title: action.title, gate: action.providerGate || "" });
    }
  }
  return {
    total: synced.length,
    created: synced.filter(item => item.action === "created").length,
    updated: synced.filter(item => item.action === "updated").length,
    won: synced.filter(item => item.action === "won").length,
    dropped: synced.filter(item => item.action === "dropped").length,
    synced
  };
}

async function runProviderAcceptanceSweep(model = {}, session = null) {
  const truth = providerTruthRows(model, session);
  const userId = session?.user?.id || "alpha";
  const workspaceId = session?.user ? workspaceIdForUser(session.user) : "local-dev-workspace";
  const connectedRows = truth.rows.filter(row => row.connected && row.tokenStored);
  const results = [];
  model.functionChecks = model.functionChecks || {};
  model.proof = model.proof || [];
  for (const row of connectedRows) {
    const action = truth.nextProviderActions.find(item => item.id === row.id) || providerTruthActionForRow(row);
    const liveProbe = await providerLiveProbe(row.id, model, session, row);
    const readResult = providerTruthCheckResult(row, action, liveProbe);
    const publishProbe = await providerPublishDryRunProbe(row.id, model, session, row);
    const existingCheck = providerFunctionCheck(model, row.id) || {};
    model.functionChecks[row.id] = {
      ...existingCheck,
      ...readResult,
      route: "/api/provider/acceptance-sweep",
      publishProbe,
      sweepAt: readResult.at,
      ownerUserId: userId,
      workspaceId
    };
    if (readResult.ok) {
      const metric = `${row.name} provider banked`;
      const alreadyProved = model.proof.some(item => item.metric === metric && (!session?.user || ownedByUser(item, session.user.id)));
      if (!alreadyProved) {
        model.proof.unshift({
          id: uid("proof"),
          type: "Provider banked",
          metric,
          note: readResult.summary,
          createdAt: readResult.at,
          ownerUserId: userId,
          workspaceId
        });
      }
    }
    if (publishProbe.ok) {
      const metric = `${row.name} publish dry-run proven`;
      const alreadyProved = model.proof.some(item => item.metric === metric && (!session?.user || ownedByUser(item, session.user.id)));
      if (!alreadyProved) {
        model.proof.unshift({
          id: uid("proof"),
          type: "Provider publish check",
          metric,
          note: publishProbe.summary,
          createdAt: publishProbe.at,
          ownerUserId: userId,
          workspaceId
        });
      }
    }
    results.push({
      id: row.id,
      name: row.name,
      read: {
        ok: readResult.ok,
        status: readResult.status,
        liveProbeOk: Boolean(readResult.liveProbe?.ok),
        attempted: Boolean(readResult.liveProbe?.attempted),
        summary: readResult.summary
      },
      publish: {
        ok: publishProbe.ok,
        attempted: Boolean(publishProbe.attempted),
        status: publishProbe.status,
        summary: publishProbe.summary
      }
    });
  }
  const at = new Date().toISOString();
  const summary = {
    total: truth.rows.length,
    connected: connectedRows.length,
    readBanked: results.filter(item => item.read.ok).length,
    liveReadPassed: results.filter(item => item.read.liveProbeOk).length,
    publishDryRunProven: results.filter(item => item.publish.ok).length,
    skipped: truth.rows.length - connectedRows.length
  };
  const taskSync = materializeProviderLedgerActions(model, providerAcceptanceLedger(model, session), session);
  model.activity = model.activity || [];
  model.activity.unshift({
    id: uid("actv"),
    type: "provider-acceptance-sweep",
    status: "completed",
    summary: `Provider acceptance sweep checked ${summary.connected}/${summary.total} connected lanes; ${summary.publishDryRunProven} publish dry-runs proven; ${taskSync.created + taskSync.updated} provider tasks synced.`,
    createdAt: at,
    ownerUserId: userId,
    workspaceId
  });
  return {
    ok: true,
    at,
    workspaceId,
    summary,
    taskSync,
    results,
    skipped: truth.rows
      .filter(row => !row.connected || !row.tokenStored)
      .map(row => ({ id: row.id, name: row.name, reason: row.blockers?.[0] || row.nextAction || "Not connected." }))
  };
}

async function runDailyProviderOwnershipLoop(model = {}, session = null, options = {}) {
  const user = session?.user || null;
  const userId = user?.id || "alpha";
  const workspaceId = user ? workspaceIdForUser(user) : "local-dev-workspace";
  const at = new Date().toISOString();
  const sweep = await runProviderAcceptanceSweep(model, session);
  const dueItems = queuedVariants(model, {
    includeFuture: options.includeFuture === true,
    now: options.now || at,
    platforms: Array.isArray(options.platforms) ? options.platforms : []
  }).slice(0, Math.max(1, Math.min(Number(options.limit || 25), 50)));
  const publishResults = [];
  for (const item of dueItems) {
    const result = await attemptQueuedVariantPublish(model, item, { live: false, user });
    rememberPublishAttempt(item, result);
    rememberQueuePublishResult(model, item, result, session);
    publishResults.push(result);
  }
  model.analytics = buildGrowthAnalytics(model);
  const analyticsSnapshot = bankAnalyticsSnapshot(model, model.analytics, session, "daily-provider-ownership-loop");
  const contracts = providerContracts(model, session);
  const providerStateSnapshot = bankProviderStateSnapshot(model, session, "daily-provider-ownership-loop");
  const publishSummary = {
    attempted: publishResults.length,
    dryRuns: publishResults.filter(item => item.ok && item.dryRun === true).length,
    blocked: publishResults.filter(item => !item.ok).length
  };
  model.activity = model.activity || [];
  model.activity.unshift({
    id: uid("actv"),
    type: "daily-provider-ownership-loop",
    status: "completed",
    summary: `Daily ownership loop: ${sweep.summary.connected}/${sweep.summary.total} connected lanes checked, ${publishSummary.dryRuns} scheduled dry-run(s), ${contracts.summary.owned}/${contracts.summary.total} provider contract(s) owned.`,
    createdAt: at,
    ownerUserId: userId,
    workspaceId
  });
  return {
    ok: true,
    at,
    workspaceId,
    sweep,
    publishQueue: {
      mode: "dry-run",
      ...publishSummary,
      results: publishResults
    },
    analytics: {
      status: model.analytics?.status || "",
      lastCompiledAt: model.analytics?.lastCompiledAt || at,
      summary: model.analytics?.summary || {},
      snapshotId: analyticsSnapshot?.id || null
    },
    providerContracts: contracts,
    providerState: {
      snapshotId: providerStateSnapshot?.recorded?.id || null,
      summary: providerStateSnapshot?.summary || {}
    },
    nextActions: contracts.nextContractActions || []
  };
}

function dailyProviderLoopStatus(model = {}, session = null) {
  const user = session?.user || null;
  const activity = (model.activity || [])
    .filter(item => item.type === "daily-provider-ownership-loop")
    .filter(item => !user || !hasOwnerMarker(item) || ownedByUser(item, user.id))
    .sort((a, b) => Date.parse(b.createdAt || b.at || "") - Date.parse(a.createdAt || a.at || ""));
  const latest = activity[0] || null;
  const contracts = providerContracts(model, session);
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: user ? workspaceIdForUser(user) : model.workspace?.id || "public",
    lastRun: latest ? {
      at: latest.createdAt || latest.at || "",
      status: latest.status || "",
      summary: latest.summary || ""
    } : null,
    runCount: activity.length,
    providerContracts: {
      summary: contracts.summary,
      nextContractActions: contracts.nextContractActions
    },
    analytics: {
      lastCompiledAt: model.analytics?.lastCompiledAt || null,
      status: model.analytics?.status || "",
      summary: model.analytics?.summary || {}
    },
    nextAction: latest
      ? (contracts.nextContractActions?.[0]?.nextAction || "Run the daily loop again after the next provider change.")
      : "Run the daily ownership loop once from an active workspace."
  };
}

function workspaceOwnerFields(session = null) {
  const user = session?.user || null;
  return {
    ownerUserId: user?.id || "alpha",
    workspaceId: user ? workspaceIdForUser(user) : "local-dev-workspace"
  };
}

function visibleWorkspaceRecords(records = [], session = null) {
  const user = session?.user || null;
  return (Array.isArray(records) ? records : [])
    .filter(item => !user || !hasOwnerMarker(item) || ownedByUser(item, user.id));
}

function publicPublishQueueRecord(item = {}) {
  const safe = cloneJson(item) || {};
  delete safe.raw;
  delete safe.providerResponse;
  if (safe.providerPostId && safe.publishedAt) safe.status = "published";
  return safe;
}

function queueRecordFromVariant(item = {}, session = null) {
  const lastAttempt = item.variant?.lastPublishAttempt || null;
  const variantStatus = String(item.variant?.status || "").toLowerCase();
  const hasPublishedEvidence = Boolean(item.variant?.providerPostId && item.variant?.publishedAt);
  let status = "queued";
  if (variantStatus === "published" || hasPublishedEvidence) status = "published";
  else if (variantStatus === "approved") status = "approved";
  else if (variantStatus === "failed") status = "failed";
  else if (variantStatus === "blocked") status = "blocked";
  else if (["submitted", "processing"].includes(variantStatus)) status = "processing";
  else if (variantStatus === "retrying") status = "retrying";
  else if (["queued", "scheduled"].includes(variantStatus)) status = "queued";
  else if (item.variant?.nextRetryAt) status = "retrying";
  else if (lastAttempt?.ok === false) status = "blocked";
  else if (lastAttempt?.ok && lastAttempt?.result?.dryRun !== false) status = "dry-run-ready";
  return {
    id: `variant-${item.variant?.id || uid("queue")}`,
    source: item.campaign?.type === "quick-post" ? "quick-post-variant" : "campaign-variant",
    campaignId: item.campaign?.id || "",
    campaignTitle: item.campaign?.title || "",
    variantId: item.variant?.id || "",
    platform: item.variant?.platform || "",
    status,
    scheduledFor: item.variant?.scheduledFor || item.variant?.queuedAt || null,
    queuedAt: item.variant?.queuedAt || null,
    live: false,
    copyPreview: String(item.variant?.copy || "").replace(/\s+/g, " ").slice(0, 160),
    lastAttempt: lastAttempt ? {
      at: lastAttempt.at || "",
      ok: Boolean(lastAttempt.ok),
      status: lastAttempt.status || "",
      error: lastAttempt.error || lastAttempt.result?.error || ""
    } : null,
    retryCount: Number(item.variant?.retryCount || 0),
    nextRetryAt: item.variant?.nextRetryAt || null,
    idempotencyKey: publishIdempotencyKey(item),
    providerPostId: item.variant?.providerPostId || "",
    publishedAt: item.variant?.publishedAt || null,
    updatedAt: item.variant?.updatedAt || item.variant?.publishedAt || item.variant?.blockedAt || null,
    ...workspaceOwnerFields(session)
  };
}

function scheduledVariantLedgerItems(model = {}, options = {}) {
  const now = Date.parse(options.now || new Date().toISOString());
  const includeFuture = options.includeFuture !== false;
  const platforms = new Set((options.platforms || []).filter(Boolean));
  const trackedStatuses = new Set(["approved", "queued", "retrying", "processing", "submitted", "published", "blocked", "failed"]);
  const terminalStatuses = new Set(["published", "blocked", "failed"]);
  const items = [];
  for (const campaign of contentVariantBatches(model)) {
    for (const variant of campaign.variants || []) {
      const status = String(variant.status || "").toLowerCase();
      if (!trackedStatuses.has(status)) continue;
      if (platforms.size && !platforms.has(variant.platform)) continue;
      const scheduledAt = Date.parse(variant.nextRetryAt || variant.scheduledFor || variant.queuedAt || "");
      if (!terminalStatuses.has(status) && !includeFuture && Number.isFinite(scheduledAt) && scheduledAt > now) continue;
      items.push({ campaign, variant, scheduledAt: Number.isNaN(scheduledAt) ? null : new Date(scheduledAt).toISOString() });
    }
  }
  return items;
}

function publishQueueLedger(model = {}, session = null, options = {}) {
  const records = visibleWorkspaceRecords(model.publishQueue, session).map(publicPublishQueueRecord);
  const variantRecords = scheduledVariantLedgerItems(model, {
    includeFuture: options.includeFuture !== false,
    now: options.now || new Date().toISOString(),
    platforms: Array.isArray(options.platforms) ? options.platforms : []
  }).map(item => queueRecordFromVariant(item, session));
  const byId = new Map();
  for (const item of [...records, ...variantRecords]) {
    if (!item?.id) continue;
    const previous = byId.get(item.id);
    if (!previous || Date.parse(item.updatedAt || item.queuedAt || item.scheduledFor || 0) >= Date.parse(previous.updatedAt || previous.queuedAt || previous.scheduledFor || 0)) {
      byId.set(item.id, item);
    }
  }
  const rows = [...byId.values()]
    .sort((a, b) => Date.parse(a.scheduledFor || a.queuedAt || a.createdAt || "") - Date.parse(b.scheduledFor || b.queuedAt || b.createdAt || ""));
  const summary = {
    total: rows.length,
    awaitingApproval: rows.filter(item => item.status === "queued-review-only").length,
    awaitingConfirmation: rows.filter(item => item.status === "approved").length,
    queued: rows.filter(item => ["queued", "scheduled"].includes(item.status)).length,
    processing: rows.filter(item => item.status === "processing").length,
    retrying: rows.filter(item => item.status === "retrying").length,
    dryRunReady: rows.filter(item => item.status === "dry-run-ready").length,
    blocked: rows.filter(item => ["blocked", "failed"].includes(item.status)).length,
    failed: rows.filter(item => item.status === "failed").length,
    published: rows.filter(item => item.status === "published").length,
    dueNow: rows.filter(item => ["queued", "scheduled", "retrying"].includes(item.status) && (!item.scheduledFor || Date.parse(item.scheduledFor) <= Date.now())).length
  };
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: session?.user ? workspaceIdForUser(session.user) : model.workspace?.id || "public",
    summary,
    nextAction: summary.blocked
      ? "Open the blocked queue items, fix their provider/account/media gate, then run the queue dry-run again."
      : summary.awaitingApproval
        ? "Open Approvals and complete content approval for the waiting posts."
        : summary.awaitingConfirmation
          ? "Open Approvals and use Confirm & queue to complete the final safety check."
      : summary.queued
        ? "Run Push scheduled queue as a dry-run before any live publish attempt."
        : "Queue approved campaign variants from Studio when content is ready.",
    rows: rows.slice(0, 100)
  };
}

function recordPublishQueueItem(model = {}, input = {}, session = null) {
  model.publishQueue = Array.isArray(model.publishQueue) ? model.publishQueue : [];
  const now = new Date().toISOString();
  const item = input.variant || input.item || input;
  const platform = item.platform || input.platform || "social-cues";
  const recordId = input.queueId || uid("queue");
  const variantId = item.id || input.variantId || `queue-variant-${recordId}`;
  const scheduledFor = input.scheduledFor || item.scheduledFor || new Date(Date.now() + 90 * 60 * 1000).toISOString();
  const queueItem = {
    ...(cloneJson(item) || {}),
    id: variantId,
    platform,
    status: "queued-review-only",
    scheduledFor,
    copy: String(item.copy || item.text || input.copy || ""),
    updatedAt: now
  };
  const record = {
    id: recordId,
    source: "api-queue",
    provider: "social-cues-queue",
    platform,
    campaignId: input.campaignId || item.campaignId || "",
    campaignTitle: input.campaignTitle || item.campaignTitle || "",
    variantId,
    status: "queued-review-only",
    approvalStage: 0,
    mode: "reminder-or-native-publish",
    queuedAt: now,
    scheduledFor,
    live: false,
    copyPreview: String(item.copy || item.text || input.copy || "").replace(/\s+/g, " ").slice(0, 160),
    item: publicPublishQueueRecord(queueItem),
    ...workspaceOwnerFields(session)
  };
  model.publishQueue.unshift(record);
  model.publishQueue = model.publishQueue.slice(0, 250);
  return record;
}

function rememberQueuePublishResult(model = {}, item = {}, result = {}, session = null) {
  model.publishQueue = Array.isArray(model.publishQueue) ? model.publishQueue : [];
  const variantId = item.variant?.id || result.variantId || "";
  const campaignId = item.campaign?.id || result.campaignId || "";
  let record = model.publishQueue.find(row =>
    row.variantId === variantId
    && (!campaignId || !row.campaignId || row.campaignId === campaignId)
    && (!session?.user || !hasOwnerMarker(row) || ownedByUser(row, session.user.id))
  );
  if (!record) {
    record = {
      id: `variant-${variantId || uid("queue")}`,
      source: "publish-due",
      platform: result.platform || item.variant?.platform || "",
      campaignId,
      campaignTitle: item.campaign?.title || result.campaignTitle || "",
      variantId,
      queuedAt: item.variant?.queuedAt || new Date().toISOString(),
      scheduledFor: item.variant?.scheduledFor || null,
      ...workspaceOwnerFields(session)
    };
    model.publishQueue.unshift(record);
  }
  const retryable = result.live && retryablePublishFailure(result);
  record.retryCount = Number(item.variant?.retryCount || record.retryCount || 0);
  record.nextRetryAt = item.variant?.nextRetryAt || null;
  record.status = result.ok
    ? result.dryRun === false ? "published" : "dry-run-ready"
    : retryable && record.retryCount < 5 ? "retrying" : result.live ? "failed" : "blocked";
  record.updatedAt = new Date().toISOString();
  record.lastAttempt = {
    at: record.updatedAt,
    ok: Boolean(result.ok),
    provider: result.provider || "",
    status: result.status || record.status,
    live: Boolean(result.live),
    dryRun: result.dryRun !== false,
    error: result.error || "",
    nextAction: result.nextAction || ""
  };
  record.idempotencyKey = result.idempotencyKey || publishIdempotencyKey(item);
  if (result.ok && result.dryRun === false) {
    record.providerPostId = result.providerPostId || providerPostIdFromResult(result);
    record.publishedAt = record.updatedAt;
  }
  model.publishQueue = model.publishQueue.slice(0, 250);
  return record;
}

function markQueuePublishProcessing(model = {}, item = {}, session = null) {
  model.publishQueue = Array.isArray(model.publishQueue) ? model.publishQueue : [];
  const variantId = item.variant?.id || "";
  const campaignId = item.campaign?.id || "";
  let record = model.publishQueue.find(row =>
    row.variantId === variantId
    && (!campaignId || !row.campaignId || row.campaignId === campaignId)
    && (!session?.user || !hasOwnerMarker(row) || ownedByUser(row, session.user.id))
  );
  if (!record) {
    record = {
      id: `variant-${variantId || uid("queue")}`,
      source: "publish-due",
      platform: item.variant?.platform || "",
      campaignId,
      campaignTitle: item.campaign?.title || "",
      variantId,
      queuedAt: item.variant?.queuedAt || new Date().toISOString(),
      scheduledFor: item.variant?.scheduledFor || null,
      ...workspaceOwnerFields(session)
    };
    model.publishQueue.unshift(record);
  }
  record.status = "processing";
  record.lastAttemptAt = new Date().toISOString();
  record.idempotencyKey = publishIdempotencyKey(item);
  return record;
}

function analyticsSnapshotSummary(model = {}, session = null) {
  const rows = visibleWorkspaceRecords(model.analyticsSnapshots, session)
    .sort((a, b) => Date.parse(b.createdAt || b.lastCompiledAt || "") - Date.parse(a.createdAt || a.lastCompiledAt || ""));
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: session?.user ? workspaceIdForUser(session.user) : model.workspace?.id || "public",
    summary: {
      total: rows.length,
      latestAt: rows[0]?.createdAt || rows[0]?.lastCompiledAt || null,
      latestStatus: rows[0]?.status || model.analytics?.status || "",
      metricCount: rows[0]?.metricCount ?? (model.analytics?.metrics || []).length
    },
    current: model.analytics || null,
    rows: rows.slice(0, 25)
  };
}

function automationPreferences(model = {}) {
  const current = model.automationPreferences || {};
  return {
    livePublishingPaused: current.livePublishingPaused === true,
    approvalRequired: true,
    updatedAt: current.updatedAt || null
  };
}

async function automationStatusPayload(model = {}, session = null) {
  const preferences = automationPreferences(model);
  const publishQueue = publishQueueLedger(model, session);
  const analyticsSnapshots = analyticsSnapshotSummary(model, session);
  const providerTruth = providerTruthRows(model, session);
  const dailyLoop = dailyProviderLoopStatus(model, session);
  const paidGrowth = paidGrowthReadiness(model);
  const renderJobs = visibleWorkspaceRecords(model.mediaRenderJobs, session)
    .sort((left, right) => Date.parse(right.createdAt || "") - Date.parse(left.createdAt || ""))
    .slice(0, 25);
  const notificationRows = session?.user
    ? await notificationOutboxForUser(session.user).catch(() => [])
    : [];
  const workerState = session?.user
    ? await workerStatusForUser(session.user).catch(error => ({ ready: false, summary: {}, rows: [], error: error.message }))
    : { ready: false, summary: {}, rows: [] };
  const connectedRows = (providerTruth.rows || []).filter(row => row.connected && row.tokenStored);
  const livePublishProviderIds = new Set(["facebook", "instagram", "threads", "youtube", "x", "tiktok"]);
  const publishRows = connectedRows.filter(row => livePublishProviderIds.has(row.id) && row.canPublish);
  const analyticsRows = connectedRows.filter(row => row.canReadAnalytics);
  const responseIds = new Set(["facebook", "instagram", "threads", "youtube", "x", "discord", "reddit"]);
  const responseRows = connectedRows.filter(row => responseIds.has(row.id));
  const commerceRows = connectedRows.filter(row => ["shopify", "etsy"].includes(row.id));
  const communityRows = connectedRows.filter(row => ["discord", "reddit", "twitch"].includes(row.id));
  const metaEventsReady = Boolean(envPresent("WEBHOOK_SIGNING_SECRET") || metaAppSecret);
  const discordEventsReady = Boolean(discordPublicKey);
  const renderWorkerReady = Boolean(workerState.ready && mediaRenderWorkerConfigured);
  const pendingNotifications = notificationRows.filter(row => ["pending", "retrying"].includes(row.status)).length;
  const laneState = (ready, attention = false) => ready ? "ready" : attention ? "attention" : "manual";

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: session?.user ? workspaceIdForUser(session.user) : model.workspace?.id || "public",
    preferences,
    summary: {
      connectedProviders: connectedRows.length,
      publishReadyProviders: publishRows.length,
      analyticsReadyProviders: analyticsRows.length,
      queuedPosts: publishQueue.summary.queued,
      blockedPosts: publishQueue.summary.blocked,
      pendingNotifications,
      renderJobs: renderJobs.length,
      automaticWorkers: workerState.ready ? 1 : 0,
      workerQueued: Number(workerState.summary?.queued || 0) + Number(workerState.summary?.retrying || 0),
      workerClaimed: Number(workerState.summary?.claimed || 0),
      workerBlocked: Number(workerState.summary?.blocked || 0) + Number(workerState.summary?.dead || 0)
    },
    truthNote: workerState.ready
      ? "The Supabase job ledger and secured worker dispatcher are active. Publishing remains approval-first; media rendering is active only when the isolated renderer is configured."
      : "Automatic worker status is unavailable for this workspace. Manual controls remain available while Social Cues checks the secured worker ledger.",
    lanes: [
      {
        id: "publishing",
        name: "Publishing queue",
        mode: workerState.ready ? "approval-first automatic dispatch" : "approval-first manual dispatch",
        state: preferences.livePublishingPaused ? "paused" : laneState(publishRows.length > 0, publishQueue.summary.blocked > 0),
        detail: preferences.livePublishingPaused
          ? "Live provider sends are paused. Dry-runs and approvals remain available."
          : `${publishQueue.summary.queued} queued, ${publishQueue.summary.dryRunReady} dry-run ready, ${publishQueue.summary.blocked} blocked.`,
        nextAction: publishQueue.nextAction,
        route: "/api/publish/queue",
        customerView: "calendar",
        canPause: true
      },
      {
        id: "account-health",
        name: "Account health",
        mode: workerState.ready ? "proactive renewal and on demand" : "on demand",
        state: laneState(connectedRows.length > 0, (providerTruth.summary?.needsReconnect || 0) > 0),
        detail: `${connectedRows.length} token-backed provider lane(s); status checks refresh tokens where the provider supports refresh.`,
        nextAction: workerState.ready ? "Social Cues renews supported provider tokens before expiry and asks for reconnection only when renewal cannot succeed." : dailyLoop.nextAction,
        route: "/api/provider/daily-loop/status",
        customerView: "accounts",
        canPause: false
      },
      {
        id: "analytics",
        name: "Analytics snapshots",
        mode: "on demand",
        state: laneState(analyticsRows.length > 0),
        detail: `${analyticsRows.length} provider lane(s) can supply analytics; ${analyticsSnapshots.summary.total} snapshot(s) are banked.`,
        nextAction: analyticsRows.length ? "Refresh insights after meaningful posts or campaign changes." : "Connect an analytics-capable provider account.",
        route: "/api/analytics/snapshots",
        customerView: "growth",
        canPause: false
      },
      {
        id: "responses",
        name: "Responses and moderation",
        mode: metaEventsReady || discordEventsReady ? "event and refresh" : "manual refresh",
        state: laneState(responseRows.length > 0),
        detail: `${responseRows.length} connected response surface(s). Signed events: Meta ${metaEventsReady ? "configured" : "not configured"}, Discord ${discordEventsReady ? "configured" : "not configured"}.`,
        nextAction: "Open Responses to review, draft, and explicitly approve replies or moderation actions.",
        route: "/api/meta/comments",
        customerView: "responses",
        canPause: false
      },
      {
        id: "media",
        name: "Media rendering",
        mode: renderWorkerReady ? "isolated queued rendering" : "queued contract",
        state: renderWorkerReady ? "ready" : "attention",
        detail: `${renderJobs.length} render job(s). ${renderWorkerReady ? "A render worker is available." : "Storage contracts exist, but the render worker is not installed."}`,
        nextAction: renderWorkerReady ? "Review completed platform cuts in Studio." : "Keep media planning visible, but do not promise background rendering until a durable worker is attached.",
        route: "/api/media/editor/readiness",
        customerView: "studio",
        canPause: false
      },
      {
        id: "notifications",
        name: "Account notifications",
        mode: workerState.ready ? "automatic queued delivery" : "queued",
        state: pendingNotifications ? "attention" : "manual",
        detail: `${pendingNotifications} pending notification(s); ${notificationRows.length} recent outbox record(s).`,
        nextAction: pendingNotifications ? "Review account alerts while delivery processing is completed." : "Alerts appear when sign-in, provider, or publish activity needs attention.",
        route: "/api/notifications/outbox",
        customerView: "devices",
        canPause: false
      }
    ],
    capabilities: [
      { id: "create", name: "Create", state: "ready", count: 1, providers: ["Social Cues Studio"], detail: "Campaign briefs, platform variants, brand guidance, follow-ups, and media plans." },
      { id: "publish", name: "Publish", state: publishRows.length ? "ready" : "gated", count: publishRows.length, providers: publishRows.map(row => row.name), detail: "Only provider lanes with a usable token, posting asset, and publish permission count as ready." },
      { id: "respond", name: "Respond", state: responseRows.length ? "available" : "gated", count: responseRows.length, providers: responseRows.map(row => row.name), detail: "Comments, replies, messages, and community actions stay approval-first." },
      { id: "analyze", name: "Analyze", state: analyticsRows.length ? "ready" : "gated", count: analyticsRows.length, providers: analyticsRows.map(row => row.name), detail: "Live provider metrics are separated from computed readiness and campaign guidance." },
      { id: "advertise", name: "Advertise", state: paidGrowth.summary.ready ? "ready" : "gated", count: paidGrowth.summary.ready, providers: paidGrowth.rows.filter(row => row.ready).map(row => row.name), detail: "Spend, budget, objective, creative, and launch require explicit approval." },
      { id: "sell", name: "Sell", state: commerceRows.length ? "available" : "gated", count: commerceRows.length, providers: commerceRows.map(row => row.name), detail: "Store and marketplace context can shape campaigns without silently changing products or listings." },
      { id: "community", name: "Community", state: communityRows.length ? "available" : "gated", count: communityRows.length, providers: communityRows.map(row => row.name), detail: "Community commands, moderation, and live-stream signals use provider-specific permissions." }
    ],
    recent: {
      publishQueue: publishQueue.rows.slice(0, 12),
      renderJobs,
      notifications: notificationRows.slice(0, 12),
      analyticsSnapshots: analyticsSnapshots.rows.slice(0, 8),
      workerJobs: workerState.rows.slice(0, 20)
    }
  };
}

function providerMetricValues(snapshot = {}) {
  const values = new Map();
  for (const metric of snapshot.metrics || []) {
    if (metric.kind !== "live") continue;
    const normalized = String(metric.value ?? "").replace(/,/g, "").trim();
    if (!/^-?\d+(?:\.\d+)?$/.test(normalized)) continue;
    values.set(metric.label, { value: Number(normalized), source: metric.source || "" });
  }
  return values;
}

function providerGrowthDeltas(current = {}, previous = null) {
  if (!previous?.createdAt || Date.parse(previous.createdAt) >= Date.parse(current.createdAt || "")) return [];
  const currentValues = providerMetricValues(current);
  const previousValues = providerMetricValues(previous);
  return [...currentValues.entries()].flatMap(([label, point]) => {
    const before = previousValues.get(label);
    if (!before || before.source !== point.source) return [];
    return [{
      label,
      source: point.source,
      previous: before.value,
      current: point.value,
      change: point.value - before.value,
      from: previous.createdAt,
      to: current.createdAt
    }];
  });
}

function bankAnalyticsSnapshot(model = {}, analytics = null, session = null, source = "manual", context = {}) {
  if (!analytics) return null;
  model.analyticsSnapshots = Array.isArray(model.analyticsSnapshots) ? model.analyticsSnapshots : [];
  const snapshot = {
    id: uid("analytics"),
    source,
    createdAt: new Date().toISOString(),
    lastCompiledAt: analytics.lastCompiledAt || new Date().toISOString(),
    status: analytics.status || "",
    summary: analytics.summary || {},
    metricCount: (analytics.metrics || []).length,
    metrics: (analytics.metrics || []).slice(0, 20),
    sourceBreakdown: (analytics.sourceBreakdown || []).slice(0, 20),
    translatedAnalysis: (analytics.translatedAnalysis || []).slice(0, 20),
    publishIdempotencyKeys: [...new Set(context.publishIdempotencyKeys || [])],
    ...workspaceOwnerFields(session)
  };
  const previous = visibleWorkspaceRecords(model.analyticsSnapshots, session)
    .filter(row => row.createdAt && Date.parse(row.createdAt) < Date.parse(snapshot.createdAt))
    .sort((left, right) => Date.parse(right.createdAt) - Date.parse(left.createdAt))[0] || null;
  snapshot.deltas = providerGrowthDeltas(snapshot, previous);
  analytics.deltas = snapshot.deltas;
  model.analyticsSnapshots.unshift(snapshot);
  model.analyticsSnapshots = model.analyticsSnapshots.slice(0, 100);
  return snapshot;
}

function buildProviderStateSnapshot(model = {}, session = null) {
  const truth = providerTruthRows(model, session);
  const acceptanceLedger = providerAcceptanceLedger(model, session);
  const contracts = providerContracts(model, session);
  const connectionLog = providerConnectionLog(model, session);
  const ownershipQueue = providerOwnershipQueue(model, session);
  const publishQueue = publishQueueLedger(model, session);
  const analytics = analyticsSnapshotSummary(model, session);
  const rows = truth.rows.map(row => {
    const contract = (contracts.rows || []).find(item => item.id === row.id) || {};
    const ledger = (acceptanceLedger.rows || []).find(item => item.id === row.id) || {};
    return {
      id: row.id,
      name: row.name,
      status: contract.status || ledger.status || row.status,
      configured: Boolean(row.configured),
      connected: Boolean(row.connected),
      tokenStored: Boolean(row.tokenStored),
      canPublish: Boolean(row.canPublish),
      canReadAnalytics: Boolean(row.canReadAnalytics),
      owned: Boolean(contract.owned || ledger.owned),
      account: row.account || null,
      identity: providerPostingIdentityName(row.account || {}, row.name),
      missing: contract.missing || ledger.missing || [],
      blockers: row.blockers || [],
      nextAction: contract.nextAction || ledger.nextAction || row.nextAction || ""
    };
  });
  const connectedAssets = [...new Map(rows
    .filter(row => row.connected && row.account)
    .map(row => [`${row.account.platform || row.id}:${row.account.providerAccountId || row.account.id || row.identity}`, row.account]))
    .values()];
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: session?.user ? workspaceIdForUser(session.user) : model.workspace?.id || "public",
    summary: {
      total: rows.length,
      configured: truth.summary.configured,
      connected: truth.summary.connected,
      connectedLanes: rows.filter(row => row.connected).length,
      connectedAssets: connectedAssets.length,
      owned: contracts.summary.owned,
      publishQueue: publishQueue.summary,
      analyticsSnapshots: analytics.summary.total,
      nextActions: (contracts.nextContractActions || truth.nextProviderActions || []).length
    },
    nextAction: contracts.nextContractActions?.[0]?.nextAction || truth.nextProviderActions?.[0]?.nextAction || publishQueue.nextAction,
    rows,
    providerTruth: { summary: truth.summary, nextProviderActions: truth.nextProviderActions },
    acceptanceLedger: { summary: acceptanceLedger.summary, nextProviderActions: acceptanceLedger.nextProviderActions },
    providerContracts: { summary: contracts.summary, nextContractActions: contracts.nextContractActions },
    connectionLog: { summary: connectionLog.summary, nextConnectionActions: connectionLog.nextConnectionActions },
    ownershipQueue: { summary: ownershipQueue.summary, next: ownershipQueue.next },
    publishQueue: { summary: publishQueue.summary, rows: publishQueue.rows.slice(0, 12) },
    analytics: analytics.summary
  };
}

function providerPostingIdentityName(account = {}, fallback = "") {
  const values = [
    account.pageName,
    account.channelTitle,
    account.shopName,
    account.storeName,
    account.globalName,
    account.displayName,
    account.display_name,
    account.username,
    account.handle,
    account.name,
    fallback
  ];
  return values
    .map(value => String(value || "").trim())
    .find(Boolean) || "";
}

function providerAssetKind(providerId = "") {
  const kinds = {
    facebook: "Facebook Page",
    instagram: "Instagram professional account",
    threads: "Threads profile",
    youtube: "YouTube channel",
    x: "X profile",
    tiktok: "TikTok profile",
    pinterest: "Pinterest profile/boards",
    canva: "Canva user/design workspace",
    shopify: "Shopify store",
    etsy: "Etsy shop",
    twitch: "Twitch channel",
    discord: "Discord user/guild",
    google_growth: "Google growth workspace",
    google_business: "Google Business Profile",
    manychat: "Manychat profile",
    elevenlabs: "ElevenLabs voice workspace",
    reddit: "Reddit community/app"
  };
  return kinds[providerId] || `${platformDisplayName(providerId)} asset`;
}

function providerEndUserSetupNote(providerId = "", row = {}, account = null) {
  if (row.connected && account) return `${providerAssetKind(providerId)} is available as ${providerPostingIdentityName(account, row.name)}.`;
  const notes = {
    facebook: "Choose a Facebook Page you manage; personal profiles are login identities, not publishable Page assets.",
    instagram: "Use an Instagram professional account linked to the Facebook Page, then connect Instagram Login or Meta again.",
    threads: "Connect the Threads profile that belongs to the Instagram identity you want Social Cues to use.",
    youtube: "Choose the YouTube channel, not just the Google account email, during Google authorization.",
    discord: "Authorize the Discord identity and select the community/guild lane when bot or channel features are enabled.",
    shopify: "Connect the Shopify store that owns the products and marketing events Social Cues should plan around.",
    etsy: "Connect the Etsy shop owner account so listings, receipts, and shop context map to the right storefront.",
    google_business: "Pick the Google Business Profile account/location that should receive profile posts, reviews, and local signals.",
    canva: "Connect the Canva account that owns the brand folders, templates, and export assets.",
    pinterest: "Connect the Pinterest profile that owns the boards and Pins for this brand.",
    tiktok: "Connect the TikTok profile that will appear publicly on published videos.",
    twitch: "Connect the Twitch channel that owns clips, VODs, and live-signal context.",
    x: "Connect the X profile that should appear as the public posting identity.",
    reddit: "Install or authorize the Reddit app/community lane after Devvit and commercial-use approval are ready.",
    manychat: "Add a customer-owned Manychat API/profile connection before subscriber CRM and flow actions can run.",
    elevenlabs: "Create a restricted customer API key with a credit quota, Text to Speech access, and Voices read access; never share the ElevenLabs password."
  };
  return notes[providerId] || `Connect the ${platformDisplayName(providerId)} account or asset that Social Cues should act as.`;
}

function providerPermissionGapExplainer(providerId = "", row = {}, account = null, options = {}) {
  const name = row.name || platformDisplayName(providerId);
  const assetKind = providerAssetKind(providerId);
  const gates = options.gates || {};
  const connected = Boolean(row.connected || gates.connected);
  const configured = Boolean(row.configured || gates.configured);
  const tokenStored = Boolean(row.tokenStored || gates.tokenStored);
  const assetDiscovered = Boolean(row.assetDiscovered || gates.assetDiscovered || account);
  const publishReady = Boolean(row.canPublish || gates.publishLaneReady);
  const analyticsReady = Boolean(row.canReadAnalytics || gates.analyticsLaneReady);
  const blockers = [...new Set([...(row.blockers || []), ...(options.blockers || [])])].filter(Boolean).slice(0, 5);
  const permissionGaps = [...new Set([...(row.permissionGaps || []), ...(options.permissionGaps || [])])].filter(Boolean).slice(0, 5);
  const missingEnv = row.missingEnv || [];
  const identity = providerPostingIdentityName(account || row.account || {}, "");
  const identityText = identity ? ` as ${identity}` : "";
  const technicalCause = [...new Set([...blockers, ...permissionGaps, ...missingEnv.map(name => `Missing ${name}`)])].slice(0, 6);
  const providerGuidance = {
    facebook: {
      asset: "Facebook needs a managed Page, not a personal profile, before Social Cues can publish or analyze Page results.",
      permission: "Facebook Pages are connected, but live publishing still depends on pages_manage_posts review and a fresh Page authorization that grants it.",
      analytics: "Facebook analytics needs a returned Page asset plus pages_read_engagement."
    },
    instagram: {
      asset: "Instagram must be a professional account linked to the Facebook Page or connected through the Instagram Login setup before Social Cues can use it.",
      permission: "Instagram publishing and insights are gated until Meta grants the current Instagram business scopes and the account is reauthorized.",
      analytics: "Instagram metrics require a professional account that Meta returns as a usable asset."
    },
    threads: {
      asset: "Threads authorization is separate from Facebook Page login; connect the Threads profile tied to the intended Instagram identity.",
      permission: "Threads publishing, replies, insights, and discovery stay gated until the Threads app scopes are approved and reauthorized."
    },
    x: {
      permission: "X is connected for identity/read first. Posting requires the write-permission upgrade, X app Read and write permissions, and available X credits or plan access.",
      analytics: "X engagement monitoring depends on X API plan access and the scopes granted to this account."
    },
    tiktok: {
      permission: "TikTok Login Kit can prove identity now, but direct posting, display/video lists, and analytics stay sandbox or review-gated until TikTok grants those products.",
      asset: "TikTok sandbox login only works for approved sandbox target users until the production app is reviewed."
    },
    youtube: {
      permission: "YouTube can connect a channel, but uploads and analytics need the granted YouTube scopes and may require Google API compliance review before public automation."
    },
    google_growth: {
      permission: "Google growth data is split across YouTube, Business Profile, Ads, Search Console, and Analytics; each API needs its own project setup, consent, and provider approval."
    },
    google_business: {
      permission: "Business Profile requires separate business.manage consent and Google Cloud project approval; YouTube sign-in does not grant this scope.",
      asset: "The signed-in Google identity must own or manage a verified Business Profile location. Social Cues discovers and lets the user select those locations after consent."
    },
    pinterest: {
      permission: "Pinterest organic Pins and analytics depend on the released app secret and approved scopes; ads/catalog lanes remain review-gated."
    },
    canva: {
      permission: "Canva user assets require a Connect integration and OAuth credentials; the Canva Apps SDK shell alone does not grant customer account access."
    },
    shopify: {
      asset: "Shopify needs the actual store domain and Admin API app credentials before Social Cues can read products or marketing events."
    },
    etsy: {
      asset: "Etsy needs the shop owner authorization plus the exact callback URL before listings, receipts, and shop context are usable.",
      permission: "Etsy sales and receipt signals require transactions_r in addition to shop/listing scopes."
    },
    linkedin: {
      asset: "LinkedIn Company Page management requires a member who is an approved Page administrator; sign-in identity and managed Company Pages are separate assets.",
      permission: "LinkedIn publishing, comments, reactions, and analytics depend on the exact Products and scopes LinkedIn approves. Company verification and Community Management review come before customer OAuth.",
      analytics: "LinkedIn Company, follower, post, video, and member analytics each require their documented Community Management scope."
    },
    patreon: {
      asset: "Patreon login identifies the creator; Social Cues then binds the selected creator campaign as the managed membership asset.",
      permission: "Member, post, and webhook lanes require their explicit Patreon API v2 scopes. Member email and mailing address remain excluded unless a future user-facing workflow justifies separate consent.",
      analytics: "Patreon member status, tier entitlement, pledge lifecycle, and creator post signal can inform retention and audience intelligence without replacing Patreon billing."
    },
    twitch: {
      permission: "Twitch identity and channel reads can work first; subscriber/follower/clip depth depends on broadcaster consent and Twitch developer approval."
    },
    discord: {
      asset: "Discord OAuth proves the user identity. Server workflows also need the bot installed in the right guild, bot token, guild ID, and channel IDs."
    },
    manychat: {
      permission: "Manychat CRM actions require the customer-owned API/profile connection before subscriber tags, flows, and automations can run."
    },
    reddit: {
      permission: "Reddit Devvit can be tested in playtest, but public or monetized customer use needs Reddit commercial/API approval."
    }
  };
  const guide = providerGuidance[providerId] || {};
  const explainer = (severity, summary, userMessage, nextAction) => ({
    severity,
    summary,
    userMessage,
    nextAction: nextAction || row.nextAction || providerEndUserSetupNote(providerId, row, account),
    technicalCause,
    permissionGaps,
    blockers,
    identity: identity || null,
    assetKind
  });
  if (!configured) {
    return explainer(
      "setup",
      `${name} setup is missing`,
      `${name} cannot connect yet because developer credentials or portal fields are not complete. This is an admin setup issue, not a user mistake.`,
      missingEnv.length ? `Add ${missingEnv.join(", ")} in Vercel/environment settings, redeploy, then test ${name} again.` : row.nextAction
    );
  }
  const connectionReason = row.connectionState?.reason || providerAccountConnectionState(account || {}).reason;
  if (!connected && tokenStored && ["needs-refresh", "expired", "needs-reconnect", "stored-not-connected"].includes(connectionReason)) {
    return explainer(
      "reconnect",
      `${name} needs token refresh`,
      `${name}${identityText} has verified account and encrypted-token evidence, but the current access token is not usable until OAuth refreshes it.`,
      `Reconnect ${name} from Accounts to refresh this posting identity without deleting its stored asset mapping.`
    );
  }
  if (!connected) {
    return explainer(
      "connect",
      `${name} needs account connection`,
      guide.asset || `${name} is configured, but this workspace has not connected the ${assetKind} Social Cues should use.`,
      row.nextAction || `Connect ${name} from Accounts while signed into this workspace.`
    );
  }
  if (!tokenStored) {
    return explainer(
      "reconnect",
      `${name} needs reconnect`,
      `${name}${identityText} has an account row, but Social Cues does not have usable server-side token evidence. Reconnect it before trusting live reads or posts.`,
      `Reconnect ${name} from Accounts so the token is stored server-side.`
    );
  }
  if (!assetDiscovered) {
    return explainer(
      "asset",
      `${name} asset not found`,
      guide.asset || `${name} login worked, but the publishable asset/profile/channel/store was not returned yet.`,
      row.nextAction || providerEndUserSetupNote(providerId, row, account)
    );
  }
  if (!publishReady || !analyticsReady || permissionGaps.length || blockers.length) {
    const missing = [
      publishReady ? "" : "publishing",
      analyticsReady ? "" : "analytics"
    ].filter(Boolean).join(" and ");
    const reviewWord = /review|approval|gated|audit|pending/i.test(`${technicalCause.join(" ")} ${guide.permission || ""}`);
    return explainer(
      reviewWord ? "review" : "permission",
      `${name} is connected, ${missing || "some capabilities"} still gated`,
      guide.permission || guide.analytics || `${name}${identityText} is connected, but ${missing || "some capabilities"} still need provider scopes, review, or proof checks before Social Cues should treat them as live.`,
      row.nextAction || "Run Check setup, then follow the provider review/scope instructions before retrying live use."
    );
  }
  return explainer(
    "ready",
    `${name} ready`,
    `${name}${identityText} is connected with usable token evidence, asset discovery, publishing, and analytics lanes marked ready.`,
    "Keep this lane healthy by running read and dry-run checks before live campaign use."
  );
}

function providerPermissionGapReportFromAssetMap(providerAssetMap = {}) {
  const rows = (providerAssetMap.rows || []).map(row => ({
    id: row.id,
    name: row.name,
    status: row.status,
    postingIdentity: row.postingIdentity,
    connected: row.connected,
    permissionExplainer: row.permissionExplainer
  }));
  return {
    ok: true,
    generatedAt: providerAssetMap.generatedAt || new Date().toISOString(),
    workspaceId: providerAssetMap.workspaceId || "public",
    summary: {
      total: rows.length,
      ready: rows.filter(row => row.permissionExplainer?.severity === "ready").length,
      setup: rows.filter(row => row.permissionExplainer?.severity === "setup").length,
      connect: rows.filter(row => row.permissionExplainer?.severity === "connect").length,
      reviewOrPermission: rows.filter(row => ["review", "permission", "asset", "reconnect"].includes(row.permissionExplainer?.severity)).length
    },
    rows
  };
}

function buildProviderAssetMap(model = {}, session = null) {
  const truth = providerTruthRows(model, session);
  const ledger = providerAcceptanceLedger(model, session);
  const contracts = providerContracts(model, session);
  const setup = providerSetupFields();
  const ledgerById = new Map((ledger.rows || []).map(row => [row.id, row]));
  const contractById = new Map((contracts.rows || []).map(row => [row.id, row]));
  const setupById = new Map((setup.rows || []).map(row => [row.id, row]));
  const rows = (truth.rows || []).map(row => {
    const ledgerRow = ledgerById.get(row.id) || {};
    const contractRow = contractById.get(row.id) || {};
    const setupRow = setupById.get(row.id) || {};
    const account = row.account || ledgerRow.account || null;
    const postingName = providerPostingIdentityName(account || {}, "");
    const assetKind = providerAssetKind(row.id);
    const connected = Boolean(row.connected && row.tokenStored);
    const gates = {
      configured: Boolean(row.configured),
      connected: Boolean(row.connected),
      tokenStored: Boolean(row.tokenStored),
      assetDiscovered: Boolean(row.assetDiscovered || account),
      readVerified: Boolean(ledgerRow.gates?.liveReadProven),
      publishDryRunProven: Boolean(ledgerRow.gates?.publishDryRunProven),
      publishLaneReady: Boolean(row.canPublish || ledgerRow.gates?.publishLaneReady),
      analyticsLaneReady: Boolean(row.canReadAnalytics || ledgerRow.gates?.analyticsLaneReady)
    };
    const status = connected
      ? gates.publishLaneReady && gates.analyticsLaneReady
        ? "ready"
        : "connected-gated"
      : gates.tokenStored
        ? "needs-refresh"
      : row.configured
        ? "needs-oauth"
        : "needs-config";
    const permissionGaps = [
      !gates.publishLaneReady ? "publishing gated" : "",
      !gates.analyticsLaneReady ? "analytics gated" : "",
      !gates.readVerified ? "read proof pending" : "",
      !gates.publishDryRunProven ? "publish dry-run pending" : ""
    ].filter(Boolean);
    const blockers = [...new Set([...(row.blockers || []), ...(ledgerRow.blockers || []), ...(contractRow.blockers || [])])].slice(0, 5);
    const permissionExplainer = providerPermissionGapExplainer(row.id, { ...row, status, permissionGaps, blockers }, account, { gates, permissionGaps, blockers });
    return {
      id: row.id,
      name: row.name,
      status,
      assetKind,
      connected,
      configured: Boolean(row.configured),
      postingIdentity: {
        name: postingName,
        label: postingName ? `${row.name}: ${postingName}` : `${row.name}: not connected`,
        providerAccountId: account?.providerAccountId || null,
        handle: account?.handle || "",
        displayName: account?.displayName || account?.name || ""
      },
      loginIdentity: {
        source: row.id === "facebook" || row.id === "instagram" ? "Meta OAuth identity" : `${row.name} OAuth identity`,
        note: connected
          ? "Token-backed provider identity is stored server-side."
          : gates.tokenStored
            ? "Encrypted token and provider identity are stored; OAuth refresh is required before live use."
            : "No usable token-backed identity is stored yet."
      },
      // providerTruthRows already returns a recursively scrubbed public account. Re-scrubbing
      // it would recalculate token evidence from credentials that were intentionally removed.
      account: account ? cloneJson(account) : null,
      gates,
      permissionGaps,
      permissionExplainer,
      blockers,
      nextAction: contractRow.nextAction || ledgerRow.nextAction || row.nextAction || setupRow.nextAction || providerEndUserSetupNote(row.id, row, account),
      setupNote: providerEndUserSetupNote(row.id, row, account),
      routes: row.routes || setupRow.routes || {}
    };
  });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: session?.user ? workspaceIdForUser(session.user) : model.workspace?.id || "public",
    summary: {
      total: rows.length,
      ready: rows.filter(row => row.status === "ready").length,
      connectedGated: rows.filter(row => row.status === "connected-gated").length,
      needsOAuth: rows.filter(row => row.status === "needs-oauth").length,
      needsConfig: rows.filter(row => row.status === "needs-config").length,
      postingIdentities: rows.filter(row => row.postingIdentity.name).length
    },
    rows,
    next: rows.find(row => row.status !== "ready") || null
  };
}

function bankProviderStateSnapshot(model = {}, session = null, source = "manual") {
  model.providerStateSnapshots = Array.isArray(model.providerStateSnapshots) ? model.providerStateSnapshots : [];
  const snapshot = buildProviderStateSnapshot(model, session);
  const record = {
    id: uid("provider-state"),
    source,
    createdAt: snapshot.generatedAt,
    workspaceId: snapshot.workspaceId,
    summary: snapshot.summary,
    nextAction: snapshot.nextAction,
    rows: snapshot.rows,
    ...workspaceOwnerFields(session)
  };
  model.providerStateSnapshots.unshift(record);
  model.providerStateSnapshots = model.providerStateSnapshots.slice(0, 100);
  return { ...snapshot, recorded: record };
}

function providerStateHistory(model = {}, session = null) {
  const rows = visibleWorkspaceRecords(model.providerStateSnapshots, session)
    .sort((a, b) => Date.parse(b.createdAt || "") - Date.parse(a.createdAt || ""))
    .slice(0, 25);
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: session?.user ? workspaceIdForUser(session.user) : model.workspace?.id || "public",
    summary: {
      total: rows.length,
      latestAt: rows[0]?.createdAt || null,
      latestConnected: rows[0]?.summary?.connected ?? null,
      latestOwned: rows[0]?.summary?.owned ?? null
    },
    rows
  };
}

function providerAcceptanceLedger(model = {}, session = null) {
  const truth = providerTruthRows(model, session);
  const rows = truth.rows.map(row => {
    const check = providerFunctionCheck(model, row.id);
    const liveProbe = check?.liveProbe || null;
    const publishProbe = providerPublishCheck(model, row.id);
    const publishAttempt = publishProbe || latestProviderPublishAttempt(model, row.id);
    const publishBlocker = latestProviderPublishBlocker(model, row.id);
    const proofMetric = `${row.name} provider banked`;
    const proof = (model.proof || []).find(item =>
      item.metric === proofMetric
      && (!session?.user || !hasOwnerMarker(item) || ownedByUser(item, session.user.id))
    ) || null;
    const gates = {
      devConfigured: Boolean(row.configured),
      oauthConnected: Boolean(row.connected && row.tokenStored),
      liveReadProven: Boolean(liveProbe?.ok),
      publishLaneReady: Boolean(row.canPublish),
      publishDryRunProven: Boolean(publishProbe?.ok || publishAttempt?.ok),
      analyticsLaneReady: Boolean(row.canReadAnalytics),
      reviewClear: !(row.blockers || []).length
    };
    const banked = Boolean(gates.oauthConnected && gates.liveReadProven);
    const owned = Boolean(gates.devConfigured && gates.oauthConnected && gates.liveReadProven && gates.publishLaneReady && gates.analyticsLaneReady && gates.reviewClear);
    const missing = Object.entries(gates)
      .filter(([, ok]) => !ok)
      .map(([key]) => key);
    const action = providerTruthActionForRow(row);
    const nextAction = owned
      ? "Keep this provider healthy with scheduled read and publish smoke checks."
      : publishBlocker?.nextAction || publishBlocker?.error || action?.nextAction || row.nextAction || row.blockers?.[0] || "Run the next provider check.";
    return {
      id: row.id,
      name: row.name,
      status: owned ? "owned" : banked ? "banked" : row.connected ? "connected-unproven" : row.configured ? "ready-to-connect" : "needs-config",
      owned,
      banked,
      gates,
      missing,
      account: row.account,
      liveProbe: liveProbe ? {
        ok: Boolean(liveProbe.ok),
        attempted: Boolean(liveProbe.attempted),
        endpoint: liveProbe.endpoint || "",
        summary: liveProbe.summary || "",
        evidence: liveProbe.evidence || {}
      } : null,
      functionCheck: check ? {
        at: check.at || "",
        status: check.status || "",
        summary: check.summary || ""
      } : null,
      publishProbe,
      publishAttempt,
      publishBlocker,
      proof: proof ? { metric: proof.metric, note: proof.note || "", createdAt: proof.createdAt || "" } : null,
      blockers: row.blockers || [],
      nextAction,
      routes: row.routes
    };
  });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: truth.workspaceId,
    summary: {
      total: rows.length,
      owned: rows.filter(row => row.owned).length,
      banked: rows.filter(row => row.banked).length,
      liveReadProven: rows.filter(row => row.gates.liveReadProven).length,
      publishLaneReady: rows.filter(row => row.gates.publishLaneReady).length,
      publishDryRunProven: rows.filter(row => row.gates.publishDryRunProven).length,
      analyticsLaneReady: rows.filter(row => row.gates.analyticsLaneReady).length,
      blocked: rows.filter(row => row.blockers.length).length
    },
    nextProviderActions: rows
      .filter(row => !row.owned)
      .map(row => ({
        id: row.id,
        name: row.name,
        status: row.status,
        missing: row.missing,
        nextAction: row.nextAction,
        routes: row.routes
      }))
      .slice(0, 8),
    rows
  };
}

function providerContracts(model = {}, session = null) {
  const portalAudit = developerPortalAudit();
  const auditById = new Map((portalAudit.rows || []).map(row => [row.id, row]));
  const serviceRows = serviceReadinessRows(providerServiceStack, auditById);
  const serviceById = new Map(serviceRows.map(row => [row.id, row]));
  const truth = providerTruthRows(model, session);
  const ledger = providerAcceptanceLedger(model, session);
  const ledgerById = new Map(ledger.rows.map(row => [row.id, row]));
  const rows = truth.rows.map(row => {
    const service = serviceById.get(row.serviceId) || serviceById.get(row.id) || null;
    const portal = auditById.get(row.id) || auditById.get(row.serviceId) || null;
    const ledgerRow = ledgerById.get(row.id) || null;
    const gates = {
      envReady: Boolean(service ? !service.missingEnv?.length && service.configured : row.configured),
      portalReady: portal ? Boolean(portal.ready) : true,
      oauthConnected: Boolean(row.connected && row.tokenStored),
      liveReadProven: Boolean(ledgerRow?.gates?.liveReadProven),
      publishLaneReady: Boolean(row.canPublish),
      publishDryRunProven: Boolean(ledgerRow?.gates?.publishDryRunProven),
      analyticsLaneReady: Boolean(row.canReadAnalytics),
      reviewClear: Boolean(ledgerRow?.gates?.reviewClear)
    };
    const missing = Object.entries(gates)
      .filter(([, ok]) => !ok)
      .map(([key]) => key);
    const owned = missing.length === 0;
    const status = owned
      ? "owned"
      : gates.oauthConnected
        ? "banked-needs-proof"
        : gates.envReady && gates.portalReady
          ? "ready-to-connect"
          : "needs-dev-portal";
    const nextAction = owned
      ? "Keep this provider healthy with recurring read, publish dry-run, and policy checks."
      : ledgerRow?.nextAction
        || row.nextAction
        || portal?.nextAction
        || service?.nextAction
        || "Finish the next missing contract gate.";
    return {
      id: row.id,
      name: row.name,
      serviceId: row.serviceId,
      status,
      owned,
      gates,
      missing,
      account: row.account,
      missingEnv: service?.missingEnv || row.missingEnv || [],
      optionalMissingEnv: service?.optionalMissingEnv || [],
      acceptedEnv: service?.acceptedEnv || {},
      portal: portal ? {
        status: portal.status,
        ready: Boolean(portal.ready),
        blocker: portal.blocker || "",
        nextAction: portal.nextAction || "",
        callback: portal.callback || "",
        portalRoute: portal.portalRoute || providerPortalRoute(row.id)
      } : null,
      routes: row.routes,
      truth: {
        configured: row.configured,
        connected: row.connected,
        tokenStored: row.tokenStored,
        canPublish: row.canPublish,
        canReadAnalytics: row.canReadAnalytics,
        blockers: row.blockers || []
      },
      ledger: ledgerRow ? {
        status: ledgerRow.status,
        banked: Boolean(ledgerRow.banked),
        liveProbe: ledgerRow.liveProbe || null,
        publishProbe: ledgerRow.publishProbe || null,
        publishBlocker: ledgerRow.publishBlocker || null,
        proof: ledgerRow.proof || null
      } : null,
      nextAction
    };
  });
  const notOwned = rows.filter(row => !row.owned);
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: truth.workspaceId,
    summary: {
      total: rows.length,
      owned: rows.filter(row => row.owned).length,
      envReady: rows.filter(row => row.gates.envReady).length,
      portalReady: rows.filter(row => row.gates.portalReady).length,
      oauthConnected: rows.filter(row => row.gates.oauthConnected).length,
      liveReadProven: rows.filter(row => row.gates.liveReadProven).length,
      publishDryRunProven: rows.filter(row => row.gates.publishDryRunProven).length,
      blocked: notOwned.length
    },
    nextContractActions: notOwned
      .map(row => ({
        id: row.id,
        name: row.name,
        status: row.status,
        missing: row.missing,
        missingEnv: row.missingEnv,
        nextAction: row.nextAction,
        routes: row.routes,
        portalRoute: row.portal?.portalRoute || providerPortalRoute(row.id)
      }))
      .slice(0, 10),
    rows
  };
}

function providerConnectionLog(model = {}, session = null) {
  const user = session?.user || null;
  const truth = providerTruthRows(model, session);
  const ledger = providerAcceptanceLedger(model, session);
  const contracts = providerContracts(model, session);
  const ledgerById = new Map((ledger.rows || []).map(row => [row.id, row]));
  const contractById = new Map((contracts.rows || []).map(row => [row.id, row]));
  const visibleActivity = (model.activity || [])
    .filter(item => !user || !hasOwnerMarker(item) || ownedByUser(item, user.id))
    .sort((a, b) => Date.parse(b.createdAt || b.at || "") - Date.parse(a.createdAt || a.at || ""));
  const step = (id, label, ok, detail = "", at = "") => ({
    id,
    label,
    state: ok ? "complete" : "blocked",
    detail,
    at
  });
  const rows = (truth.rows || []).map(row => {
    const ledgerRow = ledgerById.get(row.id) || null;
    const contract = contractById.get(row.id) || null;
    const accountLabel = row.account?.handle || row.account?.displayName || row.account?.name || "";
    const liveRead = Boolean(ledgerRow?.gates?.liveReadProven);
    const publishDryRun = Boolean(ledgerRow?.gates?.publishDryRunProven);
    const analytics = Boolean(row.canReadAnalytics);
    const reviewClear = Boolean(contract?.gates?.reviewClear);
    const developerReady = Boolean(row.configured && (contract?.gates?.portalReady ?? true));
    const developerDetail = !row.configured
      ? (row.missingEnv?.length ? `Missing ${row.missingEnv.join(", ")}` : "Developer setup is incomplete.")
      : contract?.gates?.portalReady === false
        ? (contract?.portal?.blocker || contract?.portal?.nextAction || "Developer credentials are present; finish the provider portal setup, review, or callback fields.")
        : "Credentials and portal route are present.";
    const steps = [
      step("developer", "Developer app/portal", developerReady, developerDetail),
      step("oauth", "OAuth/account", Boolean(row.connected && row.tokenStored), row.connected ? `${accountLabel || row.name} has token-backed account evidence.` : "No connected account evidence for this workspace."),
      step("read", "Live read proof", liveRead, ledgerRow?.liveProbe?.summary || ledgerRow?.functionCheck?.summary || "Run a read check to prove the provider returns usable data.", ledgerRow?.liveProbe?.at || ledgerRow?.functionCheck?.at || ""),
      step("publish", "Publish dry-run", publishDryRun, ledgerRow?.publishProbe?.summary || ledgerRow?.publishAttempt?.error || "Run a safe dry-run before any live publish attempt.", ledgerRow?.publishProbe?.at || ledgerRow?.publishAttempt?.at || ""),
      step("analytics", "Analytics/insight lane", analytics, analytics ? "Provider capability matrix says analytics/read metrics are available." : "Analytics is still scope, plan, review, or asset gated."),
      step("review", "Review/policy gate", reviewClear, reviewClear ? "No current review blocker is attached to this lane." : ((row.blockers || [])[0] || contract?.portal?.blocker || "Provider review or portal completion is still needed."))
    ];
    const currentStep = steps.find(item => item.state !== "complete") || { id: "owned", label: "Owned", detail: "All provider connection gates are currently satisfied." };
    const activity = visibleActivity
      .filter(item =>
        item.providerId === row.id
        || String(item.summary || item.message || item.label || "").toLowerCase().includes(String(row.name || row.id).toLowerCase())
      )
      .slice(0, 4)
      .map(item => ({
        id: item.id || "",
        type: item.type || item.label || "activity",
        status: item.status || "",
        summary: item.summary || item.message || item.detail || "",
        createdAt: item.createdAt || item.at || ""
      }));
    return {
      id: row.id,
      name: row.name,
      status: contract?.owned ? "owned" : row.connected ? "connected" : row.configured ? "ready-to-connect" : "needs-config",
      owned: Boolean(contract?.owned),
      banked: Boolean(ledgerRow?.banked || (row.connected && row.tokenStored)),
      account: row.account,
      currentStep,
      steps,
      recentActivity: activity,
      nextAction: contract?.nextAction || ledgerRow?.nextAction || row.nextAction || "Run the next provider check.",
      routes: row.routes
    };
  });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: truth.workspaceId,
    summary: {
      total: rows.length,
      owned: rows.filter(row => row.owned).length,
      banked: rows.filter(row => row.banked).length,
      connected: rows.filter(row => row.steps.find(step => step.id === "oauth")?.state === "complete").length,
      readProven: rows.filter(row => row.steps.find(step => step.id === "read")?.state === "complete").length,
      publishDryRunProven: rows.filter(row => row.steps.find(step => step.id === "publish")?.state === "complete").length,
      needsAttention: rows.filter(row => !row.owned).length
    },
    nextConnectionActions: rows
      .filter(row => !row.owned)
      .map(row => ({
        id: row.id,
        name: row.name,
        status: row.status,
        currentStep: row.currentStep,
        nextAction: row.nextAction,
        routes: row.routes
      }))
      .slice(0, 10),
    rows
  };
}

function providerOwnershipQueue(model = {}, session = null) {
  const log = providerConnectionLog(model, session);
  const weightByStep = {
    read: 10,
    publish: 20,
    analytics: 30,
    review: 40,
    oauth: 50,
    developer: 60,
    owned: 100
  };
  const rows = (log.rows || []).map(row => {
    const current = row.currentStep || {};
    const oauthReady = (row.steps || []).some(step => step.id === "oauth" && step.state === "complete");
    const executable = Boolean(oauthReady && ["read", "publish", "analytics", "review"].includes(current.id));
    const phase = row.owned
      ? "Owned"
      : current.id === "developer"
        ? "Configure"
        : current.id === "oauth"
          ? "Connect"
          : executable
            ? "Prove"
            : "Review";
    const priority = row.owned ? 1000 : (weightByStep[current.id] || 80) - (row.banked ? 5 : 0);
    return {
      id: row.id,
      name: row.name,
      status: row.status,
      phase,
      executable,
      priority,
      banked: row.banked,
      owned: row.owned,
      currentStep: current,
      nextAction: executable
        ? `Run ownership proof for ${row.name}: live read and safe publish dry-run.`
        : row.nextAction,
      routes: row.routes,
      account: row.account ? {
        name: row.account.name || "",
        handle: row.account.handle || row.account.displayName || "",
        providerAccountId: row.account.providerAccountId || ""
      } : null
    };
  }).sort((a, b) => a.priority - b.priority || String(a.name).localeCompare(String(b.name)));
  const activeRows = rows.filter(row => !row.owned);
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    workspaceId: log.workspaceId,
    summary: {
      total: rows.length,
      owned: rows.filter(row => row.owned).length,
      executable: rows.filter(row => row.executable && !row.owned).length,
      connectNeeded: rows.filter(row => !row.owned && row.currentStep?.id === "oauth").length,
      configureNeeded: rows.filter(row => !row.owned && row.currentStep?.id === "developer").length,
      reviewNeeded: rows.filter(row => !row.owned && ["analytics", "review"].includes(row.currentStep?.id)).length,
      remaining: activeRows.length
    },
    next: activeRows[0] || null,
    rows
  };
}

async function runProviderOwnershipProof(model = {}, session = null, providerId = "") {
  const userId = session?.user?.id || "alpha";
  const workspaceId = session?.user ? workspaceIdForUser(session.user) : "local-dev-workspace";
  const queue = providerOwnershipQueue(model, session);
  const target = providerId
    ? queue.rows.find(row => row.id === providerId)
    : queue.next;
  if (!target) {
    return { ok: true, skipped: true, status: "owned", summary: "All provider lanes are already owned in the current queue.", providerOwnershipQueue: queue };
  }
  const truth = providerTruthRows(model, session);
  const row = truth.rows.find(item => item.id === target.id);
  if (!row) return { ok: false, status: "missing-provider", error: "Provider lane not found.", providerId: target.id, providerOwnershipQueue: queue };
  if (!target.executable) {
    const at = new Date().toISOString();
    model.activity = model.activity || [];
    model.activity.unshift({
      id: uid("actv"),
      type: "provider-ownership-run",
      providerId: target.id,
      status: "blocked",
      summary: `${target.name} cannot be auto-owned yet: ${target.currentStep?.detail || target.nextAction || "manual provider work required."}`,
      createdAt: at,
      ownerUserId: userId,
      workspaceId
    });
    return {
      ok: false,
      providerId: target.id,
      status: "manual-step-required",
      phase: target.phase,
      currentStep: target.currentStep,
      nextAction: target.nextAction,
      providerOwnershipQueue: providerOwnershipQueue(model, session)
    };
  }
  const action = truth.nextProviderActions.find(item => item.id === target.id) || providerTruthActionForRow(row);
  const liveProbe = await providerLiveProbe(target.id, model, session, row);
  const readResult = providerTruthCheckResult(row, action, liveProbe);
  const publishProbe = await providerPublishDryRunProbe(target.id, model, session, row);
  const at = new Date().toISOString();
  model.functionChecks = {
    ...(model.functionChecks || {}),
    [target.id]: {
      ...readResult,
      route: "/api/provider/ownership-run",
      publishProbe,
      ownershipRunAt: at,
      ownerUserId: userId,
      workspaceId
    }
  };
  model.activity = model.activity || [];
  model.activity.unshift({
    id: uid("actv"),
    type: "provider-ownership-run",
    providerId: target.id,
    status: readResult.ok && publishProbe.ok ? "ownership-progress" : "ownership-blocked",
    summary: `${readResult.summary} Publish dry-run: ${publishProbe.summary}`,
    createdAt: at,
    ownerUserId: userId,
    workspaceId
  });
  model.proof = model.proof || [];
  for (const proof of [
    readResult.ok ? { type: "Provider ownership run", metric: `${row.name} ownership read proven`, note: readResult.summary, createdAt: readResult.at } : null,
    publishProbe.ok ? { type: "Provider ownership run", metric: `${row.name} ownership publish dry-run proven`, note: publishProbe.summary, createdAt: publishProbe.at } : null
  ].filter(Boolean)) {
    const exists = model.proof.some(item => item.metric === proof.metric && (!session?.user || ownedByUser(item, session.user.id)));
    if (!exists) model.proof.unshift({ id: uid("proof"), ...proof, ownerUserId: userId, workspaceId });
  }
  return {
    ok: true,
    providerId: target.id,
    phase: target.phase,
    readResult,
    publishProbe,
    providerOwnershipQueue: providerOwnershipQueue(model, session),
    connectionLog: providerConnectionLog(model, session),
    providerContracts: providerContracts(model, session)
  };
}

async function runProviderOwnershipSweep(model = {}, session = null, options = {}) {
  const userId = session?.user?.id || "alpha";
  const workspaceId = session?.user ? workspaceIdForUser(session.user) : "local-dev-workspace";
  const queue = providerOwnershipQueue(model, session);
  const limit = Math.max(1, Math.min(Number(options.limit || 10), 25));
  const providerFilter = Array.isArray(options.providers)
    ? new Set(options.providers.map(item => String(item).trim()).filter(Boolean))
    : null;
  const executableRows = (queue.rows || [])
    .filter(row => row.executable && !row.owned)
    .filter(row => !providerFilter || providerFilter.has(row.id))
    .slice(0, limit);
  const results = [];
  for (const row of executableRows) {
    const result = await runProviderOwnershipProof(model, session, row.id);
    results.push({
      providerId: row.id,
      name: row.name,
      ok: Boolean(result.ok),
      phase: result.phase || row.phase,
      read: result.readResult ? {
        ok: Boolean(result.readResult.ok),
        status: result.readResult.status,
        summary: result.readResult.summary
      } : null,
      publish: result.publishProbe ? {
        ok: Boolean(result.publishProbe.ok),
        status: result.publishProbe.status,
        summary: result.publishProbe.summary
      } : null,
      status: result.status || (result.ok ? "checked" : "blocked"),
      nextAction: result.nextAction || result.currentStep?.detail || row.nextAction || ""
    });
  }
  const at = new Date().toISOString();
  const refreshedQueue = providerOwnershipQueue(model, session);
  const refreshedLog = providerConnectionLog(model, session);
  const refreshedContracts = providerContracts(model, session);
  model.activity = model.activity || [];
  model.activity.unshift({
    id: uid("actv"),
    type: "provider-ownership-sweep",
    status: results.length ? "completed" : "skipped",
    summary: `Ownership sweep checked ${results.length} executable provider lane(s); ${results.filter(item => item.read?.ok).length} read proof(s), ${results.filter(item => item.publish?.ok).length} publish dry-run proof(s).`,
    createdAt: at,
    ownerUserId: userId,
    workspaceId
  });
  return {
    ok: true,
    at,
    workspaceId,
    summary: {
      executableBefore: executableRows.length,
      checked: results.length,
      readProven: results.filter(item => item.read?.ok).length,
      publishDryRunProven: results.filter(item => item.publish?.ok).length,
      blocked: results.filter(item => !item.ok).length,
      remaining: refreshedQueue.summary.remaining,
      next: refreshedQueue.next
    },
    results,
    providerOwnershipQueue: refreshedQueue,
    connectionLog: refreshedLog,
    providerContracts: refreshedContracts,
    ownershipReport: providerOwnershipReport(model, session)
  };
}

function providerOwnershipReport(model = {}, session = null) {
  const queue = providerOwnershipQueue(model, session);
  const log = providerConnectionLog(model, session);
  const contracts = providerContracts(model, session);
  const at = new Date().toISOString();
  const topRows = (queue.rows || []).filter(row => !row.owned).slice(0, 10);
  const ownedRows = (queue.rows || []).filter(row => row.owned);
  const executableRows = (queue.rows || []).filter(row => row.executable && !row.owned);
  const manualRows = (queue.rows || []).filter(row => !row.executable && !row.owned);
  const sections = {
    summary: {
      generatedAt: at,
      workspaceId: queue.workspaceId,
      total: queue.summary.total,
      owned: queue.summary.owned,
      remaining: queue.summary.remaining,
      executable: queue.summary.executable,
      connectNeeded: queue.summary.connectNeeded,
      configureNeeded: queue.summary.configureNeeded,
      reviewNeeded: queue.summary.reviewNeeded
    },
    nextProvider: queue.next ? {
      id: queue.next.id,
      name: queue.next.name,
      phase: queue.next.phase,
      executable: queue.next.executable,
      currentStep: queue.next.currentStep,
      nextAction: queue.next.nextAction,
      routes: queue.next.routes
    } : null,
    executableNow: executableRows.map(row => ({
      id: row.id,
      name: row.name,
      phase: row.phase,
      currentStep: row.currentStep,
      nextAction: row.nextAction
    })),
    manualWork: manualRows.slice(0, 10).map(row => ({
      id: row.id,
      name: row.name,
      phase: row.phase,
      currentStep: row.currentStep,
      nextAction: row.nextAction,
      routes: row.routes
    })),
    owned: ownedRows.map(row => ({ id: row.id, name: row.name, phase: row.phase })),
    contractSummary: contracts.summary,
    connectionSummary: log.summary
  };
  const lines = [
    "# Social Cues Provider Ownership Report",
    "",
    `Generated: ${at}`,
    `Workspace: ${queue.workspaceId}`,
    "",
    "## Summary",
    `- Owned: ${sections.summary.owned}/${sections.summary.total}`,
    `- Remaining: ${sections.summary.remaining}`,
    `- Executable now: ${sections.summary.executable}`,
    `- Needs connect: ${sections.summary.connectNeeded}`,
    `- Needs configure: ${sections.summary.configureNeeded}`,
    `- Needs review/policy: ${sections.summary.reviewNeeded}`,
    "",
    "## Next Provider",
    sections.nextProvider
      ? `- ${sections.nextProvider.name}: ${sections.nextProvider.phase} - ${sections.nextProvider.currentStep?.label || "Next"} - ${sections.nextProvider.nextAction || "Run the next provider step."}`
      : "- All provider lanes are owned.",
    "",
    "## Executable Now",
    ...(sections.executableNow.length
      ? sections.executableNow.map(row => `- ${row.name}: ${row.currentStep?.label || row.phase} - ${row.nextAction || "Run ownership proof."}`)
      : ["- No safe automated ownership proof is available right now."]),
    "",
    "## Manual / Portal Work",
    ...(sections.manualWork.length
      ? sections.manualWork.map(row => `- ${row.name}: ${row.currentStep?.label || row.phase} - ${row.currentStep?.detail || row.nextAction || "Manual provider step required."}`)
      : ["- No manual provider work is currently queued."]),
    "",
    "## Owned Lanes",
    ...(sections.owned.length
      ? sections.owned.map(row => `- ${row.name}`)
      : ["- None yet."])
  ];
  return {
    ok: true,
    generatedAt: at,
    workspaceId: queue.workspaceId,
    summary: sections.summary,
    sections,
    markdown: lines.join("\n"),
    providerOwnershipQueue: queue,
    connectionLog: {
      summary: log.summary,
      nextConnectionActions: log.nextConnectionActions
    },
    providerContracts: {
      summary: contracts.summary,
      nextContractActions: contracts.nextContractActions
    }
  };
}

