function discordRedirectUri() {
  return `${discordPublicAppUrl}/api/oauth/discord/callback`;
}

function mediaEditorReadiness() {
  const formats = platforms
    .filter(item => ["tiktok", "instagram", "youtube", "facebook", "x", "threads"].includes(item.id))
    .map(item => ({
      platform: item.id,
      name: item.name,
      output: item.id === "youtube" ? "16:9 or Shorts cut plus title/description/chapters" : "vertical short-form cut with captions, tags, CTA, and safe-area framing",
      spec: platformVideoSpec(item.id),
      hashtags: platformVideoHashtags(item.id)
    }));
  const planningReady = Boolean(openaiApiKey);
  const uploadReady = mediaStorageReady();
  const renderReady = Boolean(planningReady && uploadReady && mediaRenderWorkerConfigured);
  return {
    provider: mediaEditorProvider,
    storage: mediaStorageProvider,
    maxUploadMb: mediaMaxUploadMb,
    cameraCaptureEnabled: mediaCameraCaptureEnabled,
    micCaptureEnabled: mediaMicCaptureEnabled,
    configured: planningReady,
    planningReady,
    storageReady: uploadReady,
    uploadReady,
    rendererConfigured: mediaRenderWorkerConfigured,
    renderReady,
    ready: renderReady,
    models: {
      text: openaiModel,
      image: openaiImageModel,
      video: openaiVideoModel || "provider gated"
    },
    internalPipeline: {
      sourceProbe: "ffprobe",
      sceneAndSilenceMap: "FFmpeg",
      transcript: "OpenAI speech-to-text",
      candidateScoring: "Source-grounded structured scoring",
      finish: "FFmpeg and Remotion",
      workerState: mediaRenderWorkerConfigured ? "configured" : "local engine proven; isolated production worker pending"
    },
    warnings: [
      "Raw media upload and AI editing should run server-side because files are large, expensive, and may contain private client footage.",
      "Camera and microphone access must be user-initiated in the browser and never auto-enabled.",
      ...(!mediaRenderWorkerConfigured ? ["Private upload and edit planning are ready. Live rendering remains disabled until the isolated Cloud Run worker completes a private test render."] : [])
    ],
    outputs: formats
  };
}

function openaiRequestHeaders() {
  return {
    "Content-Type": "application/json",
    Authorization: `Bearer ${openaiApiKey}`,
    ...(openaiProjectId ? { "OpenAI-Project": openaiProjectId } : {}),
    ...(openaiOrgId ? { "OpenAI-Organization": openaiOrgId } : {})
  };
}

function openaiResponseText(result = {}) {
  if (typeof result.output_text === "string" && result.output_text.trim()) return result.output_text;
  for (const item of result.output || []) {
    for (const content of item?.content || []) {
      if (["output_text", "text"].includes(content?.type) && typeof content.text === "string") return content.text;
    }
  }
  return "";
}

function openaiUsageSummary(model = {}, session = null, at = new Date()) {
  const rows = visibleWorkspaceRecords(model.openaiUsage, session);
  const day = at.toISOString().slice(0, 10);
  const month = at.toISOString().slice(0, 7);
  const daily = rows.filter(row => String(row.createdAt || "").startsWith(day));
  const monthly = rows.filter(row => String(row.createdAt || "").startsWith(month));
  const monthlyTokens = monthly.reduce((total, row) => total + Number(row.totalTokens || 0), 0);
  return {
    day,
    month,
    limits: {
      dailyRequests: openaiDailyRequestLimit,
      monthlyRequests: openaiMonthlyRequestLimit,
      monthlyTokens: openaiMonthlyTokenLimit
    },
    used: {
      dailyRequests: daily.length,
      monthlyRequests: monthly.length,
      monthlyTokens
    },
    remaining: {
      dailyRequests: Math.max(0, openaiDailyRequestLimit - daily.length),
      monthlyRequests: Math.max(0, openaiMonthlyRequestLimit - monthly.length),
      monthlyTokens: Math.max(0, openaiMonthlyTokenLimit - monthlyTokens)
    },
    allowed: daily.length < openaiDailyRequestLimit
      && monthly.length < openaiMonthlyRequestLimit
      && monthlyTokens < openaiMonthlyTokenLimit
  };
}

function recordOpenaiUsage(model = {}, session = null, feature = "generation", result = {}) {
  const usage = result.usage || {};
  const record = {
    id: uid("openai-usage"),
    feature,
    model: result.model || openaiModel,
    inputTokens: Number(usage.input_tokens || 0),
    outputTokens: Number(usage.output_tokens || 0),
    totalTokens: Number(usage.total_tokens || 0),
    requestId: String(result.id || "").slice(0, 160),
    createdAt: new Date().toISOString(),
    ...(session?.user ? accountOwnerPatch(session.user) : {})
  };
  model.openaiUsage = [record, ...(model.openaiUsage || [])].slice(0, 2000);
  return record;
}

async function claimDurableOpenaiAllowance(session = null, feature = "generation", idempotencyKey = "") {
  const user = session?.user;
  const workspaceId = workspaceModelIdForUser(user || {});
  const ownerUserId = supabaseUserIdForUser(user || {});
  if (!supabaseEnabled || !isUuid(workspaceId) || !isUuid(ownerUserId)) return { durable: false, allowed: true, ledgerId: "" };
  const result = await optionalSupabaseRequest("/rpc/social_cues_claim_openai_allowance", {
    method: "POST",
    body: JSON.stringify({
      p_workspace_id: workspaceId,
      p_user_id: ownerUserId,
      p_feature: String(feature || "generation").slice(0, 120),
      p_idempotency_key: String(idempotencyKey || uid("openai-request")).slice(0, 500),
      p_daily_request_limit: openaiDailyRequestLimit,
      p_monthly_request_limit: openaiMonthlyRequestLimit,
      p_monthly_token_limit: openaiMonthlyTokenLimit,
      p_metadata: { model: openaiModel }
    })
  });
  const decision = Array.isArray(result) ? result[0] || {} : result || {};
  return {
    durable: true,
    allowed: decision.allowed === true,
    dailyUsed: Number(decision.daily_used || 0),
    monthlyUsed: Number(decision.monthly_used || 0),
    monthlyTokens: Number(decision.monthly_tokens || 0),
    ledgerId: decision.ledger_id || ""
  };
}

async function completeDurableOpenaiUsage(claim = {}, result = {}, error = null) {
  if (!claim.durable || !isUuid(claim.ledgerId)) return null;
  const usage = result?.usage || {};
  const inputTokens = Math.max(0, Number(usage.input_tokens || 0));
  const outputTokens = Math.max(0, Number(usage.output_tokens || 0));
  const totalTokens = Math.max(0, Number(usage.total_tokens || inputTokens + outputTokens));
  const estimatedCostMicrousd = Math.round(
    inputTokens * openaiInputCostPerMillionMicrousd / 1_000_000
    + outputTokens * openaiOutputCostPerMillionMicrousd / 1_000_000
  );
  const now = new Date().toISOString();
  const rows = await optionalSupabaseRequest(`/provider_usage_ledger?id=eq.${encodeURIComponent(claim.ledgerId)}`, {
    method: "PATCH",
    headers: { Prefer: "return=representation" },
    body: JSON.stringify({
      status: error ? "failed" : "completed",
      input_tokens: inputTokens,
      output_tokens: outputTokens,
      total_tokens: totalTokens,
      estimated_cost_microusd: estimatedCostMicrousd,
      metadata: {
        model: result?.model || openaiModel,
        providerRequestId: String(result?.id || "").slice(0, 160),
        costEstimateConfigured: Boolean(openaiInputCostPerMillionMicrousd || openaiOutputCostPerMillionMicrousd),
        error: error ? String(error.message || error).slice(0, 500) : ""
      },
      updated_at: now
    })
  });
  return Array.isArray(rows) ? rows[0] || null : null;
}

async function openaiStructuredResponse({ name, schema, instructions, input, maxOutputTokens = 9000 }) {
  if (!openaiApiKey) throw Object.assign(new Error("OpenAI is not configured for server-side generation."), { status: 503 });
  const response = await fetch("https://api.openai.com/v1/responses", {
    method: "POST",
    headers: openaiRequestHeaders(),
    body: JSON.stringify({
      model: openaiModel,
      store: false,
      instructions,
      input,
      max_output_tokens: maxOutputTokens,
      text: {
        format: {
          type: "json_schema",
          name,
          strict: true,
          schema
        }
      }
    })
  });
  const result = await response.json().catch(() => ({}));
  if (!response.ok) {
    const error = new Error(result.error?.message || `OpenAI request failed with status ${response.status}.`);
    error.status = response.status;
    error.requestId = response.headers.get("x-request-id") || "";
    throw error;
  }
  const outputText = openaiResponseText(result);
  if (!outputText) throw Object.assign(new Error("OpenAI returned no structured output."), { status: 502 });
  try {
    return { result, data: JSON.parse(outputText) };
  } catch {
    throw Object.assign(new Error("OpenAI returned output that did not match the Social Cues data contract."), { status: 502 });
  }
}

