function mediaStorageReady() {
  if (mediaStorageProvider === "supabase-storage") return Boolean(supabaseUrl && supabaseServiceKey);
  if (mediaStorageProvider === "vercel-blob") return Boolean(vercelBlobToken);
  return mediaStorageProvider === "local";
}

async function signedSupabaseMediaUrl(storagePath, expiresIn = 300) {
  if (!supabaseUrl || !supabaseServiceKey || !storagePath) throw new Error("Private media signing is not configured.");
  const encodedPath = String(storagePath).split("/").map(encodeURIComponent).join("/");
  const response = await fetch(`${supabaseUrl}/storage/v1/object/sign/${encodeURIComponent(mediaStorageBucket)}/${encodedPath}`, {
    method: "POST",
    headers: supabaseHeaders(),
    body: JSON.stringify({ expiresIn: Math.max(60, Math.min(Number(expiresIn || 300), 3600)) })
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || !body.signedURL) throw new Error(body.error || body.message || `Media signing ${response.status}`);
  return new URL(body.signedURL, supabaseUrl).toString();
}

function providerMediaDeliveryToken(asset = {}, expiresIn = 7200) {
  if (!authSessionSecret || !asset.storagePath || asset.status !== "uploaded") return "";
  const payload = Buffer.from(JSON.stringify({
    path: String(asset.storagePath),
    type: String(asset.contentType || "application/octet-stream"),
    exp: Math.floor(Date.now() / 1000) + Math.max(300, Math.min(Number(expiresIn || 7200), 21600))
  })).toString("base64url");
  const signature = crypto.createHmac("sha256", authSessionSecret).update(payload).digest("base64url");
  return `${payload}.${signature}`;
}

function providerMediaDeliveryUrl(asset = {}, expiresIn = 7200) {
  const token = providerMediaDeliveryToken(asset, expiresIn);
  return token ? `${brandHomeUrl}/api/media/provider/${token}` : "";
}

function providerMediaDeliveryPayload(token = "") {
  const [payload, signature] = String(token || "").split(".");
  if (!payload || !signature || !authSessionSecret) return null;
  const expected = crypto.createHmac("sha256", authSessionSecret).update(payload).digest("base64url");
  const expectedBuffer = Buffer.from(expected);
  const signatureBuffer = Buffer.from(signature);
  if (expectedBuffer.length !== signatureBuffer.length || !crypto.timingSafeEqual(expectedBuffer, signatureBuffer)) return null;
  try {
    const decoded = JSON.parse(Buffer.from(payload, "base64url").toString("utf8"));
    if (!decoded.path || Number(decoded.exp || 0) <= Math.floor(Date.now() / 1000)) return null;
    return decoded;
  } catch {
    return null;
  }
}

function supabaseStorageOrigin() {
  const url = new URL(supabaseUrl);
  if (/\.supabase\.(co|in|red)$/i.test(url.hostname) && !url.hostname.includes(".storage.supabase.")) {
    url.hostname = url.hostname.replace(/\.supabase\.(co|in|red)$/i, ".storage.supabase.$1");
  }
  return url.origin;
}

async function createSignedSupabaseMediaUpload(storagePath) {
  if (!supabaseUrl || !supabaseServiceKey || !storagePath) throw new Error("Private media uploads are not configured.");
  const encodedPath = String(storagePath).split("/").map(encodeURIComponent).join("/");
  const storageBase = `${supabaseUrl.replace(/\/$/, "")}/storage/v1`;
  const response = await fetch(`${storageBase}/object/upload/sign/${encodeURIComponent(mediaStorageBucket)}/${encodedPath}`, {
    method: "POST",
    headers: supabaseHeaders(),
    body: "{}"
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || !body.url) throw new Error(body.error || body.message || `Media upload signing ${response.status}`);
  const signedUrl = /^https?:\/\//i.test(String(body.url))
    ? String(body.url)
    : `${storageBase}${String(body.url).startsWith("/") ? "" : "/"}${body.url}`;
  const token = new URL(signedUrl).searchParams.get("token");
  if (!token) throw new Error("Media upload signing returned no token.");
  return {
    signedUrl,
    token,
    expiresIn: 7200,
    method: "PUT",
    resumable: {
      endpoint: `${supabaseStorageOrigin()}/storage/v1/upload/resumable`,
      protocol: "tus-1.0.0",
      chunkSize: 6 * 1024 * 1024,
      bucket: mediaStorageBucket,
      objectName: storagePath
    }
  };
}

async function supabaseMediaObjectInfo(storagePath) {
  if (!supabaseUrl || !supabaseServiceKey || !storagePath) throw new Error("Private media verification is not configured.");
  const encodedPath = String(storagePath).split("/").map(encodeURIComponent).join("/");
  const response = await fetch(`${supabaseUrl.replace(/\/$/, "")}/storage/v1/object/info/${encodeURIComponent(mediaStorageBucket)}/${encodedPath}`, {
    method: "GET",
    headers: supabaseHeaders()
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(body.error || body.message || `Media upload verification ${response.status}`);
  return body;
}

