function supabaseTokenAal(accessToken = "") {
  try {
    const payload = JSON.parse(base64UrlDecode(String(accessToken).split(".")[1] || "").toString("utf8"));
    return {
      currentLevel: payload.aal || "aal1",
      methods: Array.isArray(payload.amr) ? payload.amr.map(item => item.method).filter(Boolean) : [],
      sessionId: payload.session_id || "",
      expiresAt: Number(payload.exp || 0)
    };
  } catch {
    return { currentLevel: "unknown", methods: [], sessionId: "", expiresAt: 0 };
  }
}

async function claimPasswordRecoveryInstance(supabaseUser, accessToken) {
  const claims = supabaseTokenAal(accessToken);
  if (!claims.methods.includes("recovery") || !isUuid(claims.sessionId)) {
    throw new Error("This password change requires a valid link from a Social Cues recovery email.");
  }
  const expiresAtMs = claims.expiresAt * 1000;
  if (!Number.isFinite(expiresAtMs) || expiresAtMs <= Date.now()) {
    throw new Error("This password reset link has expired. Request a new recovery email.");
  }
  const rows = await optionalSupabaseRequest("/password_recovery_instances?on_conflict=session_id", {
    method: "POST",
    headers: { Prefer: "resolution=ignore-duplicates,return=representation" },
    body: JSON.stringify([{
      user_id: supabaseUser.id,
      session_id: claims.sessionId,
      status: "claimed",
      expires_at: new Date(expiresAtMs).toISOString(),
      updated_at: new Date().toISOString()
    }])
  });
  if (!Array.isArray(rows)) {
    throw new Error("Secure password recovery storage is unavailable. Request a new link after the service is restored.");
  }
  if (!rows.length) {
    throw new Error("This password reset link has already been used. Request a new recovery email.");
  }
  return rows[0];
}

async function finishPasswordRecoveryInstance(instanceId, status = "consumed") {
  if (!isUuid(instanceId)) return;
  const completedAt = new Date().toISOString();
  await optionalSupabaseRequest(`/password_recovery_instances?id=eq.${encodeURIComponent(instanceId)}`, {
    method: "PATCH",
    headers: { Prefer: "return=minimal" },
    body: JSON.stringify({
      status,
      consumed_at: status === "consumed" ? completedAt : null,
      updated_at: completedAt
    })
  });
}

