function requestIp(req) {
  const forwarded = String(req.headers["x-forwarded-for"] || "").split(",").map(item => item.trim()).filter(Boolean)[0];
  const realIp = String(req.headers["x-real-ip"] || "").trim();
  const socketIp = String(req.socket?.remoteAddress || "").trim();
  return forwarded || realIp || socketIp || "unknown";
}

function authRateLimitIdentity(email = "") {
  return normalizeEmail(email) || "anonymous";
}

async function authRateLimitDecision(action, req, email = "") {
  const policy = authRateLimitPolicies[action];
  if (!policy) return { ok: true, remaining: null, retryAfterSeconds: 0 };
  const now = Date.now();
  const key = `${action}:${requestIp(req)}:${authRateLimitIdentity(email)}`;
  if (supabaseEnabled) {
    try {
      const identityHash = hashSecret(key);
      const result = await supabaseRequest("/rpc/social_cues_claim_auth_rate_limit", {
        method: "POST",
        body: JSON.stringify({
          p_action: action,
          p_identity_hash: identityHash,
          p_window_seconds: Math.ceil(policy.windowMs / 1000),
          p_max_attempts: policy.max
        })
      });
      const decision = Array.isArray(result) ? result[0] : result;
      if (!decision?.allowed) {
        const retryAfterSeconds = Math.max(1, Number(decision?.retry_after_seconds || 60));
        return {
          ok: false,
          remaining: 0,
          retryAfterSeconds,
          durable: true,
          error: `Too many ${policy.label}. Wait about ${retryAfterSeconds} seconds and try again.`
        };
      }
      return {
        ok: true,
        remaining: Number(decision.remaining ?? 0),
        retryAfterSeconds: 0,
        durable: true
      };
    } catch {
      if (runtimeMode === "vercel") {
        return {
          ok: false,
          remaining: 0,
          retryAfterSeconds: 30,
          durable: false,
          error: "Account security checks are temporarily unavailable. Wait about 30 seconds and try again."
        };
      }
    }
  }
  const existing = authRateLimitState.get(key) || [];
  const recent = existing.filter(timestamp => now - timestamp < policy.windowMs);
  if (recent.length >= policy.max) {
    const retryAfterSeconds = Math.max(1, Math.ceil((policy.windowMs - (now - recent[0])) / 1000));
    authRateLimitState.set(key, recent);
    return {
      ok: false,
      retryAfterSeconds,
      error: `Too many ${policy.label}. Wait about ${retryAfterSeconds} seconds and try again.`
    };
  }
  recent.push(now);
  authRateLimitState.set(key, recent);
  return {
    ok: true,
    remaining: Math.max(0, policy.max - recent.length),
    retryAfterSeconds: 0
  };
}

async function createSupabasePasswordUser(input = {}) {
  const email = normalizeEmail(input.email);
  const password = normalizePassword(input.password);
  const promoCode = normalizePromoCode(input.promoCode);
  const promo = promoCode ? promoCodeRecord(promoCode) : null;
  const signup = await supabaseAuthRequest("/signup", {
    method: "POST",
    body: JSON.stringify({
      email,
      password,
      data: {
        name: input.name || "Social Cues User",
        workspace_name: input.workspaceName || "Social Cues",
        ...(promo ? {
          promo_code: promo.code,
          promo_access: promo.access || "highest-tier-test",
          promo_days: promo.days || 120
        } : {})
      }
    })
  });
  const confirmed = Boolean(signup?.user?.email_confirmed_at || signup?.user?.confirmed_at);
  if (!signup?.access_token || !confirmed) {
    const pendingUser = signup?.user || (signup?.id || signup?.email ? signup : null);
    return { needsEmailVerification: true, user: pendingUser };
  }
  return signup;
}

async function getSupabaseAuthUser(token) {
  const body = await supabaseAuthRequest("/user", { method: "GET" }, token);
  return body?.user || body;
}

async function localGetModel() {
  await ensureModel();
  try {
    return await readJsonFile(modelPath);
  } catch (error) {
    const backupPath = path.join(dataDir, `model.invalid-${Date.now()}.json`);
    await copyFile(modelPath, backupPath).catch(() => {});
    const seed = await readJsonFile(seedPath);
    await localSaveModel(seed);
    lastPersistence = {
      driver: "local",
      ok: false,
      message: `Recovered malformed local model.json; backup saved as ${path.basename(backupPath)}. ${error.message}`
    };
    return seed;
  }
}

let localModelSaveQueue = Promise.resolve();

async function renameLocalModelWithRetry(tempPath) {
  let lastError = null;
  for (let attempt = 1; attempt <= 8; attempt += 1) {
    try {
      await rename(tempPath, modelPath);
      return;
    } catch (error) {
      lastError = error;
      if (!["EPERM", "EBUSY", "EACCES"].includes(error?.code) || attempt === 8) throw error;
      await new Promise(resolve => setTimeout(resolve, 20 * attempt));
    }
  }
  throw lastError;
}

async function localSaveModel(model) {
  const save = async () => {
    await mkdir(dataDir, { recursive: true });
    model.updatedAt = new Date().toISOString();
    const tempPath = path.join(dataDir, `model.${process.pid}.${Date.now()}.${crypto.randomBytes(4).toString("hex")}.tmp`);
    await writeFile(tempPath, JSON.stringify(model, null, 2));
    await renameLocalModelWithRetry(tempPath);
    return model;
  };
  const pending = localModelSaveQueue.then(save, save);
  localModelSaveQueue = pending.then(() => undefined, () => undefined);
  return pending;
}

async function getSeedModel() {
  return readJsonFile(seedPath);
}

async function readJsonFile(filePath) {
  const raw = await readFile(filePath, "utf8");
  return JSON.parse(raw.replace(/^\uFEFF/, ""));
}

async function supabaseGetModel() {
  const rows = await supabaseRequest("/app_state?id=eq.primary&select=id,model,updated_at");
  if (Array.isArray(rows) && rows[0]?.model) {
    lastPersistence = { driver: "supabase", ok: true, message: "loaded cloud model" };
    return rows[0].model;
  }
  const seed = await getSeedModel();
  await supabaseSaveModel(seed);
  lastPersistence = { driver: "supabase", ok: true, message: "seeded cloud model" };
  return seed;
}

async function supabaseSaveModel(model) {
  model.updatedAt = new Date().toISOString();
  await supabaseRequest("/app_state?on_conflict=id", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=representation" },
    body: JSON.stringify([{ id: "primary", model, updated_at: model.updatedAt }])
  });
  lastPersistence = { driver: "supabase", ok: true, message: "saved cloud model" };
  return model;
}

function isUuid(value) {
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || ""));
}

function responseEventStatus(value = "unread") {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  return new Set(["unread", "read", "needs_reply", "drafted", "approved", "replied", "moderated", "ignored", "failed"]).has(normalized)
    ? normalized
    : "unread";
}

function publicResponseEvent(row = {}) {
  return {
    id: row.id || "",
    provider: row.provider || "",
    platform: row.platform || row.provider || "",
    providerEventId: row.provider_event_id || "",
    conversationId: row.conversation_id || "",
    parentEventId: row.parent_event_id || "",
    eventType: row.event_type || "response",
    author: {
      id: row.author_id || "",
      name: row.author_name || "",
      handle: row.author_handle || ""
    },
    body: row.body_text || "",
    media: Array.isArray(row.media) ? row.media : [],
    status: responseEventStatus(row.status),
    analysis: row.analysis && typeof row.analysis === "object" ? row.analysis : {},
    metadata: row.metadata && typeof row.metadata === "object" ? row.metadata : {},
    observedAt: row.observed_at || row.created_at || null,
    updatedAt: row.updated_at || null
  };
}

async function normalizedConnectedAccountId(user = {}, account = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  const platform = String(account?.platform || "").trim();
  const providerAccountId = String(account?.providerAccountId || account?.id || "").trim();
  if (!supabaseEnabled || !isUuid(workspaceId) || !isUuid(ownerUserId) || !platform || !providerAccountId) return "";
  const rows = await optionalSupabaseRequest(
    `/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.${encodeURIComponent(platform)}&provider_account_id=eq.${encodeURIComponent(providerAccountId)}&select=id&limit=1`
  );
  return Array.isArray(rows) ? rows[0]?.id || "" : "";
}

async function persistResponseEvents(user = {}, account = {}, events = []) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !isUuid(workspaceId) || !isUuid(ownerUserId) || !Array.isArray(events) || !events.length) return [];
  const connectedAccountId = await normalizedConnectedAccountId(user, account).catch(() => "");
  const now = new Date().toISOString();
  const rows = events.slice(0, 250).map(event => ({
    workspace_id: workspaceId,
    user_id: ownerUserId,
    connected_account_id: isUuid(connectedAccountId) ? connectedAccountId : null,
    provider: String(event.provider || account?.oauthProvider || account?.provider || account?.platform || "unknown").slice(0, 80),
    platform: String(event.platform || account?.platform || event.provider || "unknown").slice(0, 80),
    provider_event_id: String(event.providerEventId || event.id || "").slice(0, 500),
    conversation_id: String(event.conversationId || "").slice(0, 500) || null,
    parent_event_id: String(event.parentEventId || "").slice(0, 500) || null,
    event_type: String(event.eventType || "response").slice(0, 80),
    author_id: String(event.authorId || event.author?.id || "").slice(0, 500) || null,
    author_name: String(event.authorName || event.author?.name || "").slice(0, 500) || null,
    author_handle: String(event.authorHandle || event.author?.handle || "").slice(0, 500) || null,
    body_text: String(event.body || event.text || "").slice(0, 20000) || null,
    media: Array.isArray(event.media) ? event.media.slice(0, 20) : [],
    status: responseEventStatus(event.status),
    analysis: event.analysis && typeof event.analysis === "object" ? event.analysis : {},
    metadata: event.metadata && typeof event.metadata === "object" ? event.metadata : {},
    observed_at: event.observedAt || event.createdAt || now,
    updated_at: now
  })).filter(row => row.provider_event_id && row.provider !== "unknown");
  if (!rows.length) return [];
  const result = await optionalSupabaseRequest("/response_events?on_conflict=workspace_id,provider,provider_event_id&select=id,provider,platform,provider_event_id,status", {
    method: "POST",
    headers: { Prefer: "resolution=ignore-duplicates,return=representation" },
    body: JSON.stringify(rows)
  });
  return Array.isArray(result) ? result : [];
}

async function durableResponseInbox(user = {}, options = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !isUuid(workspaceId) || !isUuid(ownerUserId)) return [];
  const limit = Math.max(1, Math.min(200, Number(options.limit || 100)));
  const status = String(options.status || "").trim();
  const provider = String(options.provider || "").trim();
  const filters = [
    `workspace_id=eq.${encodeURIComponent(workspaceId)}`,
    `user_id=eq.${encodeURIComponent(ownerUserId)}`,
    status ? `status=eq.${encodeURIComponent(responseEventStatus(status))}` : "",
    provider ? `provider=eq.${encodeURIComponent(provider)}` : "",
    "select=id,provider,platform,provider_event_id,conversation_id,parent_event_id,event_type,author_id,author_name,author_handle,body_text,media,status,analysis,metadata,observed_at,created_at,updated_at",
    "order=observed_at.desc",
    `limit=${limit}`
  ].filter(Boolean).join("&");
  const rows = await optionalSupabaseRequest(`/response_events?${filters}`);
  return (Array.isArray(rows) ? rows : []).map(publicResponseEvent);
}

async function durableResponseEventForUser(user = {}, eventId = "") {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!isUuid(eventId) || !isUuid(workspaceId) || !isUuid(ownerUserId)) return null;
  const rows = await optionalSupabaseRequest(`/response_events?id=eq.${encodeURIComponent(eventId)}&workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&select=*&limit=1`);
  return Array.isArray(rows) ? rows[0] || null : null;
}

async function recordDurableResponseAction(user = {}, input = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !isUuid(workspaceId) || !isUuid(ownerUserId)) return null;
  const event = input.responseEventId ? await durableResponseEventForUser(user, input.responseEventId) : null;
  const providerEventId = String(input.providerEventId || input.targetId || "").trim();
  const idempotencyKey = String(input.idempotencyKey || `${input.provider || event?.provider || "response"}:${input.actionType || "action"}:${providerEventId || input.responseEventId || uid("action")}`).slice(0, 500);
  const now = new Date().toISOString();
  const rows = await optionalSupabaseRequest("/response_actions?on_conflict=workspace_id,idempotency_key&select=*", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=representation" },
    body: JSON.stringify([{
      workspace_id: workspaceId,
      user_id: ownerUserId,
      response_event_id: event?.id || null,
      provider: String(input.provider || event?.provider || "unknown").slice(0, 80),
      platform: String(input.platform || event?.platform || input.provider || "unknown").slice(0, 80),
      action_type: String(input.actionType || "action").slice(0, 80),
      idempotency_key: idempotencyKey,
      draft_text: String(input.draftText || input.text || "").slice(0, 20000) || null,
      status: String(input.status || "completed").slice(0, 40),
      approved_by: input.approved ? ownerUserId : null,
      approved_at: input.approved ? now : null,
      provider_action_id: String(input.providerActionId || "").slice(0, 500) || null,
      receipt: input.receipt && typeof input.receipt === "object" ? input.receipt : {},
      last_error: String(input.lastError || "").slice(0, 2000) || null,
      updated_at: now
    }])
  });
  return Array.isArray(rows) ? rows[0] || null : null;
}

function supabaseUserIdForUser(user = {}) {
  return [user.supabaseUserId, user.id].find(isUuid) || "";
}

function workspaceModelIdForUser(user = {}) {
  return [user.workspaceId, user.supabaseUserId, user.id].find(isUuid) || "";
}

const workspaceScopedCollectionKeys = ["campaigns", "quickPosts", "actions", "proof", "mediaAssets", "mediaRenderJobs", "publishQueue", "analyticsSnapshots", "providerStateSnapshots", "activity"];
const serverRetainedWorkspaceCollectionKeys = new Set(["mediaAssets", "mediaRenderJobs", "publishQueue", "analyticsSnapshots", "providerStateSnapshots"]);
const sharedRegistryKeys = ["authUsers", "deviceSessions", "oauthStates", "oauthEvents", "metaDeletionRequests", "billing", "integrations"];

function cloneJson(value) {
  return JSON.parse(JSON.stringify(value ?? null));
}

function copySharedRegistryFields(target = {}, shared = {}, { includeIntegrations = true } = {}) {
  for (const key of sharedRegistryKeys) {
    if (key === "integrations" && !includeIntegrations) continue;
    if (shared?.[key] !== undefined) target[key] = cloneJson(shared[key]);
  }
  return target;
}

