function workspaceOwnedItems(model, key, user = {}) {
  if (!Array.isArray(model?.[key]) || !user?.id) return [];
  return model[key].filter(item => ownedByUser(item, user.id));
}

function safeWorkspaceSnapshot(model, user = {}) {
  const safe = JSON.parse(JSON.stringify(model || {}));
  const workspace = workspaceForUser(model, user);
  safe.currentUser = publicAppUser(user);
  safe.workspace = workspace;
  safe.workspaces = [workspace];
  for (const key of workspaceScopedCollectionKeys) {
    safe[key] = workspaceOwnedItems(model, key, user);
  }
  safe.connectedAccounts = visibleConnectedAccounts(model)
    .filter(account => ownedByUser(account, user.id))
    .map(account => {
      const snapshot = publicAccount(account);
      return snapshot;
    });
  // Device sessions are security records, not workspace content. They are loaded
  // from the owner-scoped device_sessions table for every authenticated request.
  safe.deviceSessions = [];
  safe.billing = publicBilling(model.billing || {});
  safe.analytics = buildGrowthAnalytics(safe);
  delete safe.authUsers;
  delete safe.authPromoClaims;
  delete safe.oauthStates;
  delete safe.oauthEvents;
  delete safe.metaDeletionRequests;
  safe.workspaceModel = {
    version: 1,
    mirroredAt: new Date().toISOString(),
    source: "client-isolated-workspace",
    clientIsolated: true
  };
  return safe;
}

async function ensureSupabaseWorkspaceRows(model, user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId) return { ok: false, reason: "workspace user is not a Supabase UUID user" };
  const workspace = workspaceForUser(model, user);
  const now = new Date().toISOString();
  await supabaseRequest("/workspaces?on_conflict=id", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify([{
      id: workspaceId,
      owner_user_id: ownerUserId,
      name: workspace.name || "Social Cues",
      plan: user.entitlement?.access || "founder_alpha",
      updated_at: now
    }])
  });
  await supabaseRequest("/profiles?on_conflict=id", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify([{
      id: ownerUserId,
      workspace_id: workspaceId,
      display_name: user.name || "Social Cues User",
      email: user.email || "",
      role: user.role || "owner",
      updated_at: now
    }])
  });
  await optionalSupabaseRequest("/workspace_members?on_conflict=workspace_id,user_id", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify([{
      workspace_id: workspaceId,
      user_id: ownerUserId,
      role: "owner",
      updated_at: now
    }])
  });
  return { ok: true, workspaceId, ownerUserId };
}

async function mirrorWorkspaceModel(model, user = {}) {
  if (!supabaseEnabled || !user?.id) return { ok: false, skipped: true };
  try {
    const workspaceRows = await ensureSupabaseWorkspaceRows(model, user);
    if (!workspaceRows.ok) return workspaceRows;
    const snapshot = safeWorkspaceSnapshot(model, user);
    const now = new Date().toISOString();
    await supabaseRequest("/workspace_models?on_conflict=workspace_id", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify([{
        workspace_id: workspaceRows.workspaceId,
        owner_user_id: workspaceRows.ownerUserId,
        model: snapshot,
        updated_at: now
      }])
    });
    await mirrorNormalizedWorkspaceRows(model, user, workspaceRows);
    return { ok: true, workspaceId: workspaceRows.workspaceId };
  } catch (error) {
    lastPersistence = { driver: "supabase", ok: false, message: `workspace mirror failed: ${error.message}` };
    return { ok: false, error: error.message };
  }
}

function normalizedProviderCleanupKey(value = "") {
  return String(value || "").trim().toLowerCase().replace(/^@/, "").replace(/[^a-z0-9]+/g, "");
}

function normalizedStoredConnectionStatus(value = "") {
  return String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
}

async function cleanupNormalizedProviderPlaceholders(workspaceId, ownerUserId, authoritativeAccounts = []) {
  const connectedIdsByPlatform = new Map();
  for (const account of authoritativeAccounts) {
    const identity = providerIdentityEvidence(account);
    if (!identity.verified || !providerAccountConnectionState(account).connected) continue;
    const ids = connectedIdsByPlatform.get(account.platform) || new Set();
    ids.add(String(account.providerAccountId || account.id || ""));
    connectedIdsByPlatform.set(account.platform, ids);
  }
  if (!supabaseEnabled || !workspaceId || !ownerUserId || !connectedIdsByPlatform.size) return { deleted: 0 };
  const rows = await optionalSupabaseRequest(`/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&select=id,provider,platform,provider_account_id,display_name,handle,status&limit=200`);
  const staleIds = (Array.isArray(rows) ? rows : [])
    .filter(row => {
      const canonicalIds = connectedIdsByPlatform.get(row.platform);
      if (!canonicalIds?.size || normalizedStoredConnectionStatus(row.status) === "connected") return false;
      const providerAccountId = String(row.provider_account_id || "");
      const identity = providerIdentityEvidence({ platform: row.platform, providerAccountId });
      const genericLabels = new Set([
        normalizedProviderCleanupKey(row.platform),
        normalizedProviderCleanupKey(row.provider),
        normalizedProviderCleanupKey(platformDisplayName(row.platform)),
        "account",
        "user"
      ].filter(Boolean));
      const displayLabel = normalizedProviderCleanupKey(row.display_name || "");
      const handleLabel = normalizedProviderCleanupKey(row.handle || "");
      const genericIdentity = Boolean((displayLabel && genericLabels.has(displayLabel)) || (handleLabel && genericLabels.has(handleLabel)));
      return canonicalIds.has(providerAccountId) || !identity.verified || genericIdentity;
    })
    .map(row => row.id)
    .filter(Boolean);
  if (!staleIds.length) return { deleted: 0 };
  const ids = staleIds.map(id => encodeURIComponent(id)).join(",");
  await optionalSupabaseRequest(`/provider_tokens?connected_account_id=in.(${ids})`, {
    method: "DELETE",
    headers: { Prefer: "return=minimal" }
  });
  await optionalSupabaseRequest(`/connected_accounts?id=in.(${ids})&workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}`, {
    method: "DELETE",
    headers: { Prefer: "return=minimal" }
  });
  return { deleted: staleIds.length };
}

function providerPersistenceAccountKey(account = {}) {
  const providerAccountId = String(account.providerAccountId || account.id || "");
  if (!providerAccountId || !providerIdentityEvidence(account).verified) return "";
  return [
    String(account.ownerUserId || account.createdBy || ""),
    String(account.oauthProvider || account.provider || account.platform || ""),
    String(account.platform || ""),
    providerAccountId
  ].join("|");
}

function providerAccountFreshness(account = {}) {
  return [account.credentialUpdatedAt, account.connectedAt, account.updatedAt]
    .map(value => Date.parse(value || ""))
    .filter(Number.isFinite)
    .reduce((latest, value) => Math.max(latest, value), 0);
}

function providerAccountPersistenceRank(account = {}) {
  const state = providerAccountConnectionState(account);
  return (state.tokenStored ? 8 : 0)
    + (state.connected ? 4 : 0)
    + (state.refreshStored ? 2 : 0)
    + (state.identityVerified ? 1 : 0);
}

function dedupeProviderAccounts(accounts = []) {
  const deduped = [];
  const keyedIndexes = new Map();
  for (const account of Array.isArray(accounts) ? accounts : []) {
    const key = providerPersistenceAccountKey(account);
    if (!key) {
      deduped.push(account);
      continue;
    }
    const existingIndex = keyedIndexes.get(key);
    if (existingIndex === undefined) {
      keyedIndexes.set(key, deduped.length);
      deduped.push(account);
      continue;
    }
    const existing = deduped[existingIndex];
    const candidateFreshness = providerAccountFreshness(account);
    const existingFreshness = providerAccountFreshness(existing);
    const candidateWins = candidateFreshness > existingFreshness
      || (candidateFreshness === existingFreshness && providerAccountPersistenceRank(account) > providerAccountPersistenceRank(existing));
    const winner = candidateWins ? account : existing;
    const fallback = candidateWins ? existing : account;
    deduped[existingIndex] = mergeServerOnlyAccountFields(cloneJson(winner), fallback);
  }
  return deduped;
}

async function mirrorNormalizedWorkspaceRows(model, user = {}, workspaceRows = {}) {
  const workspaceId = workspaceRows.workspaceId || workspaceModelIdForUser(user);
  const ownerUserId = workspaceRows.ownerUserId || supabaseUserIdForUser(user);
  if (!workspaceId || !ownerUserId) return { ok: false, skipped: true };
  const now = new Date().toISOString();
  const normalizedConnectedAccounts = dedupeProviderAccounts(visibleConnectedAccounts(model));

  const accounts = normalizedConnectedAccounts
    .filter(account => ownedByUser(account, user.id)
      && (account.providerAccountId || account.id)
      && (providerIdentityEvidence(account).verified || hasStoredToken(account) || providerAccountConnectionState(account).connected))
    .map(account => {
      const connectionState = providerAccountConnectionState(account);
      const refreshable = connectionState.reason === "needs-refresh";
      const normalizedConnected = connectionState.connected || refreshable;
      return {
        workspace_id: workspaceId,
        user_id: ownerUserId,
        provider: account.oauthProvider || account.provider || account.platform,
        platform: account.platform,
        provider_account_id: String(account.providerAccountId || account.id),
        display_name: account.name || account.displayName || account.handle || account.platform,
        handle: account.handle || "",
        status: normalizedConnected ? "connected" : "not_connected",
        scopes: Array.isArray(account.scopes) ? account.scopes : [],
        public_profile: publicAccount(account),
        connected_at: normalizedConnected ? account.connectedAt || null : null,
        last_sync_at: account.lastSyncedAt || account.updatedAt || null,
        updated_at: now
      };
    });
  const accountRows = accounts.length ? await optionalSupabaseRequest("/connected_accounts?on_conflict=workspace_id,provider,platform,provider_account_id&select=id,provider,platform,provider_account_id", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=representation" },
    body: JSON.stringify(accounts)
  }) : null;

  if (Array.isArray(accountRows) && accountRows.length) {
    const tokenRows = [];
    const existingTokenRows = accountRows.length ? await optionalSupabaseRequest(
      `/provider_tokens?connected_account_id=in.(${accountRows.map(row => encodeURIComponent(row.id)).join(",")})&token_kind=eq.oauth&select=connected_account_id,updated_at&limit=200`
    ) : [];
    const existingTokenUpdatedAt = new Map((Array.isArray(existingTokenRows) ? existingTokenRows : []).map(row => [row.connected_account_id, row.updated_at || ""]));
    for (const account of normalizedConnectedAccounts) {
      if (!ownedByUser(account, user.id) || !hasStoredToken(account)) continue;
      const provider = account.oauthProvider || account.provider || account.platform;
      const providerAccountId = String(account.providerAccountId || account.id);
      const row = accountRows.find(item =>
        item.provider === provider
        && item.platform === account.platform
        && String(item.provider_account_id) === providerAccountId
      );
      if (!row?.id || !account.credential) continue;
      const incomingCredentialAt = newestProviderCredentialEvidenceAt(account);
      const existingCredentialAt = existingTokenUpdatedAt.get(row.id) || "";
      if (existingCredentialAt && Date.parse(existingCredentialAt) >= Date.parse(incomingCredentialAt || "")) continue;
      tokenRows.push({
        connected_account_id: row.id,
        workspace_id: workspaceId,
        user_id: ownerUserId,
        provider,
        token_kind: "oauth",
        encrypted_token: account.credential,
        encrypted_refresh_token: account.refreshCredential || null,
        token_type: account.tokenType || null,
        scopes: Array.isArray(account.scopes) ? account.scopes : [],
        expires_at: account.tokenExpiresAt || null,
        refresh_expires_at: account.refreshTokenExpiresAt || null,
        updated_at: incomingCredentialAt || now
      });
    }
    if (tokenRows.length) {
      await optionalSupabaseRequest("/provider_tokens?on_conflict=connected_account_id,token_kind", {
        method: "POST",
        headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
        body: JSON.stringify(tokenRows)
      });
    }
  }
  await cleanupNormalizedProviderPlaceholders(workspaceId, ownerUserId, normalizedConnectedAccounts);

  const existingDeviceRows = await optionalSupabaseRequest(
    `/device_sessions?user_id=eq.${encodeURIComponent(ownerUserId)}&select=device_id,revoked_at,trusted`
  );
  const existingDevices = new Map((Array.isArray(existingDeviceRows) ? existingDeviceRows : []).map(row => [String(row.device_id), row]));
  const devices = (model.deviceSessions || [])
    .filter(device => {
      if (String(device.userId || "") !== String(user.id)) return false;
      const deviceId = String(device.deviceId || device.id || "");
      if (existingDevices.has(deviceId)) return true;
      const activatedAt = Date.parse(device.activatedAt || "");
      return Number.isFinite(activatedAt) && activatedAt >= Date.now() - 10 * 60 * 1000;
    })
    .map(device => {
      const deviceId = String(device.deviceId || device.id);
      const existing = existingDevices.get(deviceId);
      const existingRevokedAt = existing?.revoked_at || null;
      const explicitlyReactivated = Boolean(
        existingRevokedAt
        && device.activatedAt
        && Date.parse(device.activatedAt) > Date.parse(existingRevokedAt)
      );
      const preserveDurableRevocation = Boolean(existingRevokedAt && !device.revokedAt && !explicitlyReactivated);
      return {
        workspace_id: workspaceId,
        user_id: ownerUserId,
        device_id: deviceId,
        session_token_hash: device.sessionTokenHash || "",
        encrypted_refresh_credential: device.refreshCredential || null,
        auth_token_expires_at: device.tokenExpiresAt || null,
        session_provider: device.sessionProvider || "supabase",
        name: device.name || "This device",
        kind: device.kind || "",
        user_agent: device.userAgent || "",
        platform: device.platform || "",
        language: device.language || "",
        screen: device.screen || "",
        time_zone: device.timeZone || "",
        trusted: preserveDurableRevocation ? false : device.trusted !== false && !device.revokedAt,
        login_count: Number(device.loginCount || 0),
        last_seen_at: device.lastSeenAt || null,
        expires_at: device.expiresAt || null,
        revoked_at: preserveDurableRevocation ? existingRevokedAt : device.revokedAt || null,
        updated_at: now
      };
    });
  if (devices.length) {
    await optionalSupabaseRequest("/device_sessions?on_conflict=user_id,device_id", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify(devices)
    });
  }

  const queue = publishQueueLedger(model, { user }, { includeFuture: true }).rows;
  if (queue.length) {
    await optionalSupabaseRequest("/scheduled_posts?on_conflict=workspace_id,external_key", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify(queue.map(row => ({
        workspace_id: workspaceId,
        external_key: String(row.id),
        platform: row.platform || "unknown",
        status: row.status || "queued",
        caption: row.copyPreview || "",
        scheduled_for: row.scheduledFor || row.queuedAt || now,
        published_at: row.publishedAt || null,
        provider_post_id: row.providerPostId || null,
        publish_error: ["blocked", "failed", "retrying"].includes(row.status) ? row.lastAttempt?.error || null : null,
        idempotency_key: row.idempotencyKey || null,
        retry_count: Number(row.retryCount || 0),
        max_attempts: 5,
        next_retry_at: row.nextRetryAt || null,
        last_attempt_at: row.lastAttempt?.at || row.lastAttemptAt || null,
        updated_at: now
      })))
    });
  }

  const receiptRows = [];
  for (const campaign of contentVariantBatches(model)) {
    for (const variant of campaign.variants || []) {
      const recordedReceipts = Array.isArray(variant.publishReceipts) ? [...variant.publishReceipts] : [];
      if (variant.status === "published" && variant.providerPostId && !recordedReceipts.some(receipt => String(receipt.providerPostId || "") === String(variant.providerPostId))) {
        recordedReceipts.push({
          provider: variant.connector || variant.platform,
          providerPostId: variant.providerPostId,
          idempotencyKey: publishIdempotencyKey({ campaign, variant }),
          status: "published",
          publishedAt: variant.publishedAt || variant.updatedAt || now,
          recoveredFromVariantEvidence: true
        });
      }
      for (const receipt of recordedReceipts) {
        if (!receipt.idempotencyKey) continue;
        receiptRows.push({
          workspace_id: workspaceId,
          user_id: ownerUserId,
          queue_external_key: `variant-${variant.id}`,
          campaign_external_id: String(campaign.id || ""),
          variant_external_id: String(variant.id || ""),
          provider: receipt.provider || variant.platform,
          platform: variant.platform,
          idempotency_key: receipt.idempotencyKey,
          provider_post_id: receipt.providerPostId || variant.providerPostId || null,
          status: receipt.status || "published",
          published_at: receipt.publishedAt || variant.publishedAt || null,
          receipt_summary: {
            duplicateSuppressed: Boolean(receipt.duplicateSuppressed),
            recoveredFromVariantEvidence: Boolean(receipt.recoveredFromVariantEvidence)
          },
          updated_at: now
        });
      }
    }
  }
  if (receiptRows.length) {
    await optionalSupabaseRequest("/publish_receipts?on_conflict=workspace_id,idempotency_key", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify(receiptRows)
    });
  }

  const snapshotRows = (model.analyticsSnapshots || []).map(snapshot => ({
    workspace_id: workspaceId,
    external_key: String(snapshot.id),
    source: snapshot.source || "unknown",
    provider: snapshot.provider || null,
    platform: snapshot.platform || null,
    metric_date: String(snapshot.createdAt || snapshot.lastCompiledAt || now).slice(0, 10),
    metrics: { summary: snapshot.summary || {}, metrics: snapshot.metrics || [], deltas: snapshot.deltas || [] },
    translated_analysis: snapshot.translatedAnalysis || [],
    publish_idempotency_keys: snapshot.publishIdempotencyKeys || [],
    created_at: snapshot.createdAt || now
  }));
  if (snapshotRows.length) {
    await optionalSupabaseRequest("/analytics_snapshots?on_conflict=workspace_id,external_key", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify(snapshotRows)
    });
  }

  const entitlement = publicEntitlement(user);
  if (entitlement) {
    await optionalSupabaseRequest("/billing_entitlements?on_conflict=workspace_id,user_id", {
      method: "POST",
      headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
      body: JSON.stringify([{
        workspace_id: workspaceId,
        user_id: ownerUserId,
        source: entitlement.source || "none",
        access: entitlement.access || "unpaid",
        status: entitlement.active ? "active" : "inactive",
        promo_code: entitlement.promoCode || null,
        stripe_customer_id: user.entitlement?.stripeCustomerId || null,
        stripe_subscription_id: user.entitlement?.stripeSubscriptionId || null,
        current_period_end: entitlement.expiresAt || null,
        updated_at: now
      }])
    });
  }

  return { ok: true };
}

function newestProviderCredentialEvidenceAt(account = {}) {
  const newest = [account.credentialUpdatedAt, account.connectedAt]
    .map(value => Date.parse(value || ""))
    .filter(Number.isFinite)
    .reduce((latest, value) => Math.max(latest, value), 0);
  return newest ? new Date(newest).toISOString() : "";
}

async function workspaceModelMirrorStatus(user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  if (!supabaseEnabled || !workspaceId) return { ready: false, mirrored: false, reason: "workspace mirror requires Supabase Auth user ids" };
  try {
    const rows = await supabaseRequest(`/workspace_models?workspace_id=eq.${encodeURIComponent(workspaceId)}&select=workspace_id,updated_at&limit=1`);
    return { ready: true, mirrored: Boolean(rows?.[0]), workspaceId, updatedAt: rows?.[0]?.updated_at || null };
  } catch (error) {
    return { ready: false, mirrored: false, workspaceId, error: error.message };
  }
}

async function rehydrateProviderTokenAccounts(model = {}, user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId) return false;
  const accountRows = await optionalSupabaseRequest(`/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&select=id,provider,platform,provider_account_id,display_name,handle,status,scopes,connected_at,public_profile&limit=200`);
  if (!Array.isArray(accountRows) || !accountRows.length) return false;
  const accountIds = accountRows.map(row => row.id).filter(Boolean);
  const tokenRows = accountIds.length
    ? await optionalSupabaseRequest(`/provider_tokens?connected_account_id=in.(${accountIds.map(id => encodeURIComponent(id)).join(",")})&token_kind=eq.oauth&select=connected_account_id,encrypted_token,encrypted_refresh_token,token_type,scopes,expires_at,refresh_expires_at,updated_at&limit=200`)
    : [];
  const tokensByAccountId = new Map((Array.isArray(tokenRows) ? tokenRows : []).map(row => [row.connected_account_id, row]));
  model.connectedAccounts = Array.isArray(model.connectedAccounts) ? model.connectedAccounts : [];
  let changed = false;
  for (const row of accountRows) {
    const tokenRow = tokensByAccountId.get(row.id);
    const publicProfile = row.public_profile && typeof row.public_profile === "object" ? row.public_profile : {};
    const providerAccountId = String(row.provider_account_id || publicProfile.providerAccountId || "");
    const platform = row.platform || publicProfile.platform || row.provider;
    if (!platform) continue;
    const identity = providerIdentityEvidence({ ...publicProfile, platform, providerAccountId });
    const storedStatus = normalizedStoredConnectionStatus(row.status || publicProfile.status || "");
    if (!tokenRow?.encrypted_token && !identity.verified && storedStatus !== "connected") continue;
    let account = model.connectedAccounts.find(item =>
      item.platform === platform
      && ownedByUser(item, user.id)
      && (
        (providerAccountId && String(item.providerAccountId || "") === providerAccountId)
        || (!item.providerAccountId && String(item.id || "") === String(publicProfile.id || ""))
        || (!item.providerAccountId && !providerAccountId)
      )
    );
    if (!account) {
      account = {
        id: publicProfile.id || uid("acct"),
        platform,
        name: publicProfile.name || row.display_name || platform,
        handle: row.handle || publicProfile.handle || "",
        status: row.status || publicProfile.status || "not connected",
        connectedAt: row.connected_at || publicProfile.connectedAt || null
      };
      stampWorkspaceOwnership(account, user, workspaceId);
      model.connectedAccounts.push(account);
    }
    const nextName = platform === "x" ? "X" : (publicProfile.name || row.display_name || account.name || platform);
    const nextDisplayName = platform === "x" ? (publicProfile.displayName || row.display_name || account.displayName || account.name || "") : (publicProfile.displayName || row.display_name || account.displayName || "");
    Object.assign(account, {
      platform,
      name: nextName,
      displayName: nextDisplayName,
      handle: row.handle || publicProfile.handle || account.handle || "",
      status: row.status || publicProfile.status || account.status || "not connected",
      connectedAt: row.connected_at || publicProfile.connectedAt || account.connectedAt || null,
      providerAccountId: providerAccountId || account.providerAccountId || null,
      oauthProvider: row.provider || publicProfile.oauthProvider || account.oauthProvider || platform,
      scopes: Array.isArray(tokenRow?.scopes) && tokenRow.scopes.length ? tokenRow.scopes : Array.isArray(row.scopes) ? row.scopes : Array.isArray(publicProfile.scopes) ? publicProfile.scopes : account.scopes || [],
      tokenType: tokenRow?.token_type || account.tokenType || null,
      tokenExpiresAt: tokenRow?.expires_at || account.tokenExpiresAt || null,
      refreshTokenExpiresAt: tokenRow?.refresh_expires_at || account.refreshTokenExpiresAt || null
    });
    if (tokenRow?.updated_at) account.credentialUpdatedAt = tokenRow.updated_at;
    if (tokenRow?.encrypted_token) account.credential = tokenRow.encrypted_token;
    if (tokenRow?.encrypted_refresh_token) account.refreshCredential = tokenRow.encrypted_refresh_token;
    if (tokenRow?.encrypted_token && providerAccountId && account.oauthProvider && account.status !== "connected" && !providerAccountConnectionState(account).needsReconnect) {
      account.status = "connected";
      account.connectedAt = account.connectedAt || row.connected_at || publicProfile.connectedAt || new Date().toISOString();
      account.connectionEvidence = `${String(account.oauthProvider).toUpperCase()} token/provider evidence restored connected status.`;
    }
    delete account.connected;
    delete account.tokenStored;
    changed = true;
  }
  const dedupedAccounts = dedupeProviderAccounts(model.connectedAccounts);
  if (dedupedAccounts.length !== model.connectedAccounts.length) {
    model.connectedAccounts = dedupedAccounts;
    changed = true;
  }
  if (reconcileProviderAccountEvidence(model)) changed = true;
  return changed;
}

function reconcileProviderAccountEvidence(model = {}) {
  const accounts = Array.isArray(model.connectedAccounts) ? model.connectedAccounts : [];
  const authoritativePlatforms = new Set(accounts
    .filter(account => providerIdentityEvidence(account).verified && hasStoredToken(account))
    .map(account => account.platform));
  const reconciled = accounts.filter(account =>
    !(authoritativePlatforms.has(account.platform) && !providerIdentityEvidence(account).verified)
  );
  if (reconciled.length === accounts.length) return false;
  model.connectedAccounts = reconciled;
  return true;
}

function providerCacheAliases(platform = "") {
  const key = String(platform || "").toLowerCase();
  const aliases = {
    meta: ["meta", "facebook", "instagram"],
    facebook: ["facebook"],
    instagram: ["instagram"],
    tiktok: ["tiktok", "short-video"],
    youtube: ["youtube"],
    google_growth: ["google_growth", "google"],
    google_business: ["google_business", "google"],
    x: ["x"],
    pinterest: ["pinterest"],
    canva: ["canva"],
    shopify: ["shopify"],
    etsy: ["etsy"],
    twitch: ["twitch"],
    discord: ["discord"],
    manychat: ["manychat"],
    reddit: ["reddit"]
  };
  return [...new Set([key, ...(aliases[key] || [])].filter(Boolean))];
}

function providerCacheTerms(platform = "") {
  return providerCacheAliases(platform)
    .flatMap(id => [id, platformDisplayName(id), providerAssetKind(id)])
    .map(value => String(value || "").trim().toLowerCase())
    .filter(value => value && value !== "x");
}

function cacheRecordOwnedByUser(record = {}, user = null) {
  return !user || !hasOwnerMarker(record) || ownedByUser(record, user.id);
}

function recordMatchesProvider(record = {}, aliases = []) {
  const aliasSet = new Set(aliases.map(item => String(item || "").toLowerCase()));
  return [
    record.providerId,
    record.platform,
    record.provider,
    record.id,
    record.sourceKey
  ].some(value => aliasSet.has(String(value || "").toLowerCase()));
}

function pruneProviderRowsFromSnapshot(record = {}, aliases = []) {
  if (!Array.isArray(record.rows)) return { record, changed: false, keep: true };
  const aliasSet = new Set(aliases.map(item => String(item || "").toLowerCase()));
  const rows = record.rows.filter(row => !aliasSet.has(String(row.id || row.platform || row.providerId || "").toLowerCase()));
  if (rows.length === record.rows.length) return { record, changed: false, keep: true };
  const next = {
    ...record,
    rows,
    summary: {
      ...(record.summary || {}),
      total: rows.length,
      connected: rows.filter(row => row.connected).length,
      canPublish: rows.filter(row => row.canPublish).length,
      canReadAnalytics: rows.filter(row => row.canReadAnalytics).length,
      blocked: rows.filter(row => Array.isArray(row.blockers) && row.blockers.length).length
    },
    cachePurgedAt: new Date().toISOString()
  };
  return { record: next, changed: true, keep: rows.length > 0 };
}

function pruneProviderEntriesFromArray(value = [], terms = []) {
  if (!Array.isArray(value)) return { value, removed: 0 };
  const filtered = value.filter(item => {
    const text = JSON.stringify(item || {}).toLowerCase();
    return !terms.some(term => term && text.includes(term));
  });
  return { value: filtered, removed: value.length - filtered.length };
}

function clearProviderWorkspaceCache(model = {}, user = null, platform = "") {
  const aliases = providerCacheAliases(platform);
  const terms = providerCacheTerms(platform);
  const aliasSet = new Set(aliases);
  const purged = {
    functionChecks: 0,
    providerStateSnapshots: 0,
    analyticsSnapshots: 0,
    activity: 0,
    proof: 0,
    metaCache: false
  };

  if (model.functionChecks && typeof model.functionChecks === "object") {
    for (const key of aliases) {
      if (model.functionChecks[key]) {
        delete model.functionChecks[key];
        purged.functionChecks += 1;
      }
    }
  }

  if (Array.isArray(model.providerStateSnapshots)) {
    const next = [];
    for (const record of model.providerStateSnapshots) {
      if (!cacheRecordOwnedByUser(record, user)) {
        next.push(record);
        continue;
      }
      const pruned = pruneProviderRowsFromSnapshot(record, aliases);
      if (pruned.changed) purged.providerStateSnapshots += 1;
      if (pruned.keep) next.push(pruned.record);
    }
    model.providerStateSnapshots = next;
  }

  if (Array.isArray(model.analyticsSnapshots)) {
    const next = [];
    for (const record of model.analyticsSnapshots) {
      if (!cacheRecordOwnedByUser(record, user)) {
        next.push(record);
        continue;
      }
      let changed = false;
      const prunedRecord = { ...record };
      for (const key of ["metrics", "sourceBreakdown", "translatedAnalysis"]) {
        const pruned = pruneProviderEntriesFromArray(prunedRecord[key], terms);
        if (pruned.removed) {
          prunedRecord[key] = pruned.value;
          changed = true;
        }
      }
      if (changed) {
        purged.analyticsSnapshots += 1;
        prunedRecord.metricCount = Array.isArray(prunedRecord.metrics) ? prunedRecord.metrics.length : prunedRecord.metricCount;
        prunedRecord.cachePurgedAt = new Date().toISOString();
      }
      next.push(prunedRecord);
    }
    model.analyticsSnapshots = next;
  }

  if (Array.isArray(model.activity)) {
    const before = model.activity.length;
    model.activity = model.activity.filter(record => !cacheRecordOwnedByUser(record, user) || !recordMatchesProvider(record, aliases));
    purged.activity = before - model.activity.length;
  }

  if (Array.isArray(model.proof)) {
    const before = model.proof.length;
    model.proof = model.proof.filter(record => {
      if (!cacheRecordOwnedByUser(record, user)) return true;
      if (recordMatchesProvider(record, aliases)) return false;
      const text = `${record.metric || ""} ${record.note || ""}`.toLowerCase();
      return !terms.some(term => term && text.includes(term));
    });
    purged.proof = before - model.proof.length;
  }

  if (platform === "meta") {
    if (model.metaConnection || model.metaHealth) purged.metaCache = true;
    delete model.metaConnection;
    delete model.metaHealth;
  } else if (platform === "facebook" && model.metaConnection) {
    model.metaConnection = {
      ...(model.metaConnection || {}),
      pageCount: 0,
      discoveredCount: 0,
      rawPageCount: 0
    };
    if (model.metaHealth?.assetSync) {
      model.metaHealth.assetSync.pagesReturned = 0;
      model.metaHealth.assetSync.pagesAvailable = 0;
    }
    purged.metaCache = true;
  } else if (platform === "instagram" && model.metaConnection) {
    model.metaConnection = {
      ...(model.metaConnection || {}),
      instagramCount: 0,
      rawInstagramCount: 0
    };
    if (model.metaHealth?.assetSync) {
      model.metaHealth.assetSync.instagramReturned = 0;
      model.metaHealth.assetSync.instagramAvailable = 0;
    }
    purged.metaCache = true;
  }

  model.integrations = model.integrations || {};
  if (platform) model.integrations[platform] = "Disabled by user; cached provider data cleared. Reconnect to restore.";
  return { ok: true, platform, aliases, purged };
}

async function clearNormalizedProviderRowsForPlatform(user = {}, platform = "") {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId || !platform) return { ok: false, skipped: true };
  const accountRows = await optionalSupabaseRequest(`/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.${encodeURIComponent(platform)}&select=id`);
  const ids = Array.isArray(accountRows) ? accountRows.map(row => row.id).filter(Boolean) : [];
  if (ids.length) {
    await optionalSupabaseRequest(`/provider_tokens?connected_account_id=in.(${ids.map(id => encodeURIComponent(id)).join(",")})`, {
      method: "DELETE",
      headers: { Prefer: "return=minimal" }
    });
  }
  await optionalSupabaseRequest(`/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.${encodeURIComponent(platform)}`, {
    method: "DELETE",
    headers: { Prefer: "return=minimal" }
  });
  return { ok: true, deletedAccounts: ids.length };
}

function mergeWorkspaceRuntimeFields(workspaceModel = {}, sharedModel = {}, user = {}) {
  const merged = JSON.parse(JSON.stringify(workspaceModel || {}));
  for (const key of ["authUsers", "deviceSessions", "oauthStates", "oauthEvents", "metaDeletionRequests"]) {
    if (sharedModel?.[key] !== undefined) merged[key] = cloneJson(sharedModel[key]);
  }
  if (sharedModel?.billing && !merged.billing) merged.billing = sharedModel.billing;
  if (sharedModel?.integrations && !merged.integrations) merged.integrations = sharedModel.integrations;
  if (user?.id) {
    merged.currentUser = publicAppUser(user);
    merged.workspace = workspaceForUser(workspaceModel, user);
    merged.workspaces = [merged.workspace];
  }
  merged.loadedFromWorkspaceModel = Boolean(workspaceModel?.workspaceModel);
  return merged;
}

function isProductOwnerAccount(user = {}) {
  const role = String(resolvedAppUserRole(user) || user.role || "").trim().toLowerCase();
  const source = String(user.entitlement?.source || "").trim().toLowerCase();
  return source === "owner-allowlist" || role === "owner";
}

function hasLegacySharedWorkspaceContamination(model = {}, user = {}) {
  if (!user?.id || isProductOwnerAccount(user)) return false;
  const source = String(model.workspaceModel?.source || "").trim().toLowerCase();
  if (source !== "app_state.compatibility.filtered") return false;
  const campaigns = Array.isArray(model.campaigns) ? model.campaigns : [];
  const sharedCampaign = campaigns.some(campaign =>
    campaign?.id === "camp-Social Cues-self-launch"
    || campaign?.title === "Social Cues Customer-Ready Launch"
  );
  const sharedOnboarding = model.onboarding?.offer === "Social Cues"
    && String(model.onboarding?.purpose || "").includes("launch itself");
  return sharedCampaign || sharedOnboarding;
}

async function supabaseGetWorkspaceModel(user = {}, sharedModel = null) {
  const workspaceId = workspaceModelIdForUser(user);
  if (!supabaseEnabled || !workspaceId) return null;
  const [rows, normalizedRows] = await Promise.all([
    supabaseRequest(`/workspace_models?workspace_id=eq.${encodeURIComponent(workspaceId)}&select=workspace_id,model,updated_at&limit=1`),
    optionalSupabaseRequest(`/workspaces?id=eq.${encodeURIComponent(workspaceId)}&select=id,name,owner_user_id,created_at,updated_at&limit=1`)
  ]);
  if (!Array.isArray(rows) || !rows[0]?.model) return null;
  const snapshot = cloneJson(rows[0].model);
  const normalizedWorkspace = Array.isArray(normalizedRows) ? normalizedRows[0] : null;
  if (normalizedWorkspace?.name) {
    snapshot.workspace = {
      ...(snapshot.workspace || {}),
      id: workspaceId,
      name: normalizedWorkspace.name,
      ownerUserId: user.id || normalizedWorkspace.owner_user_id || "",
      owner: user.name || snapshot.workspace?.owner || "Workspace Owner",
      ownerEmail: user.email || snapshot.workspace?.ownerEmail || "",
      createdAt: normalizedWorkspace.created_at || snapshot.workspace?.createdAt || null,
      updatedAt: normalizedWorkspace.updated_at || snapshot.workspace?.updatedAt || null
    };
    snapshot.workspaces = [snapshot.workspace];
  }
  if (hasLegacySharedWorkspaceContamination(snapshot, user)) {
    const clean = await clientWorkspaceModelForUser(user, {
      workspaceName: normalizedWorkspace?.name || snapshot.workspace?.name || `${user.name || "User"}'s Social Cues`
    }, sharedModel || {});
    clean.workspaceModel = {
      ...(clean.workspaceModel || {}),
      source: "legacy-shared-seed-quarantine",
      clientIsolated: true,
      quarantinedAt: new Date().toISOString()
    };
    await rehydrateProviderTokenAccounts(clean, user);
    const devices = await normalizedDeviceSessionsForUser(supabaseUserIdForUser(user));
    replaceUserDeviceSessions(clean, user.id, devices);
    await mirrorWorkspaceModel(clean, user);
    lastPersistence = { driver: "supabase", ok: true, message: "quarantined legacy shared workspace seed" };
    return clean;
  }
  const model = mergeWorkspaceRuntimeFields(snapshot, sharedModel || {}, user);
  try {
    await rehydrateProviderTokenAccounts(model, user);
  } catch (error) {
    lastPersistence = { driver: "supabase", ok: false, message: `provider token rehydrate failed: ${error.message}` };
    console.warn(JSON.stringify({
      event: "provider_token_rehydrate_failed",
      workspaceId,
      ownerUserId: supabaseUserIdForUser(user) || null,
      message: String(error.message || error).slice(0, 300)
    }));
  }
  sanitizeConnectedAccounts(model);
  const devices = await normalizedDeviceSessionsForUser(supabaseUserIdForUser(user));
  replaceUserDeviceSessions(model, user.id, devices);
  repairTokenBackedMetaAssets(model, user);
  hydrateMetaLoginStatus(model);
  model.workspaceModel = {
    ...(model.workspaceModel || {}),
    version: model.workspaceModel?.version || 1,
    loadedAt: new Date().toISOString(),
    updatedAt: rows[0].updated_at || null,
    source: "workspace_models"
  };
  lastPersistence = { driver: "supabase", ok: true, message: "loaded workspace model" };
  return model;
}

async function modelForSession(session = null, sharedModel = null) {
  const base = sharedModel || await getModel();
  if (!session?.user) return base;
  if (!supabaseEnabled) return base;
  try {
    const workspaceModel = await supabaseGetWorkspaceModel(session.user, base);
    if (workspaceModel) return workspaceModel;
  } catch (error) {
    lastPersistence = { driver: "supabase", ok: false, message: `workspace load failed: ${error.message}` };
  }
  return clientWorkspaceModelForUser(session.user, {}, base);
}

async function getModel() {
  let model;
  try {
    model = supabaseEnabled ? await supabaseGetModel() : await localGetModel();
  } catch (error) {
    lastPersistence = { driver: "supabase", ok: false, message: error.message };
    model = await localGetModel();
  }
  let changed = false;
  if (!Array.isArray(model.connectedAccounts)) {
    const seed = await getSeedModel();
    model.connectedAccounts = seed.connectedAccounts || [];
    changed = true;
  }
  if (!model.activeProviderAccounts || typeof model.activeProviderAccounts !== "object" || Array.isArray(model.activeProviderAccounts)) {
    model.activeProviderAccounts = {};
    changed = true;
  }
  if (!("currentUser" in model)) {
    model.currentUser = null;
    changed = true;
  }
  if (!Array.isArray(model.actions)) {
    const seed = await getSeedModel();
    model.actions = seed.actions || [];
    changed = true;
  }
  if (!model.onboarding) {
    const seed = await getSeedModel();
    model.onboarding = seed.onboarding || {};
    changed = true;
  }
  if (!model.analytics) {
    const seed = await getSeedModel();
    model.analytics = seed.analytics || { metrics: [] };
    changed = true;
  }
  for (const key of ["quickPosts", "publishQueue", "analyticsSnapshots", "providerStateSnapshots", "mediaRenderJobs"]) {
    if (!Array.isArray(model[key])) {
      model[key] = [];
      changed = true;
    }
  }
  if (model.integrations) {
    for (const key of ["sora"]) {
      if (key in model.integrations) {
        delete model.integrations[key];
        changed = true;
      }
    }
    if (model.integrations.shopify !== "Backlog") {
      model.integrations.shopify = "Backlog";
      changed = true;
    }
    const pinterestStatus = pinterestCredentialsReady()
      ? (model.integrations.pinterest || "OAuth credentials ready")
      : pinterestAppShellReady()
        ? "Developer app created; Trial access pending in Pinterest review"
        : "Developer app pending";
    if (model.integrations.pinterest !== pinterestStatus) {
      model.integrations.pinterest = pinterestStatus;
      changed = true;
    }
    const canvaStatus = canvaClientId && canvaClientSecret ? (model.integrations.canva || "OAuth credentials ready") : "MFA / developer integration pending";
    if (model.integrations.canva !== canvaStatus) {
      model.integrations.canva = canvaStatus;
      changed = true;
    }
  }
  if (!model.billing) {
    const seed = await getSeedModel();
    model.billing = seed.billing || {};
    changed = true;
  }
  if (sanitizeConnectedAccounts(model)) changed = true;
  if (reconcileProviderAccountEvidence(model)) changed = true;
  if (hydrateMetaLoginStatus(model)) changed = true;
  if (changed) await saveModel(model);
  return model;
}

function isConnectedStatus(status) {
  return String(status || "").toLowerCase() === "connected";
}

function hasStoredToken(account) {
  return Boolean(account?.credential || account?.token || account?.accessToken || account?.refreshToken);
}

function isRealConnectedAccount(account) {
  if (account?.disabled) return false;
  if (!account || account.status !== "connected") return false;
  const identityVerified = providerIdentityEvidence(account).verified;
  if (account.platform === "meta") return account.oauthProvider === "meta" && hasStoredToken(account) && identityVerified;
  if (account.platform === "facebook") return account.oauthProvider === "meta" && hasStoredToken(account) && identityVerified;
  if (account.platform === "instagram") return ["meta", "instagram"].includes(account.oauthProvider) && hasStoredToken(account) && identityVerified;
  if (account.platform === "threads") return account.oauthProvider === "threads" && hasStoredToken(account) && identityVerified;
  if (account.platform === "x") return account.oauthProvider === "x" && hasStoredToken(account) && identityVerified;
  return hasStoredToken(account) && identityVerified;
}

function providerAccountConnectionState(account) {
  const tokenStored = hasStoredToken(account);
  const refreshStored = Boolean(account?.refreshCredential || account?.refreshToken);
  const storedStatus = String(account?.status || "not connected");
  const identity = providerIdentityEvidence(account || {});
  const expiresAtMs = Date.parse(account?.tokenExpiresAt || "");
  const expired = Number.isFinite(expiresAtMs) && expiresAtMs <= Date.now();
  const needsReconnect = Boolean(
    account?.needsReconnect
    || account?.refreshError
    || account?.lastTokenError
    || account?.tokenValid === false
  );
  const reason = account?.disabled ? "disabled"
    : !tokenStored ? "missing-token"
    : !identity.verified ? identity.reason
    : needsReconnect ? "needs-reconnect"
    : expired && refreshStored ? "needs-refresh"
    : expired ? "expired"
    : !isConnectedStatus(storedStatus) ? "stored-not-connected"
    : "connected";
  return {
    connected: reason === "connected" && isRealConnectedAccount(account),
    tokenStored,
    refreshStored,
    storedStatus,
    identityVerified: identity.verified,
    identityReason: identity.reason,
    reason,
    expired,
    needsReconnect,
    tokenExpiresAt: account?.tokenExpiresAt || null
  };
}

function isVerifiedThreadsProviderAccountId(value = "") {
  return providerIdentityEvidence({ platform: "threads", providerAccountId: value }).verified;
}

function threadsAccountNeedsIdentityRepair(account = null) {
  if (!account || account.oauthProvider !== "threads" || !hasStoredToken(account)) return false;
  if (!isVerifiedThreadsProviderAccountId(account.providerAccountId)) return true;
  if (!(account.scopes || []).includes("threads_basic")) return true;
  return !String(account.handle || "").trim() || ["threads", "@threads"].includes(String(account.handle || "").trim().toLowerCase());
}

function repairConnectedOAuthAccount(account, provider) {
  if (!account || account.disabled) return false;
  if (account.status === "connected") return false;
  if (account.oauthProvider !== provider) return false;
  if (!hasStoredToken(account) || !account.providerAccountId) return false;
  if (account.tokenExpiresAt && Date.parse(account.tokenExpiresAt) <= Date.now()) return false;
  account.status = "connected";
  account.connectedAt = account.connectedAt || new Date().toISOString();
  account.connectionEvidence = `${provider.toUpperCase()} token/provider evidence restored connected status.`;
  return true;
}

function sanitizeConnectedAccounts(model) {
  if (!Array.isArray(model.connectedAccounts)) return false;
  let changed = false;
  for (const account of model.connectedAccounts) {
    if (!account.credential && account.token) {
      account.credential = account.token;
      delete account.token;
      changed = true;
    }
    if (account.accessToken) {
      delete account.accessToken;
      changed = true;
    }
    if (account.refreshToken) {
      delete account.refreshToken;
      changed = true;
    }
    const status = String(account.status || "").toLowerCase();
    const pendingOauth = ["oauth code received", "oauth pending secret"].includes(status);
    if (["facebook", "instagram"].includes(account.platform) && !account.providerAccountId && account.handle) {
      account.handle = "";
      changed = true;
    }
    const repairProvider = account.oauthProvider || account.provider || "";
    if (repairProvider && repairConnectedOAuthAccount(account, repairProvider)) {
      changed = true;
      continue;
    }
    if (isRealConnectedAccount(account) || pendingOauth || status === "not connected") continue;
    if (isConnectedStatus(account.status) || ["logged in", "meta login connected"].includes(status)) {
      account.status = "not connected";
      account.connectedAt = null;
      account.connectionEvidence = "removed: no provider token or provider account id was stored";
      changed = true;
    }
  }
  return changed;
}

function hydrateMetaLoginStatus(model) {
  const accounts = model.connectedAccounts || [];
  const metaUser = accounts.find(account => account.platform === "meta" && isRealConnectedAccount(account));
  if (!metaUser) return false;
  let changed = false;
  model.integrations = model.integrations || {};
  if (model.integrations.meta !== `Logged in as ${metaUser.name || metaUser.handle || "Meta user"}`) {
    model.integrations.meta = `Logged in as ${metaUser.name || metaUser.handle || "Meta user"}`;
    changed = true;
  }
  for (const platform of ["facebook", "instagram"]) {
    const account = accounts.find(item => item.platform === platform);
    const isDirectInstagramAccount = platform === "instagram" && account?.oauthProvider === "instagram" && isRealConnectedAccount(account);
    if (isDirectInstagramAccount) continue;
    if (account && account.oauthProvider !== "meta") {
      account.oauthProvider = "meta";
      account.scopes = metaUser.scopes || metaScopes;
      account.loginNote = platform === "facebook"
        ? "Meta login is connected, but no Facebook Page asset was returned. This account is not connected until Meta returns a Page id and token."
        : "Meta login is connected, but no Instagram professional asset was returned. This account is not connected until Meta returns an IG id and token.";
      changed = true;
    }
  }
  return changed;
}

async function saveModel(model) {
  try {
    return supabaseEnabled ? await supabaseSaveModel(model) : await localSaveModel(model);
  } catch (error) {
    lastPersistence = { driver: "supabase", ok: false, message: error.message };
    return localSaveModel(model);
  }
}

async function saveModelForUser(model, user = null) {
  if (user?.id && supabaseEnabled) {
    const workspaceModel = await workspaceModelForRegistryWrite(model, user);
    await mirrorWorkspaceModel(workspaceModel, user);
    await saveModel(serverRegistryModel(model));
    return workspaceModel;
  }
  const saved = await saveModel(model);
  if (user?.id) await mirrorWorkspaceModel(saved, user);
  return saved;
}

async function confirmPersistedProviderAccount(user, platform, providerAccountId, sharedModel = null, fallbackAccount = null) {
  if (!user?.id || !supabaseEnabled) return { ok: true, skipped: true, reason: "Supabase workspace persistence is not active." };
  try {
    const workspaceId = workspaceModelIdForUser(user);
    const ownerUserId = supabaseUserIdForUser(user);
    const expectedProviderAccountId = String(providerAccountId || "");
    let accountRow = null;
    let tokenRow = null;

    // Verify the normalized rows written by mirrorWorkspaceModel directly. Reloading the
    // larger workspace snapshot here can briefly return its previous version after OAuth.
    for (const delayMs of [0, 100, 250, 500, 1000, 2000]) {
      if (delayMs) await sleep(delayMs);
      let accountRows = await optionalSupabaseRequest(
        `/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.${encodeURIComponent(platform)}&provider_account_id=eq.${encodeURIComponent(expectedProviderAccountId)}&select=id,provider,platform,provider_account_id,display_name,handle,status,scopes,connected_at,public_profile&limit=1`
      );
      if (!Array.isArray(accountRows) || !accountRows[0]?.id) {
        accountRows = await optionalSupabaseRequest(
          `/connected_accounts?user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.${encodeURIComponent(platform)}&provider_account_id=eq.${encodeURIComponent(expectedProviderAccountId)}&select=id,provider,platform,provider_account_id,display_name,handle,status,scopes,connected_at,public_profile&limit=1`
        );
      }
      accountRow = Array.isArray(accountRows) ? accountRows[0] || null : null;
      if (!accountRow?.id) continue;
      const tokenRows = await optionalSupabaseRequest(
        `/provider_tokens?connected_account_id=eq.${encodeURIComponent(accountRow.id)}&token_kind=eq.oauth&select=connected_account_id,encrypted_token,token_type,scopes,expires_at,refresh_expires_at&limit=1`
      );
      tokenRow = Array.isArray(tokenRows) ? tokenRows[0] || null : null;
      if (tokenRow?.encrypted_token) break;
    }

    const tokenStored = Boolean(accountRow && tokenRow?.encrypted_token);
    const identityStored = Boolean(accountRow?.provider_account_id && String(accountRow.provider_account_id) === expectedProviderAccountId);
    const account = accountRow ? {
      ...(accountRow.public_profile && typeof accountRow.public_profile === "object" ? accountRow.public_profile : {}),
      platform: accountRow.platform,
      oauthProvider: accountRow.provider,
      providerAccountId: accountRow.provider_account_id,
      name: accountRow.display_name,
      displayName: accountRow.display_name,
      handle: accountRow.handle || "",
      status: accountRow.status,
      scopes: Array.isArray(tokenRow?.scopes) && tokenRow.scopes.length ? tokenRow.scopes : accountRow.scopes || [],
      tokenType: tokenRow?.token_type || null,
      tokenExpiresAt: tokenRow?.expires_at || null,
      refreshTokenExpiresAt: tokenRow?.refresh_expires_at || null,
      tokenStored
    } : null;
    const fallbackState = providerAccountConnectionState(fallbackAccount || {});
    const pending = Boolean(!accountRow && fallbackState.identityVerified && fallbackState.tokenStored);
    return {
      ok: Boolean(accountRow && tokenStored && identityStored),
      pending,
      skipped: false,
      account: account ? publicAccount(account) : null,
      tokenStored,
      identityStored,
      reason: account
        ? tokenStored && identityStored
          ? "Provider identity and encrypted token were reloaded from the user workspace."
          : "The provider account reloaded without complete token and identity evidence."
        : pending
          ? "The provider verified the account and token; normalized storage verification is still pending."
          : "The provider account was not found after the workspace save."
    };
  } catch (error) {
    const fallbackState = providerAccountConnectionState(fallbackAccount || {});
    const pending = Boolean(fallbackState.identityVerified && fallbackState.tokenStored);
    return {
      ok: false,
      pending,
      skipped: false,
      account: fallbackAccount ? publicAccount(fallbackAccount) : null,
      tokenStored: fallbackState.tokenStored,
      identityStored: fallbackState.identityVerified,
      reason: pending
        ? `The provider verified the account and token; normalized storage verification is still pending: ${error.message}`
        : error.message
    };
  }
}

function responseHeaders(contentType, options = {}) {
  const scriptSrc = options.scriptNonce ? `script-src 'self' 'nonce-${options.scriptNonce}'` : "script-src 'self'";
  return {
    "Content-Type": contentType,
    "Cache-Control": "no-store",
    "Access-Control-Allow-Origin": corsOrigin,
    "Access-Control-Allow-Methods": "GET,POST,OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type, Authorization",
    "X-Content-Type-Options": "nosniff",
    "Referrer-Policy": "strict-origin-when-cross-origin",
    "Permissions-Policy": "camera=(self), microphone=(self), geolocation=()",
    "Content-Security-Policy": [
      "default-src 'self'",
      scriptSrc,
      "style-src 'self' 'unsafe-inline'",
      "img-src 'self' data: blob: https:",
      "media-src 'self' data: blob: https:",
      "connect-src 'self' https:",
      "frame-ancestors 'none'",
      "base-uri 'self'",
      "form-action 'self' https://checkout.stripe.com"
    ].join("; ")
  };
}

function json(res, status, value) {
  const body = JSON.stringify(value, null, 2);
  res.writeHead(status, responseHeaders("application/json; charset=utf-8"));
  res.end(body);
}

function setCookie(res, value) {
  if (typeof res.setHeader === "function") res.setHeader("Set-Cookie", value);
}

function sessionCookieValue(token = "", expiresAt = "") {
  const secure = runtimeMode === "vercel" ? "; Secure" : "";
  const maxAgeSeconds = expiresAt && Date.parse(expiresAt) > Date.now()
    ? Math.max(60, Math.floor((Date.parse(expiresAt) - Date.now()) / 1000))
    : 60 * 60 * 24 * 30;
  return `sc_session=${encodeURIComponent(token)}; Path=/; Max-Age=${maxAgeSeconds}; SameSite=Lax; HttpOnly${secure}`;
}

function expiredSessionCookieValue() {
  const secure = runtimeMode === "vercel" ? "; Secure" : "";
  return `sc_session=; Path=/; Max-Age=0; SameSite=Lax; HttpOnly${secure}`;
}

function refreshSessionCookieIfNeeded(res, session) {
  if (session?.refreshed && session.token && session.device?.expiresAt) {
    setCookie(res, sessionCookieValue(session.token, session.device.expiresAt));
  }
}

const externalSignedPostPaths = new Set([
  "/api/discord/interactions",
  "/api/discord/webhook-events",
  "/api/meta/deauthorize",
  "/api/meta/data-deletion",
  "/api/meta/webhook",
  "/api/patreon/webhook",
  "/api/linkedin/webhook",
  "/api/billing/webhook"
]);

function allowedWriteOrigins(req) {
  const forwardedProto = String(req.headers["x-forwarded-proto"] || "").split(",")[0].trim();
  const requestProto = forwardedProto || (runtimeMode === "vercel" ? "https" : "http");
  const requestHost = String(req.headers["x-forwarded-host"] || req.headers.host || "").split(",")[0].trim();
  return new Set([
    corsOrigin,
    new URL(brandHomeUrl).origin,
    requestHost ? `${requestProto}://${requestHost}` : ""
  ].filter(Boolean));
}

function sameOriginWriteAllowed(req, url) {
  if (!["POST", "PUT", "PATCH", "DELETE"].includes(req.method || "")) return true;
  if (externalSignedPostPaths.has(url.pathname)) return true;
  if (runtimeMode !== "vercel") return true;
  const allowed = allowedWriteOrigins(req);
  const origin = String(req.headers.origin || "");
  if (origin) return allowed.has(origin);
  const referer = String(req.headers.referer || req.headers.referrer || "");
  if (referer) {
    try {
      return allowed.has(new URL(referer).origin);
    } catch {
      return false;
    }
  }
  return false;
}

function text(res, status, body, contentType = "text/plain; charset=utf-8") {
  const isHtml = /^text\/html\b/i.test(contentType);
  const scriptNonce = isHtml ? crypto.randomBytes(16).toString("base64url") : "";
  const htmlBody = isHtml
    ? String(body).replace(/<script(?![^>]*\snonce=)/gi, `<script nonce="${scriptNonce}"`)
    : body;
  res.writeHead(status, responseHeaders(contentType, { scriptNonce }));
  res.end(htmlBody);
}

function escapeHtml(value) {
  return String(value ?? "").replace(/[&<>"']/g, char => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    "\"": "&quot;",
    "'": "&#39;"
  }[char]));
}

function binary(res, status, body, contentType) {
  const headers = responseHeaders(contentType);
  headers["Content-Length"] = String(body.length);
  if (typeof res.setHeader === "function" && typeof res.status === "function" && typeof res.send === "function") {
    for (const [key, value] of Object.entries(headers)) res.setHeader(key, value);
    return res.status(status).send(body);
  }
  res.writeHead(status, headers);
  res.end(body);
}

function publicMediaAssetUrl(fileName) {
  return `${brandHomeUrl}/media/social-cues-promo-pack/${encodeURIComponent(fileName)}`;
}

function publicMediaContentType(fileName) {
  const ext = path.extname(fileName).toLowerCase();
  if (ext === ".mp4") return "video/mp4";
  if (ext === ".png") return "image/png";
  if (ext === ".jpg" || ext === ".jpeg") return "image/jpeg";
  return "application/octet-stream";
}

function publicLaunchPromoAssets() {
  return launchPromoAssets.map(asset => ({
    ...asset,
    url: publicMediaAssetUrl(asset.fileName),
    metaPullReady: true,
    note: "Public HTTPS asset. Safe for Meta, TikTok, YouTube, X, and Threads pull-by-URL checks."
  }));
}

async function bodyJson(req) {
  let raw = "";
  let total = 0;
  for await (const chunk of req) {
    total += chunk.length;
    if (total > maxJsonBodyBytes) throw new Error(`Request body exceeds ${maxJsonBodyBytes} bytes.`);
    raw += chunk;
  }
  return raw ? JSON.parse(raw) : {};
}

async function bodyText(req) {
  let raw = "";
  let total = 0;
  for await (const chunk of req) {
    total += chunk.length;
    if (total > maxJsonBodyBytes) throw new Error(`Request body exceeds ${maxJsonBodyBytes} bytes.`);
    raw += chunk;
  }
  return raw;
}

function uid(prefix) {
  return `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2, 7)}`;
}

function normalizeEmail(value) {
  return String(value || "").trim().toLowerCase();
}

function normalizePassword(value) {
  return String(value || "");
}

function normalizePromoCode(value) {
  return String(value || "").trim().toUpperCase().replace(/\s+/g, "");
}

function promoCodeRecord(value) {
  const code = normalizePromoCode(value);
  if (!code) return null;
  return testPromoCodes.find(item => item.code === code) || null;
}

const terminalPromoClaimStatuses = new Set(["released", "revoked", "expired"]);

function promoClaims(model) {
  model.authPromoClaims = Array.isArray(model.authPromoClaims) ? model.authPromoClaims : [];
  return model.authPromoClaims;
}

function activePromoUserClaim(model, code) {
  const normalized = normalizePromoCode(code);
  if (!normalized) return null;
  return (model.authUsers || []).find(user => normalizePromoCode(user.entitlement?.promoCode) === normalized && publicEntitlement(user).active) || null;
}

function activePromoLedgerClaim(model, code) {
  const normalized = normalizePromoCode(code);
  if (!normalized) return null;
  return (model.authPromoClaims || []).find(item => {
    const status = String(item.status || "pending").toLowerCase();
    return normalizePromoCode(item.code) === normalized && item.active !== false && !terminalPromoClaimStatuses.has(status);
  }) || null;
}

function promoLedgerClaimForEmail(model, email) {
  const normalizedEmail = normalizeEmail(email);
  if (!normalizedEmail) return null;
  return (model.authPromoClaims || []).find(item => {
    const status = String(item.status || "pending").toLowerCase();
    return normalizeEmail(item.email) === normalizedEmail && item.active !== false && !terminalPromoClaimStatuses.has(status);
  }) || null;
}

function validatePromoClaim(model, promo, email) {
  if (!promo) return { ok: true };
  const normalizedEmail = normalizeEmail(email);
  if (promo.email && promo.email !== normalizedEmail) {
    return { ok: false, status: 403, error: "That Social Cues promo code is assigned to a different email address." };
  }
  const userClaim = activePromoUserClaim(model, promo.code);
  if (userClaim && normalizeEmail(userClaim.email) !== normalizedEmail) {
    return { ok: false, status: 409, error: "That Social Cues promo code has already been assigned to a tester." };
  }
  const ledgerClaim = activePromoLedgerClaim(model, promo.code);
  if (ledgerClaim && normalizeEmail(ledgerClaim.email) !== normalizedEmail) {
    return { ok: false, status: 409, error: "That Social Cues promo code has already been assigned to a tester." };
  }
  return { ok: true };
}

function recordPromoClaim(model, promo, email, status = "pending", user = null) {
  if (!promo || !email) return null;
  const claims = promoClaims(model);
  const normalizedEmail = normalizeEmail(email);
  const code = normalizePromoCode(promo.code);
  let claim = claims.find(item => normalizePromoCode(item.code) === code && normalizeEmail(item.email) === normalizedEmail);
  if (!claim) {
    claim = {
      id: uid("promo-claim"),
      code,
      label: promo.label || "",
      email: normalizedEmail,
      claimedAt: new Date().toISOString()
    };
    claims.push(claim);
  }
  claim.status = status;
  claim.active = true;
  claim.userId = user?.id || claim.userId || "";
  claim.workspaceId = user ? workspaceIdForUser(user) : claim.workspaceId || "";
  claim.updatedAt = new Date().toISOString();
  return claim;
}

function envEmailList(names = []) {
  return names
    .flatMap(name => String(process.env[name] || "").split(/[,\s]+/))
    .map(normalizeEmail)
    .filter(Boolean);
}

function signupOwnerEmails() {
  return [...new Set([
    supportEmail,
    "barton.cory.m@gmail.com",
    ...envEmailList([
      "ACCOUNT_SIGNUP_OWNER_EMAILS",
      "SIGNUP_OWNER_EMAILS",
      "OWNER_EMAILS",
      "ADMIN_EMAILS",
      "OWNER_EMAIL",
      "ADMIN_EMAIL"
    ])
  ].map(normalizeEmail).filter(Boolean))];
}

function emailMatchesOwnerAddress(email, ownerEmail) {
  const normalized = normalizeEmail(email);
  const owner = normalizeEmail(ownerEmail);
  if (!normalized || !owner) return false;
  if (normalized === owner) return true;
  const [local, domain] = normalized.split("@");
  const [ownerLocal, ownerDomain] = owner.split("@");
  return Boolean(local && domain && ownerLocal && ownerDomain && domain === ownerDomain && local.startsWith(`${ownerLocal}+`));
}

function isSignupOwnerEmail(email) {
  return signupOwnerEmails().some(ownerEmail => emailMatchesOwnerAddress(email, ownerEmail));
}

function signupGateSummary() {
  return {
    mode: "invite-only",
    allowed: "Owner allowlist or active Social Cues promo code",
    ownerEmailCount: signupOwnerEmails().length,
    activePromoCodeCount: testPromoCodes.filter(item => item.active !== false).length
  };
}

function addMonths(date, months) {
  const next = new Date(date);
  next.setMonth(next.getMonth() + months);
  return next;
}

function addDays(date, days) {
  const next = new Date(date);
  next.setDate(next.getDate() + days);
  return next;
}

function publicEntitlement(user) {
  const entitlement = user?.entitlement || {};
  const expiresAt = entitlement.expiresAt || null;
  const expired = expiresAt ? Date.parse(expiresAt) <= Date.now() : false;
  const active = !expired && entitlement.active !== false && Boolean(entitlement.access && entitlement.access !== "unpaid");
  return {
    access: entitlement.access || "unpaid",
    source: entitlement.source || "none",
    promoCode: entitlement.promoCode || "",
    active,
    grantedAt: entitlement.grantedAt || null,
    expiresAt,
    billingStartsAfter: entitlement.billingStartsAfter || expiresAt,
    selectedPlan: entitlement.selectedPlan || "",
    tier: entitlement.tier || entitlement.access || "",
    subscriptionPaid: Boolean(active && (entitlement.subscriptionPaid || entitlement.fullAccess)),
    appFeePaid: Boolean(active && (entitlement.appFeePaid || entitlement.fullAccess)),
    paymentStatus: entitlement.paymentStatus || (entitlement.active ? "active" : "unpaid"),
    alphaHonorDiscountPercent: Number(entitlement.alphaHonorDiscountPercent || 0),
    deactivatesBeforeAlpha: Boolean(entitlement.deactivatesBeforeAlpha),
    memberOnly: Boolean(entitlement.memberOnly)
  };
}

function resolvedAppUserRole(user = null) {
  if (!user) return "Guest";
  const entitlement = publicEntitlement(user);
  if (entitlement.memberOnly) return "Member";
  if (isSignupOwnerEmail(user.email) || entitlement.source === "owner-allowlist" || entitlement.tier === "owner") return "Owner";
  if (entitlement.source === "promo-code") return "Alpha tester";
  if (entitlement.source === "stripe") return "Customer";
  return "Member";
}

function publicAuthAlert(alert = {}) {
  return {
    id: alert.id || uid("auth-alert"),
    type: alert.type || "account",
    status: alert.status || "info",
    label: alert.label || "Account event",
    detail: alert.detail || "",
    createdAt: alert.createdAt || new Date().toISOString(),
    deviceId: alert.deviceId || "",
    deviceName: alert.deviceName || "",
    actionRequired: Boolean(alert.actionRequired)
  };
}

function authAlertsForUser(model, userId = "") {
  const user = (model?.authUsers || []).find(item => String(item.id || "") === String(userId || ""));
  const alerts = Array.isArray(user?.authAlerts) ? user.authAlerts : [];
  return alerts.map(publicAuthAlert);
}

function providerExpiryAlertsForUser(model, user = {}) {
  const now = Date.now();
  return (model.connectedAccounts || [])
    .filter(account => ownedByUser(account, user.id) && hasStoredToken(account) && account.tokenExpiresAt)
    .map(account => {
      const expiresAtMs = Date.parse(account.tokenExpiresAt);
      if (!Number.isFinite(expiresAtMs)) return null;
      const daysRemaining = Math.ceil((expiresAtMs - now) / (24 * 60 * 60 * 1000));
      if (daysRemaining > 14) return null;
      const expired = daysRemaining <= 0;
      const identity = account.handle || account.displayName || account.name || platformDisplayName(account.platform);
      return publicAuthAlert({
        id: `provider-expiry-${account.platform}-${account.providerAccountId || account.id}`,
        type: "provider-token",
        status: expired ? "error" : "warning",
        label: `${platformDisplayName(account.platform)} ${expired ? "needs reconnect" : "token expires soon"}`,
        detail: expired
          ? `${identity} can no longer be treated as connected. Reconnect it from Accounts.`
          : `${identity} expires in ${daysRemaining} day${daysRemaining === 1 ? "" : "s"}. Reconnect before scheduled work is due.`,
        actionRequired: true,
        createdAt: new Date().toISOString()
      });
    })
    .filter(Boolean)
    .sort((left, right) => Number(right.status === "error") - Number(left.status === "error"));
}

async function persistAuthAlertAudit(user = {}, alert = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId) return { ok: false, skipped: true };
  await optionalSupabaseRequest("/audit_logs", {
    method: "POST",
    headers: { Prefer: "return=minimal" },
    body: JSON.stringify([{
      workspace_id: workspaceId,
      user_id: ownerUserId,
      event_type: `auth.${alert.type || "event"}`,
      provider: "supabase",
      platform: "auth",
      target_id: alert.deviceId || "",
      metadata: {
        status: alert.status || "info",
        label: alert.label || "Account event",
        detail: alert.detail || "",
        deviceName: alert.deviceName || "",
        actionRequired: Boolean(alert.actionRequired)
      },
      created_at: alert.createdAt || new Date().toISOString()
    }])
  });
  return { ok: true };
}

async function enqueueNotificationOutbox(user = {}, notification = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId) return { ok: false, skipped: true };
  const channel = notification.channel || "in-app";
  const idempotencyKey = notification.idempotencyKey || `${notification.type || "notice"}:${notification.id || uid("notification")}:${channel}`;
  const rows = await optionalSupabaseRequest("/notification_outbox?on_conflict=workspace_id,idempotency_key", {
    method: "POST",
    headers: { Prefer: "resolution=ignore-duplicates,return=representation" },
    body: JSON.stringify([{
      workspace_id: workspaceId,
      user_id: ownerUserId,
      idempotency_key: idempotencyKey,
      type: notification.type || "notice",
      channel,
      target: notification.target || (channel === "email" ? normalizeEmail(user.email) : String(user.id)),
      status: "pending",
      payload: {
        label: notification.label || "Social Cues notice",
        detail: notification.detail || "",
        actionRequired: Boolean(notification.actionRequired),
        route: notification.route || "",
        actionLabel: notification.actionLabel || "Open Social Cues"
      },
      next_attempt_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    }])
  });
  return { ok: true, queued: Array.isArray(rows) ? rows.length > 0 : false, idempotencyKey };
}

async function notificationOutboxForUser(user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId) return [];
  const rows = await optionalSupabaseRequest(
    `/notification_outbox?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&select=id,type,channel,status,payload,attempts,next_attempt_at,last_error,sent_at,created_at&order=created_at.desc&limit=50`
  );
  return Array.isArray(rows) ? rows.map(row => ({
    id: row.id,
    type: row.type,
    channel: row.channel,
    status: row.status,
    label: row.payload?.label || "Social Cues notice",
    detail: row.payload?.detail || "",
    actionRequired: Boolean(row.payload?.actionRequired),
    route: row.payload?.route || "",
    actionLabel: row.payload?.actionLabel || "Open Social Cues",
    attempts: Number(row.attempts || 0),
    nextAttemptAt: row.next_attempt_at || null,
    lastError: row.last_error || "",
    sentAt: row.sent_at || null,
    createdAt: row.created_at
  })) : [];
}

function normalizePushSubscription(input = {}) {
  const endpoint = String(input.endpoint || "").trim();
  let parsedEndpoint;
  try {
    parsedEndpoint = new URL(endpoint);
  } catch {
    throw new Error("The browser push endpoint is invalid.");
  }
  if (parsedEndpoint.protocol !== "https:") throw new Error("The browser push endpoint must use HTTPS.");
  const p256dh = String(input.keys?.p256dh || "").trim();
  const auth = String(input.keys?.auth || "").trim();
  if (!p256dh || !auth) throw new Error("The browser push subscription is missing encryption keys.");
  if (endpoint.length > 4096 || p256dh.length > 2048 || auth.length > 1024) throw new Error("The browser push subscription is too large.");
  return { endpoint, expirationTime: Number.isFinite(Number(input.expirationTime)) ? Number(input.expirationTime) : null, keys: { p256dh, auth } };
}

async function pushStatusForUser(user = {}, deviceId = "") {
  const workspaceId = workspaceModelIdForUser(user);
  const userId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !isUuid(workspaceId) || !isUuid(userId)) {
    return { configured: webPushConfigured, enabled: false, subscriptions: 0, deviceEnabled: false };
  }
  const rows = await optionalSupabaseRequest(`/push_subscriptions?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(userId)}&status=eq.active&select=device_id,status,last_used_at,created_at`);
  const subscriptions = Array.isArray(rows) ? rows : [];
  return {
    configured: webPushConfigured,
    enabled: subscriptions.length > 0,
    subscriptions: subscriptions.length,
    deviceEnabled: Boolean(deviceId && subscriptions.some(row => row.device_id === deviceId)),
    publicKey: webPushConfigured ? vapidPublicKey : ""
  };
}

async function storePushSubscription(user = {}, deviceId = "", input = {}) {
  if (!webPushConfigured) throw new Error("Device notifications are not configured on the Social Cues server.");
  const workspaceId = workspaceModelIdForUser(user);
  const userId = supabaseUserIdForUser(user);
  if (!isUuid(workspaceId) || !isUuid(userId)) throw new Error("The workspace identity is incomplete.");
  const normalizedDeviceId = String(deviceId || "").trim().slice(0, 300);
  if (!normalizedDeviceId) throw new Error("This remembered device is missing its device id.");
  const subscription = normalizePushSubscription(input);
  const endpointHash = hashSecret(subscription.endpoint);
  const now = new Date().toISOString();
  await optionalSupabaseRequest("/push_subscriptions?on_conflict=user_id,device_id,endpoint_hash", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify([{
      workspace_id: workspaceId,
      user_id: userId,
      device_id: normalizedDeviceId,
      endpoint_hash: endpointHash,
      encrypted_subscription: encryptedToken(JSON.stringify(subscription)),
      status: "active",
      last_error: null,
      updated_at: now
    }])
  });
  return pushStatusForUser(user, normalizedDeviceId);
}

async function revokePushSubscriptions(user = {}, deviceId = "") {
  const workspaceId = workspaceModelIdForUser(user);
  const userId = supabaseUserIdForUser(user);
  const normalizedDeviceId = String(deviceId || "").trim().slice(0, 300);
  if (!isUuid(workspaceId) || !isUuid(userId) || !normalizedDeviceId) throw new Error("The device notification identity is incomplete.");
  const now = new Date().toISOString();
  await optionalSupabaseRequest(`/push_subscriptions?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(userId)}&device_id=eq.${encodeURIComponent(normalizedDeviceId)}&status=eq.active`, {
    method: "PATCH",
    headers: { Prefer: "return=minimal" },
    body: JSON.stringify({ status: "revoked", updated_at: now })
  });
  return pushStatusForUser(user, normalizedDeviceId);
}

class WorkerJobError extends Error {
  constructor(message, options = {}) {
    super(message);
    this.name = "WorkerJobError";
    this.retryable = options.retryable === true;
    this.blocked = options.blocked === true;
    this.retryAt = options.retryAt || null;
    this.result = options.result || {};
  }
}

function workerRequestAuthorized(req) {
  if (!workerSecret) return runtimeMode !== "vercel";
  const presented = String(req?.headers?.authorization || "").replace(/^Bearer\s+/i, "").trim();
  if (!presented) return false;
  const expectedBuffer = Buffer.from(workerSecret);
  const presentedBuffer = Buffer.from(presented);
  return expectedBuffer.length === presentedBuffer.length && crypto.timingSafeEqual(expectedBuffer, presentedBuffer);
}

function publicWorkerJob(row = {}) {
  return {
    id: row.id,
    kind: row.kind,
    status: row.status,
    priority: Number(row.priority || 0),
    runAt: row.run_at || row.runAt || null,
    attempts: Number(row.attempts || 0),
    maxAttempts: Number(row.max_attempts || row.maxAttempts || 0),
    lastError: row.last_error || row.lastError || "",
    estimatedCostMicrousd: Number(row.estimated_cost_microusd || 0),
    actualCostMicrousd: Number(row.actual_cost_microusd || 0),
    createdAt: row.created_at || row.createdAt || null,
    updatedAt: row.updated_at || row.updatedAt || null,
    completedAt: row.completed_at || row.completedAt || null
  };
}

async function workerUserForJob(registry = {}, job = {}) {
  const payload = job.payload || {};
  const userId = String(job.user_id || payload.userId || "");
  const workspaceId = String(job.workspace_id || payload.workspaceId || "");
  const registered = (registry.authUsers || []).find(user =>
    String(supabaseUserIdForUser(user) || user.id || "") === userId
    || String(workspaceModelIdForUser(user) || workspaceIdForUser(user) || "") === workspaceId
  ) || null;
  if (registered) return registered;
  if (!supabaseEnabled || !isUuid(userId) || !isUuid(workspaceId)) return null;
  const profileRows = await optionalSupabaseRequest(`/profiles?id=eq.${encodeURIComponent(userId)}&workspace_id=eq.${encodeURIComponent(workspaceId)}&select=id,workspace_id,display_name,email,role,created_at&limit=1`);
  const profile = Array.isArray(profileRows) ? profileRows[0] || null : null;
  if (!profile) return null;
  const user = {
    id: userId,
    supabaseUserId: userId,
    workspaceId,
    name: profile.display_name || "Social Cues User",
    email: normalizeEmail(profile.email),
    role: profile.role || "Member",
    authProvider: "supabase",
    createdAt: profile.created_at || null
  };
  await hydrateNormalizedSupabaseAccountState(registry, user);
  registry.authUsers = Array.isArray(registry.authUsers) ? registry.authUsers : [];
  registry.authUsers.push(user);
  return user;
}

function workerRetryAt(job = {}, minimumSeconds = 30) {
  const attempt = Math.max(1, Number(job.attempts || 1));
  const seconds = Math.min(3600, Math.max(minimumSeconds, 30 * (2 ** Math.min(attempt - 1, 7))));
  return new Date(Date.now() + seconds * 1000).toISOString();
}

async function enqueueWorkerJobs(rows = []) {
  if (!supabaseEnabled || !rows.length) return [];
  const normalized = rows
    .filter(row => isUuid(row.workspace_id) && isUuid(row.user_id) && row.kind && row.idempotency_key)
    .map(row => ({
      workspace_id: row.workspace_id,
      user_id: row.user_id,
      kind: row.kind,
      status: "queued",
      idempotency_key: String(row.idempotency_key).slice(0, 500),
      priority: Math.max(0, Math.min(Number(row.priority ?? 50), 100)),
      payload: row.payload || {},
      run_at: row.run_at || new Date().toISOString(),
      max_attempts: Math.max(1, Math.min(Number(row.max_attempts || 5), 20)),
      estimated_cost_microusd: Math.max(0, Number(row.estimated_cost_microusd || 0)),
      updated_at: new Date().toISOString()
    }));
  if (!normalized.length) return [];
  const result = await optionalSupabaseRequest("/worker_jobs?on_conflict=workspace_id,idempotency_key", {
    method: "POST",
    headers: { Prefer: "resolution=ignore-duplicates,return=representation" },
    body: JSON.stringify(normalized)
  });
  return Array.isArray(result) ? result : [];
}

async function reconcileTerminalTokenRefreshJobs() {
  if (!supabaseEnabled) return { ready: false, retired: 0, accountsDisconnected: 0 };
  const rows = await optionalSupabaseRequest("/worker_jobs?kind=eq.token_refresh&status=in.(blocked,dead)&select=id,workspace_id,user_id,payload,completed_at&order=completed_at.asc&limit=200");
  if (!Array.isArray(rows) || !rows.length) return { ready: true, retired: 0, accountsDisconnected: 0 };
  const accountIds = [...new Set(rows.map(row => row.payload?.connectedAccountId).filter(isUuid))];
  const [accountRows, tokenRows] = accountIds.length ? await Promise.all([
    optionalSupabaseRequest(`/connected_accounts?id=in.(${accountIds.map(encodeURIComponent).join(",")})&select=id,status`),
    optionalSupabaseRequest(`/provider_tokens?connected_account_id=in.(${accountIds.map(encodeURIComponent).join(",")})&token_kind=eq.oauth&select=connected_account_id,expires_at`)
  ]) : [[], []];
  const accountsById = new Map((Array.isArray(accountRows) ? accountRows : []).map(row => [row.id, row]));
  const tokensByAccountId = new Map((Array.isArray(tokenRows) ? tokenRows : []).map(row => [row.connected_account_id, row]));
  const disconnectedAccountIds = new Set();
  const retiredJobIds = [];
  for (const row of rows) {
    const connectedAccountId = row.payload?.connectedAccountId;
    if (!isUuid(connectedAccountId)) continue;
    const currentExpiry = Date.parse(tokensByAccountId.get(connectedAccountId)?.expires_at || "");
    const attemptedExpiry = Date.parse(row.payload?.expiresAt || "");
    const superseded = Number.isFinite(currentExpiry) && (!Number.isFinite(attemptedExpiry) || currentExpiry > attemptedExpiry + 1000);
    if (!superseded && accountsById.get(connectedAccountId)?.status === "connected") disconnectedAccountIds.add(connectedAccountId);
    retiredJobIds.push(row.id);
  }
  const now = new Date().toISOString();
  if (disconnectedAccountIds.size) {
    await optionalSupabaseRequest(`/connected_accounts?id=in.(${[...disconnectedAccountIds].map(encodeURIComponent).join(",")})`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({ status: "not_connected", connected_at: null, updated_at: now })
    });
  }
  if (retiredJobIds.length) {
    await optionalSupabaseRequest(`/worker_jobs?id=in.(${retiredJobIds.map(encodeURIComponent).join(",")})&kind=eq.token_refresh&status=in.(blocked,dead)`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({
        status: "cancelled",
        result: { reason: "Terminal refresh state reconciled after disconnect or newer credential evidence." },
        last_error: null,
        completed_at: now,
        updated_at: now
      })
    });
  }
  return { ready: true, retired: retiredJobIds.length, accountsDisconnected: disconnectedAccountIds.size };
}

async function discoverWorkerJobs() {
  if (!supabaseEnabled) return { ready: false, enqueued: 0, reasons: ["Supabase is not configured."] };
  const reconciliation = await reconcileTerminalTokenRefreshJobs();
  const now = new Date().toISOString();
  const refreshBefore = new Date(Date.now() + tokenRefreshLeadMinutes * 60 * 1000).toISOString();
  const [scheduledRows, notificationRows, tokenRows, workspaceRows, entitlementRows] = await Promise.all([
    automaticPublishingEnabled
      ? optionalSupabaseRequest(`/scheduled_posts?status=in.(queued,retrying)&scheduled_for=lte.${encodeURIComponent(now)}&select=id,workspace_id,external_key,platform,status,scheduled_for,idempotency_key,retry_count,max_attempts,next_retry_at&order=scheduled_for.asc&limit=100`)
      : Promise.resolve([]),
    optionalSupabaseRequest(`/notification_outbox?status=in.(pending,retrying)&next_attempt_at=lte.${encodeURIComponent(now)}&select=id,workspace_id,user_id,idempotency_key,channel,next_attempt_at,attempts&order=next_attempt_at.asc&limit=100`),
    optionalSupabaseRequest(`/provider_tokens?expires_at=not.is.null&expires_at=lte.${encodeURIComponent(refreshBefore)}&encrypted_refresh_token=not.is.null&select=id,connected_account_id,workspace_id,user_id,provider,expires_at,refresh_expires_at&order=expires_at.asc&limit=100`),
    optionalSupabaseRequest("/workspace_models?select=workspace_id,owner_user_id,updated_at&order=updated_at.desc&limit=100"),
    optionalSupabaseRequest("/billing_entitlements?status=in.(active,trialing,paid,promo-paid,owner-verified)&select=workspace_id,user_id,status&limit=500")
  ]);

  const tokenAccountIds = (Array.isArray(tokenRows) ? tokenRows : []).map(row => row.connected_account_id).filter(isUuid);
  const connectedRows = tokenAccountIds.length
    ? await optionalSupabaseRequest(`/connected_accounts?id=in.(${tokenAccountIds.join(",")})&select=id,provider,platform,provider_account_id,status`)
    : [];
  const connectedById = new Map((Array.isArray(connectedRows) ? connectedRows : []).map(row => [row.id, row]));
  const scheduledWorkspaceIds = [...new Set((Array.isArray(scheduledRows) ? scheduledRows : []).map(row => row.workspace_id).filter(isUuid))];
  const scheduledProfiles = scheduledWorkspaceIds.length
    ? await optionalSupabaseRequest(`/profiles?workspace_id=in.(${scheduledWorkspaceIds.join(",")})&select=id,workspace_id,created_at&order=created_at.asc`)
    : [];
  const ownerByWorkspace = new Map();
  for (const profile of Array.isArray(scheduledProfiles) ? scheduledProfiles : []) {
    if (!ownerByWorkspace.has(profile.workspace_id)) ownerByWorkspace.set(profile.workspace_id, profile.id);
  }
  const supportedRefreshPlatforms = new Set(["x", "etsy", "tiktok", "twitch", "discord", "youtube"]);
  const jobs = [];
  const hourKey = now.slice(0, 13).replace(/[-T:]/g, "");
  const dayKey = now.slice(0, 10).replace(/-/g, "");
  const activeWorkspaceOwners = new Set((Array.isArray(entitlementRows) ? entitlementRows : []).map(row => `${row.workspace_id}:${row.user_id}`));

  for (const row of Array.isArray(workspaceRows) ? workspaceRows : []) {
    if (!isUuid(row.workspace_id) || !isUuid(row.owner_user_id)) continue;
    if (!activeWorkspaceOwners.has(`${row.workspace_id}:${row.owner_user_id}`)) continue;
    jobs.push({
      workspace_id: row.workspace_id,
      user_id: row.owner_user_id,
      kind: "analytics_collection",
      idempotency_key: `analytics-collection:${hourKey}`,
      priority: 30,
      run_at: now,
      max_attempts: 3,
      payload: { source: "scheduled-hourly", hourKey }
    });
    jobs.push({
      workspace_id: row.workspace_id,
      user_id: row.owner_user_id,
      kind: "audience_brief",
      idempotency_key: `audience-brief:${dayKey}`,
      priority: 20,
      run_at: now,
      max_attempts: 3,
      payload: { source: "scheduled-daily", briefDate: now.slice(0, 10) }
    });
  }

  for (const row of Array.isArray(scheduledRows) ? scheduledRows : []) {
    if (!isUuid(row.workspace_id)) continue;
    const userId = ownerByWorkspace.get(row.workspace_id);
    if (!isUuid(userId)) continue;
    jobs.push({
      workspace_id: row.workspace_id,
      user_id: userId,
      kind: "scheduled_publish",
      idempotency_key: `publish:${row.idempotency_key || row.external_key || row.id}`,
      priority: 80,
      run_at: row.next_retry_at || row.scheduled_for || now,
      max_attempts: Number(row.max_attempts || 5),
      payload: {
        scheduledPostId: row.id,
        externalKey: row.external_key,
        variantId: String(row.external_key || "").replace(/^variant-/, ""),
        platform: row.platform,
        scheduledFor: row.scheduled_for
      }
    });
  }

  for (const row of Array.isArray(notificationRows) ? notificationRows : []) {
    jobs.push({
      workspace_id: row.workspace_id,
      user_id: row.user_id,
      kind: "notification_delivery",
      idempotency_key: `notification:${row.idempotency_key || row.id}`,
      priority: row.channel === "email" ? 70 : 55,
      run_at: row.next_attempt_at || now,
      max_attempts: 6,
      payload: { notificationId: row.id }
    });
  }

  for (const row of Array.isArray(tokenRows) ? tokenRows : []) {
    const connected = connectedById.get(row.connected_account_id);
    const platform = connected?.platform || row.provider;
    if (!supportedRefreshPlatforms.has(platform)) continue;
    if (connected && String(connected.status || "").replace(/[\s-]+/g, "_").toLowerCase() !== "connected") continue;
    const platformLeadMinutes = Math.min(tokenRefreshLeadMinutes, tokenRefreshLeadByPlatformMinutes[platform] || 15);
    const expiresAt = Date.parse(row.expires_at || "");
    if (Number.isFinite(expiresAt) && expiresAt > Date.now() + platformLeadMinutes * 60 * 1000) continue;
    jobs.push({
      workspace_id: row.workspace_id,
      user_id: row.user_id,
      kind: "token_refresh",
      idempotency_key: `token-refresh:${row.connected_account_id}:${row.expires_at}`,
      priority: 90,
      run_at: now,
      max_attempts: 4,
      payload: {
        connectedAccountId: row.connected_account_id,
        platform,
        provider: connected?.provider || row.provider,
        providerAccountId: connected?.provider_account_id || "",
        expiresAt: row.expires_at,
        refreshExpiresAt: row.refresh_expires_at
      }
    });
  }

  const enqueued = await enqueueWorkerJobs(jobs);
  return {
    ready: true,
    reconciliation,
    discovered: jobs.length,
    enqueued: enqueued.length,
    byKind: jobs.reduce((summary, job) => ({ ...summary, [job.kind]: (summary[job.kind] || 0) + 1 }), {})
  };
}

async function claimWorkerJobs(workerId, limit = workerBatchSize) {
  const rows = await optionalSupabaseRequest("/rpc/social_cues_claim_worker_jobs", {
    method: "POST",
    body: JSON.stringify({
      p_worker_id: workerId,
      p_limit: limit,
      p_lease_seconds: workerLeaseSeconds,
      p_kinds: ["scheduled_publish", "provider_publish_status", "token_refresh", "notification_delivery", "analytics_collection", "audience_brief"]
    })
  });
  return Array.isArray(rows) ? rows : [];
}

async function heartbeatWorkerJob(jobId, workerId) {
  return optionalSupabaseRequest("/rpc/social_cues_heartbeat_worker_job", {
    method: "POST",
    body: JSON.stringify({ p_job_id: jobId, p_worker_id: workerId, p_lease_seconds: workerLeaseSeconds })
  });
}

async function finishWorkerJob(job, workerId, status, options = {}) {
  const rows = await optionalSupabaseRequest("/rpc/social_cues_finish_worker_job", {
    method: "POST",
    body: JSON.stringify({
      p_job_id: job.id,
      p_worker_id: workerId,
      p_status: status,
      p_result: options.result || {},
      p_error: options.error || null,
      p_run_at: options.runAt || null,
      p_actual_cost_microusd: Math.max(0, Number(options.actualCostMicrousd || 0))
    })
  });
  return Array.isArray(rows) ? rows[0] || null : null;
}

function escapeNotificationHtml(value = "") {
  return String(value).replace(/[&<>"']/g, character => ({
    "&": "&amp;", "<": "&lt;", ">": "&gt;", "\"": "&quot;", "'": "&#39;"
  })[character]);
}

async function processNotificationWorkerJob(job) {
  const notificationId = job.payload?.notificationId;
  const rows = await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notificationId)}&select=id,workspace_id,user_id,idempotency_key,type,channel,target,status,payload,attempts,next_attempt_at,sent_at,created_at&limit=1`);
  const notice = Array.isArray(rows) ? rows[0] || null : null;
  if (!notice) return { missing: true, message: "Notification was removed before delivery." };
  if (notice.status === "sent") return { duplicateSuppressed: true, sentAt: notice.sent_at };

  await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
    method: "PATCH",
    headers: { Prefer: "return=minimal" },
    body: JSON.stringify({ status: "processing", attempts: Number(notice.attempts || 0) + 1, updated_at: new Date().toISOString() })
  });

  if (notice.channel === "in-app") {
    const sentAt = new Date().toISOString();
    await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({ status: "sent", sent_at: sentAt, last_error: null, updated_at: sentAt })
    });
    return { channel: "in-app", sentAt };
  }

  if (notice.channel === "push") {
    if (!webPushConfigured) throw new WorkerJobError("VAPID keys are required for device notification delivery.", { blocked: true });
    const subscriptionRows = await optionalSupabaseRequest(`/push_subscriptions?workspace_id=eq.${encodeURIComponent(notice.workspace_id)}&user_id=eq.${encodeURIComponent(notice.user_id)}&status=eq.active&select=id,device_id,encrypted_subscription`);
    const subscriptions = Array.isArray(subscriptionRows) ? subscriptionRows : [];
    if (!subscriptions.length) {
      const skippedAt = new Date().toISOString();
      await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
        method: "PATCH",
        headers: { Prefer: "return=minimal" },
        body: JSON.stringify({ status: "sent", sent_at: skippedAt, last_error: null, updated_at: skippedAt })
      });
      return { channel: "push", skipped: true, reason: "No active device subscription." };
    }
    const label = String(notice.payload?.label || "Social Cues notice").slice(0, 200);
    const detail = String(notice.payload?.detail || "").slice(0, 4000);
    const route = String(notice.payload?.route || "/app");
    const payload = JSON.stringify({ title: label, body: detail, url: route.startsWith("/") ? route : "/app", tag: String(notice.idempotency_key || notice.id).slice(0, 200) });
    let delivered = 0;
    let retryableFailure = null;
    for (const row of subscriptions) {
      try {
        const subscription = JSON.parse(decryptedToken(row.encrypted_subscription));
        await webpush.sendNotification(subscription, payload, { TTL: 3600, urgency: "normal" });
        delivered += 1;
        await optionalSupabaseRequest(`/push_subscriptions?id=eq.${encodeURIComponent(row.id)}`, {
          method: "PATCH",
          headers: { Prefer: "return=minimal" },
          body: JSON.stringify({ last_used_at: new Date().toISOString(), last_error: null, updated_at: new Date().toISOString() })
        });
      } catch (error) {
        const statusCode = Number(error.statusCode || error.status || 0);
        const expired = statusCode === 404 || statusCode === 410;
        const retryable = statusCode === 429 || statusCode >= 500 || !statusCode;
        await optionalSupabaseRequest(`/push_subscriptions?id=eq.${encodeURIComponent(row.id)}`, {
          method: "PATCH",
          headers: { Prefer: "return=minimal" },
          body: JSON.stringify({ status: expired ? "expired" : retryable ? "active" : "failed", last_error: String(error.message || "Push delivery failed.").slice(0, 1000), updated_at: new Date().toISOString() })
        }).catch(() => {});
        if (retryable) retryableFailure = error;
      }
    }
    if (!delivered && retryableFailure) {
      throw new WorkerJobError(retryableFailure.message || "Device notification delivery failed.", { retryable: true, retryAt: workerRetryAt(job) });
    }
    const sentAt = new Date().toISOString();
    await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({ status: "sent", sent_at: sentAt, last_error: null, updated_at: sentAt })
    });
    return { channel: "push", delivered, sentAt };
  }

  if (notice.channel !== "email") {
    throw new WorkerJobError(`Unsupported notification channel: ${notice.channel}`, { blocked: true });
  }
  const emailAgeMs = Date.now() - Date.parse(notice.created_at || "");
  if (Number.isFinite(emailAgeMs) && emailAgeMs > notificationEmailMaxAgeHours * 60 * 60 * 1000) {
    const expiredAt = new Date().toISOString();
    await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({ status: "expired", last_error: "Email delivery window elapsed before worker activation.", updated_at: expiredAt })
    });
    return { channel: "email", expired: true, expiredAt };
  }
  if (!resendApiKey) throw new WorkerJobError("RESEND_API_KEY is required for notification delivery.", { blocked: true });
  if (!notice.target || !String(notice.target).includes("@")) throw new WorkerJobError("Notification email target is missing.", { blocked: true });

  const label = String(notice.payload?.label || "Social Cues notice").slice(0, 200);
  const detail = String(notice.payload?.detail || "").slice(0, 4000);
  const route = String(notice.payload?.route || "");
  const actionLabel = String(notice.payload?.actionLabel || "Open Social Cues").slice(0, 80);
  const actionUrl = route.startsWith("/") ? `${publicAppUrl}${route}` : publicAppUrl;
  const response = await fetch("https://api.resend.com/emails", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${resendApiKey}`,
      "Content-Type": "application/json",
      "Idempotency-Key": String(notice.idempotency_key || notice.id).slice(0, 256)
    },
    body: JSON.stringify({
      from: `${smtpSenderName} <${smtpFrom}>`,
      to: [notice.target],
      subject: label,
      text: `${label}\n\n${detail}\n\n${actionLabel}: ${actionUrl}`,
      html: `<h1>${escapeNotificationHtml(label)}</h1><p>${escapeNotificationHtml(detail)}</p><p><a href="${escapeNotificationHtml(actionUrl)}">${escapeNotificationHtml(actionLabel)}</a></p>`
    })
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = body.message || body.error || `Resend email ${response.status}`;
    const retryable = response.status === 429 || response.status >= 500;
    await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({ status: retryable ? "retrying" : "failed", last_error: String(message).slice(0, 1000), next_attempt_at: workerRetryAt(job), updated_at: new Date().toISOString() })
    });
    throw new WorkerJobError(message, { retryable, blocked: !retryable });
  }
  const sentAt = new Date().toISOString();
  await optionalSupabaseRequest(`/notification_outbox?id=eq.${encodeURIComponent(notice.id)}`, {
    method: "PATCH",
    headers: { Prefer: "return=minimal" },
    body: JSON.stringify({ status: "sent", sent_at: sentAt, last_error: null, updated_at: sentAt })
  });
  return { channel: "email", sentAt, providerMessageId: body.id || null };
}

async function processTokenRefreshWorkerJob(job, registry) {
  const user = await workerUserForJob(registry, job);
  if (!user) throw new WorkerJobError("The token owner no longer exists.", { blocked: true });
  const model = await modelForSession({ user }, registry);
  const platform = job.payload?.platform;
  const providerAccountId = String(job.payload?.providerAccountId || "");
  const account = (model.connectedAccounts || []).find(item =>
    item.platform === platform
    && ownedByUser(item, user.id)
    && (!providerAccountId || String(item.providerAccountId || "") === providerAccountId)
  );
  if (!account) throw new WorkerJobError(`No ${platform} account matches this refresh job.`, { blocked: true });
  const expiresAt = Date.parse(account.tokenExpiresAt || "");
  const platformLeadMinutes = Math.min(tokenRefreshLeadMinutes, tokenRefreshLeadByPlatformMinutes[platform] || 15);
  const refreshBoundary = Date.now() + platformLeadMinutes * 60 * 1000;
  if (Number.isFinite(expiresAt) && expiresAt > refreshBoundary) {
    return { skipped: true, reason: "A newer token is already stored.", expiresAt: account.tokenExpiresAt };
  }
  const refreshers = {
    x: refreshXAccount,
    etsy: refreshEtsyAccount,
    patreon: refreshPatreonAccount,
    tiktok: refreshTikTokAccount,
    twitch: refreshTwitchAccount,
    discord: refreshDiscordAccount,
    youtube: refreshYouTubeAccount
  };
  const refresher = refreshers[platform];
  if (!refresher) throw new WorkerJobError(`Automatic refresh is not implemented for ${platform}.`, { blocked: true });
  try {
    const refreshed = await refresher(model, account, user);
    return {
      platform,
      providerAccountId: refreshed.providerAccountId || null,
      expiresAt: refreshed.tokenExpiresAt || null,
      refreshedAt: refreshed.credentialUpdatedAt || new Date().toISOString()
    };
  } catch (error) {
    const retryable = /429|rate limit|timeout|temporar|network|fetch failed|\b5\d\d\b/i.test(String(error.message || error));
    if (!retryable) {
      await markProviderReconnectNeeded(model, account, platformDisplayName(platform), error.message, user).catch(() => {});
      if (isUuid(job.payload?.connectedAccountId)) {
        await optionalSupabaseRequest(`/connected_accounts?id=eq.${encodeURIComponent(job.payload.connectedAccountId)}&workspace_id=eq.${encodeURIComponent(job.workspace_id)}`, {
          method: "PATCH",
          headers: { Prefer: "return=minimal" },
          body: JSON.stringify({ status: "not_connected", connected_at: null, updated_at: new Date().toISOString() })
        }).catch(() => {});
      }
      await enqueueNotificationOutbox(user, {
        type: "provider-reconnect",
        channel: "in-app",
        label: `${platformDisplayName(platform)} needs to be reconnected`,
        detail: "Social Cues could not renew this provider session. Reconnect it from Accounts before the next scheduled post.",
        actionRequired: true,
        route: "/app",
        idempotencyKey: `token-reconnect:${job.payload?.connectedAccountId || platform}:${job.payload?.expiresAt || "expired"}`
      }).catch(() => {});
    }
    throw new WorkerJobError(error.message, { retryable, blocked: !retryable });
  }
}

async function processScheduledPublishWorkerJob(job, registry) {
  if (!automaticPublishingEnabled) {
    throw new WorkerJobError("Automatic publishing is disabled at the operator level.", { blocked: true });
  }
  const user = await workerUserForJob(registry, job);
  if (!user) throw new WorkerJobError("The scheduled post owner no longer exists.", { blocked: true });
  const model = await modelForSession({ user }, registry);
  if (automationPreferences(model).livePublishingPaused) {
    throw new WorkerJobError("Live publishing is paused by the workspace owner.", { blocked: true });
  }
  const externalKey = String(job.payload?.externalKey || "");
  const variantId = String(job.payload?.variantId || externalKey).replace(/^variant-/, "");
  const item = queuedVariants(model, { includeFuture: true }).find(candidate =>
    String(candidate.variant?.id || "") === variantId
    || String(candidate.queueRecord?.id || "") === externalKey
  ) || null;
  if (!item) return { skipped: true, reason: "The campaign variant was removed before publishing." };
  if (item.variant.status === "published") return { duplicateSuppressed: true, providerPostId: item.variant.providerPostId || null };
  if (!["approved", "queued", "retrying"].includes(item.variant.status)) {
    return { skipped: true, reason: `Variant status ${item.variant.status || "unknown"} is not publishable.` };
  }
  const dueAt = Date.parse(item.variant.nextRetryAt || item.variant.scheduledFor || item.variant.queuedAt || "");
  if (Number.isFinite(dueAt) && dueAt > Date.now()) {
    throw new WorkerJobError("Scheduled publish is not due yet.", { retryable: true, retryAt: new Date(dueAt).toISOString() });
  }

  markQueuePublishProcessing(model, item, { user });
  if (item.queueRecord) item.queueRecord.status = "processing";
  const result = await attemptQueuedVariantPublish(model, item, { live: true, user });
  rememberPublishAttempt(item, result);
  rememberQueuePublishResult(model, item, result, { user });
  await saveModelForUser(model, user);
  if (!result.ok) {
    const retryable = retryablePublishFailure(result);
    if (!retryable || Number(job.attempts || 0) >= Number(job.max_attempts || 5)) {
      await enqueueNotificationOutbox(user, {
        type: "publish-failure",
        channel: "email",
        label: `${platformDisplayName(item.variant.platform)} publish needs attention`,
        detail: result.error || "The provider did not accept this scheduled post.",
        actionRequired: true,
        route: "/app",
        idempotencyKey: `publish-worker-failure:${result.idempotencyKey || publishIdempotencyKey(item)}`
      }).catch(() => {});
    }
    throw new WorkerJobError(result.error || "Scheduled provider publish failed.", {
      retryable,
      blocked: !retryable,
      retryAt: item.variant.nextRetryAt || workerRetryAt(job),
      result
    });
  }
  if (item.variant.platform === "tiktok" && result.publishId) {
    await enqueueWorkerJobs([{
      workspace_id: workspaceModelIdForUser(user),
      user_id: supabaseUserIdForUser(user),
      kind: "provider_publish_status",
      idempotency_key: `publish-status:tiktok:${result.publishId}`,
      priority: 75,
      run_at: new Date(Date.now() + 30_000).toISOString(),
      max_attempts: 20,
      payload: {
        platform: "tiktok",
        publishId: result.publishId,
        campaignId: item.campaign.id,
        variantId: item.variant.id,
        providerAccountId: result.providerAccountId || result.account?.providerAccountId || null,
        mode: result.mode || "draft"
      }
    }]);
    return { platform: "tiktok", provider: "tiktok", submitted: true, publishId: result.publishId, mode: result.mode || "draft" };
  }
  return {
    platform: item.variant.platform,
    provider: result.provider,
    providerPostId: result.providerPostId || providerPostIdFromResult(result) || null,
    duplicateSuppressed: Boolean(result.duplicateSuppressed),
    publishedAt: item.variant.publishedAt || new Date().toISOString()
  };
}

async function processProviderPublishStatusWorkerJob(job, registry) {
  if (job.payload?.platform !== "tiktok") throw new WorkerJobError(`Unsupported publish-status provider: ${job.payload?.platform || "unknown"}`, { blocked: true });
  const user = await workerUserForJob(registry, job);
  if (!user) throw new WorkerJobError("The provider-status owner no longer exists.", { blocked: true });
  const model = await modelForSession({ user }, registry);
  const account = (model.connectedAccounts || []).find(item =>
    item.platform === "tiktok"
    && ownedByUser(item, user.id)
    && (!job.payload.providerAccountId || String(item.providerAccountId || "") === String(job.payload.providerAccountId))
  );
  if (!account || !tokenForTikTokAccount(account)) throw new WorkerJobError("Reconnect TikTok before checking the submitted post.", { blocked: true });
  const response = await tiktokApi("/v2/post/publish/status/fetch/", { publish_id: job.payload.publishId }, tokenForTikTokAccount(account), { method: "POST" });
  const data = response?.data || response || {};
  const status = String(data.status || "");
  let target = null;
  for (const campaign of contentVariantBatches(model)) {
    if (job.payload.campaignId && String(campaign.id) !== String(job.payload.campaignId)) continue;
    const variant = (campaign.variants || []).find(candidate => String(candidate.id || "") === String(job.payload.variantId || ""));
    if (variant) { target = { campaign, variant }; break; }
  }
  if (["PROCESSING_UPLOAD", "PROCESSING_DOWNLOAD"].includes(status)) {
    throw new WorkerJobError(`TikTok submission is ${status.toLowerCase().replaceAll("_", " ")}.`, {
      retryable: true,
      retryAt: new Date(Date.now() + 60_000).toISOString(),
      result: { publishId: job.payload.publishId, providerStatus: status, downloadedBytes: data.downloaded_bytes || null, uploadedBytes: data.uploaded_bytes || null }
    });
  }
  if (status === "SEND_TO_USER_INBOX") {
    if (target) {
      target.variant.status = "submitted";
      target.variant.connectionEvidence = "TikTok delivered the draft to the creator inbox; the creator must finish posting in TikTok.";
      target.variant.updatedAt = new Date().toISOString();
      await saveModelForUser(model, user);
    }
    await enqueueNotificationOutbox(user, {
      type: "tiktok-inbox-action",
      channel: "in-app",
      label: "Finish the TikTok draft",
      detail: "TikTok delivered the media to your creator inbox. Open TikTok to review and finish posting it.",
      actionRequired: true,
      route: "/app",
      idempotencyKey: `tiktok-inbox:${job.payload.publishId}`
    }).catch(() => {});
    return { publishId: job.payload.publishId, providerStatus: status, requiresUserAction: true };
  }
  if (status === "PUBLISH_COMPLETE") {
    const publicIds = data.publicaly_available_post_id || data.publicly_available_post_id || [];
    const providerPostId = String(publicIds[0] || job.payload.publishId);
    if (target) {
      target.variant.status = "published";
      target.variant.providerPostId = providerPostId;
      target.variant.publishedAt = new Date().toISOString();
      target.variant.updatedAt = target.variant.publishedAt;
      await saveModelForUser(model, user);
    }
    return { publishId: job.payload.publishId, providerStatus: status, providerPostId, publishedAt: target?.variant?.publishedAt || new Date().toISOString() };
  }
  if (status === "FAILED") {
    const reason = String(data.fail_reason || "TikTok processing failed.");
    if (target) {
      target.variant.status = "failed";
      target.variant.publishError = reason;
      target.variant.updatedAt = new Date().toISOString();
      await saveModelForUser(model, user);
    }
    throw new WorkerJobError(`TikTok publish failed: ${reason}`, { blocked: true, result: { publishId: job.payload.publishId, providerStatus: status, failReason: reason } });
  }
  throw new WorkerJobError(`TikTok returned an unknown publish status: ${status || "empty"}.`, { retryable: true, retryAt: new Date(Date.now() + 60_000).toISOString(), result: { publishId: job.payload.publishId, providerStatus: status } });
}

async function processAnalyticsCollectionWorkerJob(job, registry) {
  const user = await workerUserForJob(registry, job);
  if (!user) throw new WorkerJobError("The analytics workspace owner no longer exists.", { blocked: true });
  if (!hasActiveAppAccess(user)) return { skipped: true, reason: "The workspace does not have an active entitlement." };
  const model = await modelForSession({ user }, registry);
  const analytics = buildGrowthAnalytics(model);
  model.analytics = analytics;
  const snapshot = bankAnalyticsSnapshot(model, analytics, { user }, job.payload?.source || "scheduled-hourly");
  await saveModelForUser(model, user);
  return {
    snapshotId: snapshot?.id || null,
    metricCount: analytics.metrics?.length || 0,
    liveMetricCount: (analytics.metrics || []).filter(metric => metric.kind === "live" && metric.observedAt).length,
    compiledAt: analytics.lastCompiledAt || null
  };
}

const audienceBriefStopWords = new Set([
  "about", "after", "again", "also", "been", "before", "being", "could", "from", "have", "into", "just", "more",
  "most", "only", "other", "over", "really", "should", "some", "than", "that", "their", "them", "then", "there",
  "these", "they", "this", "through", "very", "want", "what", "when", "where", "which", "while", "with", "would",
  "your", "youre", "https", "social", "cues"
]);

function repeatedAudienceTerms(events = []) {
  const counts = new Map();
  for (const event of events) {
    const words = String(event.body_text || "").toLowerCase().match(/[a-z0-9][a-z0-9'-]{2,}/g) || [];
    for (const word of words) {
      if (audienceBriefStopWords.has(word) || /^\d+$/.test(word)) continue;
      counts.set(word, (counts.get(word) || 0) + 1);
    }
  }
  return [...counts.entries()]
    .filter(([, count]) => count >= 2)
    .sort((left, right) => right[1] - left[1] || left[0].localeCompare(right[0]))
    .slice(0, 5)
    .map(([term, count]) => ({ term, count }));
}

function localAudienceBrief(model = {}, events = [], briefDate = "") {
  const analytics = model.analytics || buildGrowthAnalytics(model);
  const liveMetrics = (analytics.metrics || []).filter(metric => metric.kind === "live" && metric.observedAt);
  const terms = repeatedAudienceTerms(events);
  const providerCount = new Set(events.map(event => event.provider).filter(Boolean)).size;
  const replyNeeded = events.filter(event => ["unread", "needs_reply", "drafted"].includes(event.status)).length;
  const enoughEvidence = events.length >= 8 && providerCount >= 2 && liveMetrics.length >= 2;
  const someEvidence = events.length >= 3 || liveMetrics.length >= 2;
  const confidence = enoughEvidence ? "medium" : "low";
  const evidenceStatus = enoughEvidence ? "mixed" : someEvidence ? "mixed" : "limited";
  const topTerms = terms.map(item => `${item.term} (${item.count})`).join(", ");
  const strongestSignals = [];
  if (events.length) {
    strongestSignals.push({
      signal: `${events.length} audience response${events.length === 1 ? "" : "s"} observed in the last 7 days`,
      evidence: `${providerCount || 1} connected provider${providerCount === 1 ? "" : "s"}; ${replyNeeded} response${replyNeeded === 1 ? "" : "s"} currently need review or follow-up.`
    });
  }
  if (terms.length) {
    strongestSignals.push({
      signal: `Repeated audience language: ${topTerms}`,
      evidence: "Terms are counted only from provider-returned response text and require at least two occurrences."
    });
  }
  if (liveMetrics.length) {
    strongestSignals.push({
      signal: `${liveMetrics.length} timestamped provider metric${liveMetrics.length === 1 ? "" : "s"} available`,
      evidence: liveMetrics.slice(0, 4).map(metric => `${metric.label}: ${metric.value} (${metric.source})`).join("; ")
    });
  }
  if (!strongestSignals.length) {
    strongestSignals.push({
      signal: "Audience evidence is not established yet",
      evidence: "No recent provider responses or timestamped audience metrics were available for this workspace."
    });
  }
  const nextMoves = [];
  if (replyNeeded) {
    nextMoves.push({
      action: `Review ${replyNeeded} response${replyNeeded === 1 ? "" : "s"} that need attention`,
      reason: "Fast, relevant replies create the next measurable audience signal.",
      measure: "Resolved responses and reply turnaround time"
    });
  }
  if (terms.length) {
    nextMoves.push({
      action: `Build one follow-up around “${terms[0].term}”`,
      reason: "It is the most repeated term in recent provider-returned audience language.",
      measure: "Replies, saves, and click-through versus the previous post"
    });
  }
  nextMoves.push({
    action: someEvidence ? "Publish one controlled follow-up and compare the next snapshot" : "Publish a baseline post on one connected platform",
    reason: someEvidence ? "A single-variable follow-up makes the next result easier to interpret." : "The audience intelligence layer needs real traffic before it can make behavioral claims.",
    measure: "Reach, replies, saves, clicks, and follower change after 24 hours"
  });
  return {
    headline: events.length ? "Your audience response brief" : "Build the first audience signal",
    summary: events.length
      ? `${events.length} recent response${events.length === 1 ? " is" : "s are"} available. ${terms.length ? `Repeated language points toward ${terms.map(item => item.term).join(", ")}.` : "There is not yet enough repeated language to call a durable theme."}`
      : "Social Cues has connected capability evidence, but not enough recent audience behavior to infer what people want today.",
    audienceMood: events.length >= 5 ? "Active, with sentiment intentionally unclassified until response analysis has stronger evidence" : "Not enough evidence",
    evidenceStatus,
    confidence,
    strongestSignals,
    risks: [
      ...(confidence === "low" ? ["Sparse evidence can make one comment or one metric look more important than it is."] : []),
      ...(replyNeeded ? [`${replyNeeded} response${replyNeeded === 1 ? " is" : "s are"} still awaiting a decision.`] : [])
    ],
    nextMoves: nextMoves.slice(0, 3),
    generatedAt: new Date().toISOString(),
    briefDate,
    liveMetricCount: liveMetrics.length,
    responseCount: events.length,
    providerCount,
    model: "social-cues-evidence-rules-v1"
  };
}

async function processAudienceBriefWorkerJob(job, registry) {
  const user = await workerUserForJob(registry, job);
  if (!user) throw new WorkerJobError("The audience brief workspace owner no longer exists.", { blocked: true });
  if (!hasActiveAppAccess(user)) return { skipped: true, reason: "The workspace does not have an active entitlement." };
  const workspaceId = workspaceModelIdForUser(user);
  const userId = supabaseUserIdForUser(user);
  if (!isUuid(workspaceId) || !isUuid(userId)) throw new WorkerJobError("The audience brief workspace identity is incomplete.", { blocked: true });
  const model = await modelForSession({ user }, registry);
  model.analytics = model.analytics || buildGrowthAnalytics(model);
  const evidenceFrom = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
  const rows = await optionalSupabaseRequest(`/response_events?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(userId)}&observed_at=gte.${encodeURIComponent(evidenceFrom)}&select=provider,status,body_text,observed_at&order=observed_at.desc&limit=500`);
  const events = Array.isArray(rows) ? rows : [];
  const briefDate = String(job.payload?.briefDate || new Date().toISOString().slice(0, 10));
  const brief = localAudienceBrief(model, events, briefDate);
  model.audienceIntelligence = brief;
  const evidenceTo = new Date().toISOString();
  await optionalSupabaseRequest("/audience_briefs?on_conflict=workspace_id,brief_date", {
    method: "POST",
    headers: { Prefer: "resolution=merge-duplicates,return=minimal" },
    body: JSON.stringify([{
      workspace_id: workspaceId,
      user_id: userId,
      brief_date: briefDate,
      evidence_from: events.map(item => item.observed_at).filter(Boolean).sort()[0] || evidenceFrom,
      evidence_to: evidenceTo,
      status: "ready",
      brief,
      model: brief.model,
      last_error: null,
      updated_at: evidenceTo
    }])
  });
  await saveModelForUser(model, user);
  await enqueueNotificationOutbox(user, {
    type: "audience-brief-ready",
    channel: "in-app",
    label: "Your audience brief is ready",
    detail: brief.summary,
    route: "/app",
    idempotencyKey: `daily-audience-brief:${briefDate}`
  }).catch(() => {});
  await enqueueNotificationOutbox(user, {
    type: "audience-brief-ready",
    channel: "push",
    label: "Your audience brief is ready",
    detail: brief.summary,
    route: "/app",
    idempotencyKey: `daily-audience-brief-push:${briefDate}`
  }).catch(() => {});
  return { briefDate, confidence: brief.confidence, responseCount: events.length, liveMetricCount: brief.liveMetricCount };
}

async function processWorkerJob(job, registry) {
  if (job.kind === "scheduled_publish") return processScheduledPublishWorkerJob(job, registry);
  if (job.kind === "provider_publish_status") return processProviderPublishStatusWorkerJob(job, registry);
  if (job.kind === "token_refresh") return processTokenRefreshWorkerJob(job, registry);
  if (job.kind === "notification_delivery") return processNotificationWorkerJob(job);
  if (job.kind === "analytics_collection") return processAnalyticsCollectionWorkerJob(job, registry);
  if (job.kind === "audience_brief") return processAudienceBriefWorkerJob(job, registry);
  throw new WorkerJobError(`Unknown worker job kind: ${job.kind}`, { blocked: true });
}

async function runDurableWorkerTick(options = {}) {
  const workerId = options.workerId || `vercel-${process.env.VERCEL_DEPLOYMENT_ID || process.pid}-${uid("worker")}`;
  const trigger = options.trigger || "manual";
  const startedAt = Date.now();
  const discovery = await discoverWorkerJobs();
  if (!discovery.ready) return { ok: false, ready: false, workerId, discovery, error: "Durable worker tables are not available." };
  const runRows = await optionalSupabaseRequest("/worker_runs", {
    method: "POST",
    headers: { Prefer: "return=representation" },
    body: JSON.stringify([{ worker_id: workerId, trigger, status: "running", metadata: { discovery } }])
  });
  const runId = runRows?.[0]?.id || null;
  const jobs = await claimWorkerJobs(workerId, options.limit || workerBatchSize);
  const summary = { claimed: jobs.length, succeeded: 0, retried: 0, blocked: 0, dead: 0 };
  const results = [];
  const registry = await getModel();

  for (const job of jobs) {
    if (Date.now() - startedAt >= workerTimeBudgetMs) {
      await finishWorkerJob(job, workerId, "retrying", { error: "Worker time budget reached before execution.", runAt: new Date(Date.now() + 60_000).toISOString() });
      summary.retried += 1;
      continue;
    }
    await heartbeatWorkerJob(job.id, workerId).catch(() => {});
    try {
      const result = await processWorkerJob(job, registry);
      await finishWorkerJob(job, workerId, "completed", { result });
      summary.succeeded += 1;
      results.push({ job: publicWorkerJob(job), status: "completed", result });
    } catch (error) {
      const attemptsExhausted = Number(job.attempts || 0) >= Number(job.max_attempts || 5);
      const status = error.blocked ? "blocked" : error.retryable && !attemptsExhausted ? "retrying" : "dead";
      const result = { ...(job.result || {}), ...(error.result || {}) };
      await finishWorkerJob(job, workerId, status, {
        result,
        error: String(error.message || error).slice(0, 2000),
        runAt: error.retryAt || workerRetryAt(job)
      });
      summary[status] += 1;
      results.push({ job: publicWorkerJob(job), status, error: String(error.message || error), result });
    }
  }

  const completedAt = new Date().toISOString();
  const runStatus = summary.dead || summary.blocked ? (summary.succeeded ? "partial" : "failed") : "completed";
  if (runId) {
    await optionalSupabaseRequest(`/worker_runs?id=eq.${encodeURIComponent(runId)}`, {
      method: "PATCH",
      headers: { Prefer: "return=minimal" },
      body: JSON.stringify({
        status: runStatus,
        completed_at: completedAt,
        ...summary,
        metadata: { discovery, durationMs: Date.now() - startedAt }
      })
    });
  }
  console.log(JSON.stringify({ event: "durable_worker_tick", workerId, runId, trigger, ...summary, durationMs: Date.now() - startedAt }));
  return { ok: runStatus !== "failed", ready: true, workerId, runId, trigger, discovery, summary, results, completedAt };
}

async function workerStatusForUser(user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  if (!supabaseEnabled || !workspaceId) return { ready: false, summary: {}, rows: [] };
  const rows = await optionalSupabaseRequest(`/worker_jobs?workspace_id=eq.${encodeURIComponent(workspaceId)}&select=id,kind,status,priority,run_at,attempts,max_attempts,last_error,estimated_cost_microusd,actual_cost_microusd,created_at,updated_at,completed_at&order=created_at.desc&limit=100`);
  const safeRows = (Array.isArray(rows) ? rows : []).map(publicWorkerJob);
  return {
    ready: true,
    summary: safeRows.reduce((summary, row) => ({ ...summary, [row.status]: (summary[row.status] || 0) + 1 }), {}),
    rows: safeRows
  };
}

function canManageWorkspaceMembers(user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  const ownsPrivateWorkspace = Boolean(workspaceId && ownerUserId && workspaceId === ownerUserId);
  return Boolean(ownsPrivateWorkspace || isSignupOwnerEmail(user.email) || ["Owner", "Admin"].includes(resolvedAppUserRole(user)));
}

async function workspaceMembershipView(user = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  if (!supabaseEnabled || !workspaceId) return { members: [], invites: [] };
  const [memberRows, profileRows, inviteRows] = await Promise.all([
    optionalSupabaseRequest(`/workspace_members?workspace_id=eq.${encodeURIComponent(workspaceId)}&select=user_id,role,created_at,updated_at&order=created_at.asc`),
    optionalSupabaseRequest(`/profiles?workspace_id=eq.${encodeURIComponent(workspaceId)}&select=id,display_name,email,role`),
    canManageWorkspaceMembers(user)
      ? optionalSupabaseRequest(`/workspace_invites?workspace_id=eq.${encodeURIComponent(workspaceId)}&select=id,invited_email,role,status,expires_at,accepted_at,revoked_at,created_at&order=created_at.desc&limit=50`)
      : Promise.resolve([])
  ]);
  const profiles = new Map((Array.isArray(profileRows) ? profileRows : []).map(row => [String(row.id), row]));
  return {
    members: (Array.isArray(memberRows) ? memberRows : []).map(row => ({
      userId: row.user_id,
      role: row.role,
      name: profiles.get(String(row.user_id))?.display_name || "Workspace member",
      email: profiles.get(String(row.user_id))?.email || "",
      joinedAt: row.created_at,
      updatedAt: row.updated_at
    })),
    invites: Array.isArray(inviteRows) ? inviteRows.map(row => ({
      id: row.id,
      email: row.invited_email,
      role: row.role,
      status: row.status,
      expiresAt: row.expires_at,
      acceptedAt: row.accepted_at,
      revokedAt: row.revoked_at,
      createdAt: row.created_at
    })) : []
  };
}

async function recordAuthAlert(model, user, alert = {}) {
  if (!model || !user?.id) return null;
  model.authUsers = model.authUsers || [];
  const storedUser = model.authUsers.find(item => String(item.id || "") === String(user.id || ""));
  if (!storedUser) return null;
  const entry = {
    id: alert.id || uid("auth-alert"),
    type: alert.type || "account",
    status: alert.status || "info",
    label: alert.label || "Account event",
    detail: alert.detail || "",
    createdAt: alert.createdAt || new Date().toISOString(),
    deviceId: alert.deviceId || "",
    deviceName: alert.deviceName || "",
    actionRequired: Boolean(alert.actionRequired)
  };
  storedUser.authAlerts = Array.isArray(storedUser.authAlerts) ? storedUser.authAlerts : [];
  storedUser.authAlerts.unshift(entry);
  storedUser.authAlerts = storedUser.authAlerts.slice(0, 20);
  await persistAuthAlertAudit(storedUser, entry).catch(() => {});
  await enqueueNotificationOutbox(storedUser, {
    ...entry,
    channel: entry.actionRequired ? "email" : "in-app",
    target: entry.actionRequired ? storedUser.email : String(storedUser.id),
    idempotencyKey: `auth:${storedUser.id}:${entry.id}:${entry.actionRequired ? "email" : "in-app"}`
  }).catch(() => {});
  return publicAuthAlert(entry);
}

function applyPromoEntitlement(user, promo, input = {}) {
  if (!promo) return;
  const now = new Date();
  const daysFree = Number(promo.days || (promo.months ? Number(promo.months) * 30 : 120));
  const existingCode = normalizePromoCode(user.entitlement?.promoCode);
  const samePromo = user.entitlement?.source === "promo-code" && existingCode === normalizePromoCode(promo.code);
  const expiresAt = samePromo && user.entitlement?.expiresAt
    ? user.entitlement.expiresAt
    : addDays(now, daysFree).toISOString();
  user.entitlement = {
    access: promo.access,
    source: "promo-code",
    promoCode: promo.code,
    promoLabel: promo.label,
    active: true,
    fullAccess: true,
    daysFree,
    monthsFree: Math.round(daysFree / 30),
    expiresAt,
    billingStartsAfter: expiresAt,
    selectedPlan: "Social Cues highest tier tester access",
    tier: "highest",
    subscriptionPaid: true,
    appFeePaid: true,
    paymentStatus: "promo-paid",
    memberOnly: Boolean(promo.memberOnly),
    alphaHonorDiscountPercent: 10,
    alphaPremiumPercent: 25,
    deactivatesBeforeAlpha: false,
    grantedAt: samePromo && user.entitlement?.grantedAt ? user.entitlement.grantedAt : (user.entitlement?.grantedAt || now.toISOString()),
    grantedReason: input.grantedReason || "120-day no-charge highest-tier test account"
  };
}

function applyPaidEntitlement(user, payment = {}) {
  if (!user) return null;
  const plan = payment.selectedPlan || payment.plan || "Paid access";
  const access = payment.access || stripeAccessForPlan(plan);
  user.entitlement = {
    access,
    source: "stripe",
    active: true,
    fullAccess: true,
    tier: payment.tier || (access.includes("founder") ? "founder" : "highest"),
    subscriptionPaid: payment.subscriptionPaid !== false,
    appFeePaid: payment.appFeePaid !== false,
    paymentStatus: payment.paymentStatus || "paid",
    stripeCustomerId: payment.customerId || user.entitlement?.stripeCustomerId || "",
    stripeCheckoutSessionId: payment.checkoutSessionId || user.entitlement?.stripeCheckoutSessionId || "",
    stripeSubscriptionId: payment.subscriptionId || user.entitlement?.stripeSubscriptionId || "",
    selectedPlan: plan,
    grantedAt: user.entitlement?.source === "stripe" && user.entitlement?.grantedAt ? user.entitlement.grantedAt : new Date().toISOString(),
    grantedReason: payment.reason || "Stripe payment confirmed"
  };
  return user.entitlement;
}

function applyPaidEntitlementForEmail(model, email) {
  const normalized = normalizeEmail(email);
  if (!normalized) return null;
  const payment = (model.billing?.paidEmails || []).find(item => normalizeEmail(item.email) === normalized && item.active !== false);
  if (!payment) return null;
  const user = (model.authUsers || []).find(item => normalizeEmail(item.email) === normalized);
  return user ? applyPaidEntitlement(user, payment) : null;
}

function applyOwnerEntitlement(user) {
  if (!user || !isSignupOwnerEmail(user.email)) return null;
  if (user.entitlement?.memberOnly) return user.entitlement;
  if (publicEntitlement(user).active) return user.entitlement;
  user.entitlement = {
    access: "owner-full-access",
    source: "owner-allowlist",
    active: true,
    fullAccess: true,
    tier: "owner",
    subscriptionPaid: true,
    appFeePaid: true,
    paymentStatus: "owner-verified",
    selectedPlan: "Social Cues owner access",
    grantedAt: user.entitlement?.grantedAt || new Date().toISOString(),
    grantedReason: "Owner email allowlist"
  };
  return user.entitlement;
}

function promoForUserAccess(model, user = {}, _supabaseUser = null, input = {}) {
  const inputPromo = promoCodeRecord(input.promoCode || "");
  if (inputPromo) return inputPromo;
  const ledgerClaim = promoLedgerClaimForEmail(model, user.email);
  return ledgerClaim ? promoCodeRecord(ledgerClaim.code) : null;
}

function hydrateUserAccessState(model, user, { supabaseUser = null, input = {} } = {}) {
  if (!model || !user?.email) return user;
  const promo = promoForUserAccess(model, user, supabaseUser, input);
  if (promo && validatePromoClaim(model, promo, user.email).ok) {
    applyPromoEntitlement(user, promo, input);
    recordPromoClaim(model, promo, user.email, "active", user);
  }
  applyPaidEntitlementForEmail(model, user.email);
  applyOwnerEntitlement(user);
  user.role = resolvedAppUserRole(user);
  return user;
}

function normalizedEntitlementActive(row = {}) {
  return ["active", "trialing", "paid", "promo-paid", "owner-verified"].includes(String(row.status || "").toLowerCase());
}

async function hydrateNormalizedSupabaseAccountState(model, user) {
  const userId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !userId) return user;
  try {
    const [profileRows, entitlementRows] = await Promise.all([
      optionalSupabaseRequest(`/profiles?id=eq.${encodeURIComponent(userId)}&select=id,workspace_id,display_name,email,role,created_at,updated_at&limit=1`),
      optionalSupabaseRequest(`/billing_entitlements?user_id=eq.${encodeURIComponent(userId)}&select=workspace_id,user_id,source,access,status,promo_code,stripe_customer_id,stripe_subscription_id,current_period_end,created_at,updated_at&order=updated_at.desc&limit=1`)
    ]);
    const profile = Array.isArray(profileRows) ? profileRows[0] : null;
    const entitlement = Array.isArray(entitlementRows) ? entitlementRows[0] : null;
    const workspaceId = String(profile?.workspace_id || entitlement?.workspace_id || user.workspaceId || userId);

    if (profile) {
      user.name = profile.display_name || user.name || "Social Cues User";
      user.email = normalizeEmail(user.email || profile.email);
      user.role = profile.role || user.role || "Member";
      user.workspaceId = workspaceId;
    }

    if (entitlement) {
      const active = normalizedEntitlementActive(entitlement);
      const access = entitlement.access || user.entitlement?.access || "unpaid";
      user.entitlement = {
        ...(user.entitlement || {}),
        access,
        source: entitlement.source || user.entitlement?.source || "none",
        active,
        fullAccess: active,
        tier: user.entitlement?.tier || access,
        subscriptionPaid: active,
        appFeePaid: active,
        paymentStatus: entitlement.status || (active ? "active" : "inactive"),
        promoCode: entitlement.promo_code || user.entitlement?.promoCode || "",
        stripeCustomerId: entitlement.stripe_customer_id || user.entitlement?.stripeCustomerId || "",
        stripeSubscriptionId: entitlement.stripe_subscription_id || user.entitlement?.stripeSubscriptionId || "",
        expiresAt: entitlement.current_period_end || null,
        billingStartsAfter: entitlement.current_period_end || null,
        selectedPlan: user.entitlement?.selectedPlan || (access === "highest-tier-test" ? "Social Cues highest tier tester access" : access),
        grantedAt: user.entitlement?.grantedAt || entitlement.created_at || entitlement.updated_at || new Date().toISOString(),
        grantedReason: user.entitlement?.grantedReason || "Durable Supabase billing entitlement"
      };
      user.workspaceId = workspaceId;
    }

    if (workspaceId) {
      const workspaceRows = await optionalSupabaseRequest(`/workspaces?id=eq.${encodeURIComponent(workspaceId)}&select=id,name,plan,owner_user_id,created_at,updated_at&limit=1`);
      const normalizedWorkspace = Array.isArray(workspaceRows) ? workspaceRows[0] : null;
      if (normalizedWorkspace) {
        model.workspaces = Array.isArray(model.workspaces) ? model.workspaces : [];
        let workspace = model.workspaces.find(item => String(item.id || "") === workspaceId);
        if (!workspace) {
          workspace = { id: workspaceId };
          model.workspaces.push(workspace);
        }
        Object.assign(workspace, {
          name: normalizedWorkspace.name || workspace.name || "Social Cues",
          owner: user.name || workspace.owner || "Workspace Owner",
          ownerUserId: normalizedWorkspace.owner_user_id || user.id,
          ownerEmail: user.email || workspace.ownerEmail || "",
          createdAt: normalizedWorkspace.created_at || workspace.createdAt || new Date().toISOString(),
          updatedAt: normalizedWorkspace.updated_at || workspace.updatedAt || new Date().toISOString()
        });
      }
    }
  } catch (error) {
    lastPersistence = { driver: "supabase", ok: false, message: `account state hydration failed: ${error.message}` };
  }
  return user;
}

function recordStripeCheckoutCompletion(model, session = {}) {
  model.billing = model.billing || {};
  model.billing.stripeEvents = model.billing.stripeEvents || [];
  model.billing.paidEmails = model.billing.paidEmails || [];
  const metadata = session.metadata || {};
  const email = normalizeEmail(metadata.email || session.customer_details?.email || session.customer_email || "");
  const selectedPlan = metadata.selected_plan || model.billing.selectedPlan || "Paid access";
  const payment = {
    email,
    userId: metadata.user_id || "",
    selectedPlan,
    access: stripeAccessForPlan(selectedPlan),
    active: true,
    customerId: session.customer || "",
    checkoutSessionId: session.id || "",
    subscriptionId: session.subscription || "",
    paymentIntentId: session.payment_intent || "",
    paymentStatus: session.payment_status || session.status || "",
    amountTotal: session.amount_total || null,
    currency: session.currency || "",
    grantedAt: new Date().toISOString(),
    reason: "Stripe Checkout completed"
  };
  model.billing.stripeEvents.unshift({
    id: uid("stripe-event"),
    type: "checkout.session.completed",
    checkoutSessionId: payment.checkoutSessionId,
    email,
    selectedPlan,
    receivedAt: new Date().toISOString()
  });
  model.billing.stripeEvents = model.billing.stripeEvents.slice(0, 100);
  if (email) {
    const existing = model.billing.paidEmails.find(item => normalizeEmail(item.email) === email);
    if (existing) Object.assign(existing, payment);
    else model.billing.paidEmails.unshift(payment);
    const user = (model.authUsers || []).find(item => normalizeEmail(item.email) === email || item.id === payment.userId);
    if (user) applyPaidEntitlement(user, payment);
  }
  model.billing.status = "Stripe payment confirmed";
  model.billing.lastStripeCheckout = payment;
  return payment;
}

function recordStripeSubscriptionState(model, subscription = {}, eventType = "") {
  const customerId = String(subscription.customer || "");
  const subscriptionId = String(subscription.id || "");
  const activeStatuses = new Set(["active", "trialing"]);
  const status = String(subscription.status || (eventType === "customer.subscription.deleted" ? "canceled" : ""));
  const active = activeStatuses.has(status);
  const payment = (model.billing?.paidEmails || []).find(item =>
    (customerId && String(item.customerId || "") === customerId)
    || (subscriptionId && String(item.subscriptionId || "") === subscriptionId)
  );
  if (!payment) return null;
  payment.active = active;
  payment.paymentStatus = status || eventType;
  payment.subscriptionId = subscriptionId || payment.subscriptionId || "";
  payment.currentPeriodEnd = subscription.current_period_end
    ? new Date(Number(subscription.current_period_end) * 1000).toISOString()
    : payment.currentPeriodEnd || null;
  payment.updatedAt = new Date().toISOString();
  const user = (model.authUsers || []).find(item =>
    normalizeEmail(item.email) === normalizeEmail(payment.email)
    || (payment.userId && item.id === payment.userId)
  );
  if (user) {
    if (active) {
      applyPaidEntitlement(user, {
        ...payment,
        subscriptionPaid: true,
        appFeePaid: true,
        reason: `Stripe subscription ${status}`
      });
      user.entitlement.expiresAt = payment.currentPeriodEnd;
    } else if (user.entitlement?.source === "stripe") {
      user.entitlement.active = false;
      user.entitlement.subscriptionPaid = false;
      user.entitlement.paymentStatus = status || "inactive";
      user.entitlement.expiresAt = payment.currentPeriodEnd;
      user.entitlement.grantedReason = `Stripe subscription ${status || "inactive"}`;
    }
  }
  return { email: payment.email, active, status, subscriptionId, customerId };
}

function passwordError(password) {
  if (password.length < 8) return "Use at least 8 characters for your Social Cues password.";
  if (password.length > 256) return "Password is too long.";
  return "";
}

function hashPassword(password, salt = crypto.randomBytes(16).toString("base64url")) {
  const hash = crypto.scryptSync(password, salt, 64).toString("base64url");
  return `scrypt:v1:${salt}:${hash}`;
}

function verifyPassword(password, stored = "") {
  const parts = String(stored || "").split(":");
  if (parts.length !== 4 || parts[0] !== "scrypt" || parts[1] !== "v1") return false;
  const candidate = hashPassword(password, parts[2]);
  return timingSafeEqualText(candidate, stored);
}

function hashSecret(value) {
  if (!authSessionSecret) {
    throw new Error("AUTH_SESSION_SECRET or OAUTH_TOKEN_ENCRYPTION_KEY is required before account sessions can be signed.");
  }
  return crypto.createHmac("sha256", authSessionSecret).update(String(value || "")).digest("base64url");
}

function missingAuthSessionSecretResponse(res) {
  return json(res, 503, {
    ok: false,
    error: "AUTH_SESSION_SECRET or OAUTH_TOKEN_ENCRYPTION_KEY is required before account sessions can be created."
  });
}

function bearerToken(req) {
  const header = req.headers.authorization || "";
  const match = /^Bearer\s+(.+)$/i.exec(header);
  if (match) return match[1].trim();
  const cookieHeader = String(req.headers.cookie || "");
  const cookie = cookieHeader
    .split(";")
    .map(part => part.trim())
    .find(part => part.startsWith("sc_session="));
  return cookie ? decodeURIComponent(cookie.slice("sc_session=".length)) : "";
}

function base64UrlDecode(value) {
  const normalized = String(value || "").replace(/-/g, "+").replace(/_/g, "/");
  const padded = normalized.padEnd(Math.ceil(normalized.length / 4) * 4, "=");
  return Buffer.from(padded, "base64");
}

function timingSafeEqualText(left, right) {
  const leftBuffer = Buffer.from(left);
  const rightBuffer = Buffer.from(right);
  return leftBuffer.length === rightBuffer.length && crypto.timingSafeEqual(leftBuffer, rightBuffer);
}

function parseMetaSignedRequest(signedRequest) {
  if (!metaAppSecret) throw new Error("META_APP_SECRET is required to verify data deletion requests.");
  const [encodedSignature, encodedPayload] = String(signedRequest || "").split(".");
  if (!encodedSignature || !encodedPayload) throw new Error("Missing signed_request.");

  const payload = JSON.parse(base64UrlDecode(encodedPayload).toString("utf8"));
  if (payload.algorithm && String(payload.algorithm).toUpperCase() !== "HMAC-SHA256") {
    throw new Error("Unsupported signed_request algorithm.");
  }

  const expected = crypto
    .createHmac("sha256", metaAppSecret)
    .update(encodedPayload)
    .digest("base64")
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/, "");

  if (!timingSafeEqualText(encodedSignature, expected)) throw new Error("Invalid signed_request signature.");
  return payload;
}

function metaSignedRequestUserId(payload = {}) {
  return String(payload.user_id || payload.user?.id || payload.user?.user_id || "").trim();
}

function metaSignedRequestOwnerKeys(model = {}, metaUserId = "") {
  const ownerUserIds = new Set();
  const workspaceIds = new Set();
  for (const account of model.connectedAccounts || []) {
    if (account.platform !== "meta") continue;
    if (String(account.providerAccountId || "") !== String(metaUserId || "")) continue;
    if (account.ownerUserId) ownerUserIds.add(String(account.ownerUserId));
    if (account.workspaceId) workspaceIds.add(String(account.workspaceId));
  }
  return { ownerUserIds, workspaceIds };
}

function accountMatchesMetaSignedRequest(model = {}, account = {}, metaUserId = "") {
  if (!metaUserId || !account) return false;
  const platformMatches = ["meta", "facebook"].includes(account.platform) || account.oauthProvider === "meta";
  if (!platformMatches) return false;
  if (account.platform === "meta" && String(account.providerAccountId || "") === String(metaUserId)) return true;

  const { ownerUserIds, workspaceIds } = metaSignedRequestOwnerKeys(model, metaUserId);
  if (account.ownerUserId && ownerUserIds.has(String(account.ownerUserId))) return true;
  if (account.workspaceId && workspaceIds.has(String(account.workspaceId))) return true;

  const legacySingleUserMeta = !hasOwnerMarker(account) && String(model.metaConnection?.userId || "") === String(metaUserId);
  return Boolean(legacySingleUserMeta);
}

function oauthTokenEncryptionKeyMaterial() {
  return process.env.OAUTH_TOKEN_ENCRYPTION_KEY || metaAppSecret || supabaseServiceKey || "Social Cues-local-dev";
}

function oauthTokenEncryptionReadiness() {
  const explicitKey = envPresent("OAUTH_TOKEN_ENCRYPTION_KEY");
  const fallback = explicitKey ? "OAUTH_TOKEN_ENCRYPTION_KEY" : metaAppSecret ? "META_APP_SECRET fallback" : supabaseServiceKey ? "Supabase server key fallback" : "local development fallback";
  const productionReady = runtimeMode !== "vercel" || explicitKey;
  return {
    explicitKey,
    productionReady,
    keySource: fallback,
    missingEnv: productionReady ? [] : ["OAUTH_TOKEN_ENCRYPTION_KEY"]
  };
}

function encryptedToken(value) {
  if (!value) return null;
  const keyMaterial = oauthTokenEncryptionKeyMaterial();
  const key = crypto.createHash("sha256").update(keyMaterial).digest();
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv("aes-256-gcm", key, iv);
  const ciphertext = Buffer.concat([cipher.update(String(value), "utf8"), cipher.final()]);
  const tag = cipher.getAuthTag();
  return {
    alg: "aes-256-gcm",
    iv: iv.toString("base64url"),
    tag: tag.toString("base64url"),
    value: ciphertext.toString("base64url")
  };
}

function decryptedToken(record) {
  if (typeof record === "string") return record;
  if (!record?.value || !record?.iv || !record?.tag) return "";
  const keyMaterial = oauthTokenEncryptionKeyMaterial();
  const key = crypto.createHash("sha256").update(keyMaterial).digest();
  try {
    const decipher = crypto.createDecipheriv("aes-256-gcm", key, Buffer.from(record.iv, "base64url"));
    decipher.setAuthTag(Buffer.from(record.tag, "base64url"));
    return Buffer.concat([
      decipher.update(Buffer.from(record.value, "base64url")),
      decipher.final()
    ]).toString("utf8");
  } catch {
    return "";
  }
}

function cleanOAuthCode(code = "") {
  return String(code || "").replace(/#_$/, "").split("#_")[0].trim();
}

async function metaGraph(pathname, params = {}, accessToken = "", options = {}) {
  const url = new URL(`https://graph.facebook.com/${metaApiVersion}${pathname}`);
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined && value !== null && value !== "") url.searchParams.set(key, value);
  }
  if (accessToken) url.searchParams.set("access_token", accessToken);
  const response = await fetch(url, { method: options.method || "GET" });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || body.error) {
    const message = body.error?.message || `Meta Graph API ${response.status}`;
    throw new Error(message);
  }
  return body;
}

async function instagramGraph(pathname, params = {}, accessToken = "", options = {}) {
  const base = pathname === "/access_token" || pathname === "/refresh_access_token"
    ? "https://graph.instagram.com"
    : `https://graph.instagram.com/${instagramApiVersion}`;
  const url = new URL(`${base}${pathname}`);
  const method = options.method || "GET";
  const payload = new URLSearchParams();
  for (const [key, value] of Object.entries(params)) {
    if (method === "POST") {
      if (value !== undefined && value !== null && value !== "") payload.set(key, value);
      continue;
    }
    if (value !== undefined && value !== null && value !== "") url.searchParams.set(key, value);
  }
  if (method === "POST") {
    if (accessToken) payload.set("access_token", accessToken);
  } else if (accessToken) {
    url.searchParams.set("access_token", accessToken);
  }
  const response = await fetch(url, {
    method,
    headers: method === "POST" ? { "Content-Type": "application/x-www-form-urlencoded" } : undefined,
    body: method === "POST" ? payload.toString() : undefined
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || body.error) {
    const message = body.error?.message || body.error_message || `Instagram API ${response.status}`;
    throw new Error(message);
  }
  return body;
}

