async function xApi(pathname, params = {}, accessToken = "", options = {}) {
  const url = new URL(`https://api.x.com/2${pathname}`);
  const method = options.method || "GET";
  for (const [key, value] of Object.entries(params)) {
    if (method === "GET" && value !== undefined && value !== null && value !== "") url.searchParams.set(key, value);
  }
  const response = await fetch(url, {
    method,
    headers: {
      ...(accessToken ? { Authorization: `Bearer ${accessToken}` } : {}),
      ...(method === "POST" ? { "Content-Type": "application/json" } : {})
    },
    body: method === "POST" ? JSON.stringify(params) : undefined
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || body.error || body.errors?.length) {
    const message = body.error_description || body.error || body.errors?.[0]?.detail || body.errors?.[0]?.title || `X API ${response.status}`;
    throw new Error(message);
  }
  return body;
}

async function tiktokApi(pathname, params = {}, accessToken = "", options = {}) {
  const url = new URL(`https://open.tiktokapis.com${pathname}`);
  const method = options.method || "GET";
  for (const [key, value] of Object.entries(params)) {
    if (method === "GET" && value !== undefined && value !== null && value !== "") url.searchParams.set(key, value);
  }
  const response = await fetch(url, {
    method,
    headers: {
      ...(accessToken ? { Authorization: `Bearer ${accessToken}` } : {}),
      ...(method === "POST" ? { "Content-Type": "application/json; charset=UTF-8" } : {})
    },
    body: method === "POST" ? JSON.stringify(params) : undefined
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || (body.error && body.error.code && body.error.code !== "ok")) {
    const message = body.error?.message || body.error_description || body.error || `TikTok API ${response.status}`;
    throw new Error(message);
  }
  return body;
}

function tiktokUserInfoFields(scopeString = "") {
  const scopes = new Set(String(scopeString || "").split(/[,\s]+/).filter(Boolean));
  const fields = ["open_id", "union_id", "avatar_url", "display_name"];
  if (scopes.has("user.info.profile")) {
    fields.push("bio_description", "profile_deep_link", "is_verified", "username");
  }
  if (scopes.has("user.info.stats")) {
    fields.push("follower_count", "following_count", "likes_count", "video_count");
  }
  return fields;
}

function scopeSet(values = []) {
  return new Set(Array.isArray(values) ? values.filter(Boolean) : String(values || "").split(/[,\s]+/).filter(Boolean));
}

function tiktokCapabilityLanes(account = null) {
  const requested = scopeSet(tiktokScopes);
  const granted = scopeSet(account?.scopes || []);
  const connected = Boolean(account && isRealConnectedAccount(account));
  return tiktokCapabilityLaneDefinitions.map(lane => {
    const requiredScopes = lane.scopes || [];
    const requestedAll = requiredScopes.every(scope => requested.has(scope));
    const grantedAll = requiredScopes.every(scope => granted.has(scope));
    let status = "review-gated";
    if (!requiredScopes.length) {
      status = "future-review";
    } else if (connected && grantedAll) {
      status = "available";
    } else if (requestedAll) {
      status = connected ? "scope-not-granted" : "ready-to-request";
    }
    return {
      ...lane,
      requiredScopes,
      requested: requestedAll,
      granted: grantedAll,
      status
    };
  });
}

function xCapabilityLanes(account = null) {
  const requested = scopeSet(xRequestableScopes);
  const granted = scopeSet(account?.scopes || []);
  const connected = Boolean(account && isRealConnectedAccount(account));
  return xCapabilityLaneDefinitions.map(lane => {
    const requiredScopes = lane.scopes || [];
    const requestedAll = requiredScopes.every(scope => requested.has(scope));
    const grantedAll = requiredScopes.every(scope => granted.has(scope));
    let status = lane.planGate ? "plan-gated" : "not-configured";
    if (!requiredScopes.length) {
      status = "future-review";
    } else if (!xClientId) {
      status = "needs-config";
    } else if (connected && grantedAll && !lane.planGate) {
      status = "available";
    } else if (connected && grantedAll && lane.planGate) {
      status = "plan-gated";
    } else if (lane.planGate && requestedAll) {
      status = "oauth-ready-plan-gated";
    } else if (requestedAll) {
      status = connected ? "scope-not-granted" : "ready-to-request";
    } else {
      status = lane.planGate ? "scope-or-plan-gated" : "scope-not-requested";
    }
    return {
      ...lane,
      requiredScopes,
      requested: requestedAll,
      granted: grantedAll,
      status
    };
  });
}

