async function patreonApi(pathname, params = {}, accessToken = "", options = {}) {
  const method = options.method || "GET";
  const url = new URL(`https://www.patreon.com/api/oauth2/v2${pathname}`);
  const hasBody = !["GET", "HEAD", "DELETE"].includes(method);
  for (const [key, value] of Object.entries(params)) {
    if (!hasBody && value !== undefined && value !== null && value !== "") url.searchParams.set(key, String(value));
  }
  const response = await fetch(url, {
    method,
    headers: {
      Authorization: `Bearer ${accessToken}`,
      Accept: "application/vnd.api+json",
      "User-Agent": "Social Cues App - Audience Intelligence",
      ...(hasBody ? { "Content-Type": "application/vnd.api+json" } : {})
    },
    body: hasBody ? JSON.stringify(params) : undefined
  });
  const body = await response.json().catch(() => ({}));
  const apiErrors = Array.isArray(body.errors)
    ? body.errors.map(error => error.detail || error.title || error.code || "Patreon API error").join("; ")
    : "";
  if (!response.ok || apiErrors || body.error) {
    const message = apiErrors || body.error_description || body.error || `Patreon API ${response.status}`;
    oauthRuntimeLog("patreon", "api_http_error", {
      pathname,
      method,
      httpStatus: response.status,
      providerDetail: String(message).slice(0, 300),
      responseContentType: response.headers.get("content-type") || ""
    });
    const error = new Error(message);
    error.status = response.status;
    error.retryAfterSeconds = Number(body.retry_after_seconds || body.errors?.[0]?.retry_after_seconds || 0) || null;
    throw error;
  }
  return body;
}

function validPatreonWebhookSignature(rawBody = "", presented = "") {
  if (!patreonWebhookSecret || !presented) return false;
  const expected = crypto.createHmac("md5", patreonWebhookSecret).update(String(rawBody)).digest("hex");
  return timingSafeEqualText(String(presented).toLowerCase(), expected.toLowerCase());
}

function patreonWebhookEvent(payload = {}, trigger = "") {
  const data = payload?.data || {};
  const campaignId = String(data.relationships?.campaign?.data?.id || payload?.included?.find?.(item => item.type === "campaign")?.id || "");
  const digest = crypto.createHash("sha256").update(`${trigger}:${JSON.stringify(payload)}`).digest("hex").slice(0, 32);
  return {
    id: `patreon-${digest}`,
    type: String(trigger || data.type || "patreon:event"),
    campaignId,
    resourceId: String(data.id || ""),
    resourceType: String(data.type || ""),
    occurredAt: new Date().toISOString()
  };
}

async function applyPatreonWebhookEvent(payload = {}, trigger = "") {
  const event = patreonWebhookEvent(payload, trigger);
  if (!event.campaignId) return { event, matchedUsers: [] };
  const sharedModel = await getModel();
  const rows = supabaseEnabled
    ? await optionalSupabaseRequest(`/connected_accounts?platform=eq.patreon&provider_account_id=eq.${encodeURIComponent(event.campaignId)}&select=id,workspace_id,user_id,provider_account_id&limit=50`)
    : [];
  const accountRows = Array.isArray(rows) ? rows : [];
  const users = (sharedModel.authUsers || []).filter(user => accountRows.some(row =>
    [row.user_id, row.workspace_id].some(value => value && [user.id, user.supabaseUserId, user.workspaceId].map(String).includes(String(value)))
  ));
  const matchedUsers = [];
  for (const user of users) {
    const workspaceModel = await workspaceModelForRegistryWrite(sharedModel, user);
    workspaceModel.patreonEvents = Array.isArray(workspaceModel.patreonEvents) ? workspaceModel.patreonEvents : [];
    if (!workspaceModel.patreonEvents.some(item => item.id === event.id)) {
      workspaceModel.patreonEvents.unshift({ ...event, ...accountOwnerPatch(user) });
      workspaceModel.patreonEvents = workspaceModel.patreonEvents.slice(0, 250);
      await saveModelForUser(workspaceModel, user);
    }
    matchedUsers.push(user.id);
  }
  return { event, matchedUsers };
}

function linkedInOrganizationId(value = "") {
  const match = String(value || "").match(/urn:li:organization:(\d+)/i);
  return match?.[1] || (/^\d+$/.test(String(value || "")) ? String(value) : "");
}

const linkedInOrganizationPostRoles = new Set([
  "ADMINISTRATOR",
  "CONTENT_ADMIN",
  "DIRECT_SPONSORED_CONTENT_POSTER"
]);

function linkedInOrganizationRoles(account = {}) {
  const values = account.providerRoles || account.profile?.roles || account.profile?.acl?.role || [];
  return [...new Set((Array.isArray(values) ? values : [values]).map(value => String(value || "").toUpperCase()).filter(Boolean))];
}

function linkedInAccountCanPublishOrganizationPost(account = {}) {
  return Boolean(
    account
    && account.accountType === "organization"
    && String(account.providerAccountUrn || "").startsWith("urn:li:organization:")
    && hasAnyScope(account, ["w_organization_social"])
    && linkedInOrganizationRoles(account).some(role => linkedInOrganizationPostRoles.has(role))
  );
}

const linkedInAnalyticsSignalLabels = new Map([
  ["organicfollowercount", "Organic followers"],
  ["paidfollowercount", "Paid followers"],
  ["pageviews", "Page views"],
  ["mobilepageviews", "Mobile Page views"],
  ["desktoppageviews", "Desktop Page views"],
  ["uniqueimpressionscount", "Unique impressions"],
  ["impressioncount", "Impressions"],
  ["clickcount", "Clicks"],
  ["likecount", "Likes"],
  ["commentcount", "Comments"],
  ["sharecount", "Shares"],
  ["engagement", "Engagement rate"]
]);

function linkedInAnalyticsSignals(value, source, pathParts = [], signals = []) {
  if (signals.length >= 80 || value === null || value === undefined) return signals;
  if (Array.isArray(value)) {
    value.forEach((item, index) => linkedInAnalyticsSignals(item, source, [...pathParts, String(index)], signals));
    return signals;
  }
  if (typeof value !== "object") return signals;
  for (const [key, child] of Object.entries(value)) {
    const normalizedKey = String(key).toLowerCase();
    const nextPath = [...pathParts, key];
    if (typeof child === "number" && Number.isFinite(child) && linkedInAnalyticsSignalLabels.has(normalizedKey)) {
      signals.push({
        id: `${source}-${nextPath.join("-")}`.replace(/[^a-z0-9-]+/gi, "-").toLowerCase(),
        label: linkedInAnalyticsSignalLabels.get(normalizedKey),
        value: child,
        source,
        path: nextPath.join(".")
      });
    } else if (child && typeof child === "object") {
      linkedInAnalyticsSignals(child, source, nextPath, signals);
    }
    if (signals.length >= 80) break;
  }
  return signals;
}

function linkedInWebhookChallengeResponse(challengeCode = "") {
  return crypto.createHmac("sha256", linkedInClientSecret).update(String(challengeCode)).digest("hex");
}

function validLinkedInWebhookSignature(rawBody = "", presented = "") {
  if (!linkedInClientSecret || !presented) return false;
  const expected = `hmacsha256=${crypto.createHmac("sha256", linkedInClientSecret).update(String(rawBody)).digest("hex")}`;
  return timingSafeEqualText(String(presented).toLowerCase(), expected.toLowerCase());
}

function linkedInWebhookEvent(notification = {}) {
  const organizationUrn = String(notification.organizationalEntity || "");
  const organizationId = linkedInOrganizationId(organizationUrn);
  const notificationId = String(notification.notificationId || "").trim();
  return {
    id: notificationId ? `linkedin-${notificationId}` : `linkedin-${crypto.createHash("sha256").update(JSON.stringify(notification)).digest("hex").slice(0, 32)}`,
    type: String(notification.action || "SOCIAL_ACTION"),
    organizationUrn,
    organizationId,
    notificationId,
    sourcePost: String(notification.sourcePost || ""),
    generatedActivity: String(notification.generatedActivity || ""),
    subscriber: String(notification.subscriber || ""),
    occurredAt: Number(notification.lastModifiedAt) ? new Date(Number(notification.lastModifiedAt)).toISOString() : new Date().toISOString()
  };
}

async function applyLinkedInWebhookEvent(notification = {}) {
  const event = linkedInWebhookEvent(notification);
  if (!event.organizationId) return { event, matchedUsers: [] };
  const sharedModel = await getModel();
  const rows = supabaseEnabled
    ? await optionalSupabaseRequest(`/connected_accounts?platform=eq.linkedin&provider_account_id=eq.${encodeURIComponent(event.organizationId)}&select=id,workspace_id,user_id,provider_account_id&limit=50`)
    : [];
  const accountRows = Array.isArray(rows) ? rows : [];
  const users = (sharedModel.authUsers || []).filter(user => accountRows.some(row =>
    [row.user_id, row.workspace_id].some(value => value && [user.id, user.supabaseUserId, user.workspaceId].map(String).includes(String(value)))
  ));
  const matchedUsers = [];
  for (const user of users) {
    const workspaceModel = await workspaceModelForRegistryWrite(sharedModel, user);
    const account = (workspaceModel.connectedAccounts || []).find(item =>
      item.platform === "linkedin" && String(item.providerAccountId || "") === event.organizationId
    );
    if (!account) continue;
    workspaceModel.linkedinNotifications = Array.isArray(workspaceModel.linkedinNotifications) ? workspaceModel.linkedinNotifications : [];
    if (!workspaceModel.linkedinNotifications.some(item => item.id === event.id)) {
      workspaceModel.linkedinNotifications.unshift({ ...event, ...accountOwnerPatch(user) });
      workspaceModel.linkedinNotifications = workspaceModel.linkedinNotifications.slice(0, 250);
      await saveModelForUser(workspaceModel, user);
    }
    matchedUsers.push(user.id);
  }
  return { event, matchedUsers };
}

async function linkedInOrganizationsForToken(accessToken = "", scopes = []) {
  const normalized = scopes.map(scope => String(scope).toLowerCase());
  if (!normalized.includes("rw_organization_admin")) return [];
  const aclElements = [];
  let start = 0;
  const count = 100;
  for (let pageNumber = 0; pageNumber < 20; pageNumber += 1) {
    const page = await linkedInApi("/organizationAcls", { q: "roleAssignee", state: "APPROVED", start, count }, accessToken);
    const elements = Array.isArray(page.elements) ? page.elements : [];
    aclElements.push(...elements);
    const total = Number(page.paging?.total);
    const pageStart = Number.isFinite(Number(page.paging?.start)) ? Number(page.paging.start) : start;
    const pageCount = Number.isFinite(Number(page.paging?.count)) ? Number(page.paging.count) : elements.length;
    const nextStart = pageStart + Math.max(pageCount, elements.length);
    if (!elements.length || (Number.isFinite(total) && nextStart >= total) || (!Number.isFinite(total) && elements.length < count)) break;
    start = nextStart > start ? nextStart : start + elements.length;
  }
  const byId = new Map();
  for (const acl of aclElements) {
    const urn = acl.organizationalTarget || acl.organizationTarget || acl.organization || "";
    const id = linkedInOrganizationId(urn);
    if (!id) continue;
    const current = byId.get(id) || { id, urn: `urn:li:organization:${id}`, acls: [], roles: [] };
    current.acls.push(acl);
    current.roles = [...new Set([...current.roles, String(acl.role || "").toUpperCase()].filter(Boolean))];
    byId.set(id, current);
  }
  const organizations = [];
  // LinkedIn's Community Development tier does not support BATCH_GET.
  for (const organization of byId.values()) {
    const profile = await linkedInApi(`/organizations/${organization.id}`, {}, accessToken).catch(() => null);
    organizations.push({
      ...organization,
      acl: organization.acls[0] || null,
      canPublishOrganizationPost: organization.roles.some(role => linkedInOrganizationPostRoles.has(role)),
      profile
    });
  }
  return organizations;
}

