function safeManychatInstallationLink(value = "") {
  try {
    const url = new URL(String(value || ""));
    const host = url.hostname.toLowerCase();
    if (url.protocol !== "https:" || (host !== "manychat.com" && !host.endsWith(".manychat.com"))) return "";
    return url.toString();
  } catch {
    return "";
  }
}

function looksLikeManychatProfileApiKey(value = "") {
  return /^\d{5,}:[A-Za-z0-9_-]{24,}$/.test(String(value || "").trim());
}

async function manychatApi(pathname, params = {}, apiKey = "", options = {}) {
  if (!apiKey) throw new Error("A Manychat Account API key is required.");
  const method = String(options.method || "GET").toUpperCase();
  const url = new URL(`${manychatApiBaseUrl}${pathname}`);
  if (method === "GET") {
    for (const [key, value] of Object.entries(params)) {
      if (value !== undefined && value !== null && value !== "") url.searchParams.set(key, value);
    }
  }
  const response = await fetch(url, {
    method,
    headers: {
      Authorization: `Bearer ${apiKey}`,
      ...(method !== "GET" ? { "Content-Type": "application/json; charset=UTF-8" } : {})
    },
    body: method !== "GET" ? JSON.stringify(params) : undefined
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok || body.status === "error" || body.status === "exception") {
    const error = new Error(body.message || body.error?.message || body.error || `Manychat API ${response.status}`);
    error.status = response.status;
    error.retryAfterSeconds = Math.max(0, Number(response.headers.get("retry-after") || 0));
    throw error;
  }
  return body;
}

function manychatQuotaPolicy(pathname = "", method = "GET") {
  const path = String(pathname || "");
  if (path === "/fb/page/getFlows") return { bucket: "flows", limit: 5, windowSeconds: 1, dailyBucket: "requests:daily" };
  if (path.startsWith("/fb/sending/")) return { bucket: "sending", limit: 10, windowSeconds: 1, dailyBucket: "sends:daily", dailyLimit: manychatDailySendLimit };
  if (path.startsWith("/fb/subscriber/")) return { bucket: method === "GET" ? "subscriber-read" : "subscriber-write", limit: 5, windowSeconds: 1, dailyBucket: "requests:daily" };
  if (method !== "GET") return { bucket: "page-write", limit: 5, windowSeconds: 1, dailyBucket: "requests:daily" };
  return { bucket: "page-read", limit: 20, windowSeconds: 1, dailyBucket: "requests:daily" };
}

async function normalizedManychatAccountId(user = {}, account = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId || !account?.providerAccountId) return "";
  const rows = await optionalSupabaseRequest(
    `/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.manychat&provider_account_id=eq.${encodeURIComponent(account.providerAccountId)}&select=id&limit=1`
  );
  return Array.isArray(rows) ? rows[0]?.id || "" : "";
}

async function claimManychatQuota(user = {}, account = {}, bucket = "requests", limit = 1, windowSeconds = 1, units = 1) {
  if (!supabaseEnabled) return { allowed: true, used: units, remaining: Math.max(0, limit - units), retryAfterSeconds: 0, durable: false };
  const connectedAccountId = await normalizedManychatAccountId(user, account);
  if (!connectedAccountId) {
    throw new Error("Manychat account storage is not ready for durable per-user rate limiting. Reconnect the account and try again.");
  }
  const result = await supabaseRequest("/rpc/social_cues_claim_provider_api_quota", {
    method: "POST",
    body: JSON.stringify({
      p_workspace_id: workspaceModelIdForUser(user),
      p_connected_account_id: connectedAccountId,
      p_provider: "manychat",
      p_bucket: bucket,
      p_window_seconds: windowSeconds,
      p_limit: limit,
      p_units: units
    })
  });
  const decision = Array.isArray(result) ? result[0] : result;
  if (!decision?.allowed) {
    const retryAfterSeconds = Math.max(1, Number(decision?.retry_after_seconds || 1));
    const error = new Error(`Manychat ${bucket} limit reached for this workspace. Retry in about ${retryAfterSeconds} seconds.`);
    error.status = 429;
    error.retryAfterSeconds = retryAfterSeconds;
    throw error;
  }
  return {
    allowed: true,
    used: Number(decision.used || 0),
    remaining: Number(decision.remaining || 0),
    retryAfterSeconds: 0,
    durable: true
  };
}

async function manychatApiForAccount(user = {}, account = {}, pathname = "", params = {}, options = {}) {
  const apiKey = decryptedToken(account?.credential || account?.token);
  if (!apiKey) throw new Error("The stored Manychat API key is missing or could not be decrypted.");
  const method = String(options.method || "GET").toUpperCase();
  const policy = manychatQuotaPolicy(pathname, method);
  await claimManychatQuota(user, account, policy.dailyBucket, policy.dailyLimit || manychatDailyRequestLimit, 86400, 1);
  await claimManychatQuota(user, account, policy.bucket, policy.limit, policy.windowSeconds, 1);
  if (pathname === "/fb/sending/sendFlow" && params.subscriber_id) {
    const subscriberHash = crypto.createHash("sha256").update(String(params.subscriber_id)).digest("hex").slice(0, 24);
    await claimManychatQuota(user, account, `subscriber-send:${subscriberHash}`, manychatSubscriberHourlySendLimit, 3600, 1);
  }
  return manychatApi(pathname, params, apiKey, { method });
}

function elevenlabsAccountForUser(model = {}, user = null) {
  return bestProviderAccountFromList((model.connectedAccounts || []).filter(account =>
    account.platform === "elevenlabs"
    && (!user?.id || ownedByUser(account, user.id))
  ), "elevenlabs");
}

function safeElevenlabsSubscription(subscription = {}) {
  const characterCount = Math.max(0, Number(subscription.character_count || 0));
  const characterLimit = Math.max(0, Number(subscription.character_limit || 0));
  return {
    tier: String(subscription.tier || "unknown"),
    status: String(subscription.status || "unknown"),
    characterCount,
    characterLimit,
    charactersRemaining: Math.max(0, characterLimit - characterCount),
    nextResetAt: subscription.next_character_count_reset_unix
      ? new Date(Number(subscription.next_character_count_reset_unix) * 1000).toISOString()
      : null,
    voiceSlotsUsed: Math.max(0, Number(subscription.voice_slots_used || 0)),
    voiceLimit: Math.max(0, Number(subscription.voice_limit || 0)),
    canUseInstantVoiceCloning: Boolean(subscription.can_use_instant_voice_cloning),
    canUseProfessionalVoiceCloning: Boolean(subscription.can_use_professional_voice_cloning),
    canUseOverages: Boolean(subscription.can_extend_character_limit)
  };
}

async function elevenlabsApi(pathname, params = {}, apiKey = "", options = {}) {
  if (!apiKey) throw new Error("An ElevenLabs API key is required.");
  const method = String(options.method || "GET").toUpperCase();
  const url = new URL(`${elevenlabsApiBaseUrl}${pathname}`);
  if (method === "GET") {
    for (const [key, value] of Object.entries(params)) {
      if (value !== undefined && value !== null && value !== "") url.searchParams.set(key, value);
    }
  }
  const response = await fetch(url, {
    method,
    headers: {
      "xi-api-key": apiKey,
      Accept: options.accept || "application/json",
      ...(method !== "GET" ? { "Content-Type": "application/json; charset=UTF-8" } : {})
    },
    body: method !== "GET" ? JSON.stringify(params) : undefined
  });
  if (options.binary && response.ok) {
    return {
      bytes: Buffer.from(await response.arrayBuffer()),
      contentType: response.headers.get("content-type") || "audio/mpeg",
      requestId: response.headers.get("request-id") || response.headers.get("x-request-id") || ""
    };
  }
  const body = await response.json().catch(() => ({}));
  if (!response.ok || body.detail?.status === "error" || body.error) {
    const detail = body.detail;
    const message = typeof detail === "string"
      ? detail
      : detail?.message || body.message || body.error?.message || body.error || `ElevenLabs API ${response.status}`;
    const error = new Error(message);
    error.status = response.status;
    error.retryAfterSeconds = Math.max(0, Number(response.headers.get("retry-after") || 0));
    throw error;
  }
  return body;
}

async function normalizedElevenlabsAccountId(user = {}, account = {}) {
  const workspaceId = workspaceModelIdForUser(user);
  const ownerUserId = supabaseUserIdForUser(user);
  if (!supabaseEnabled || !workspaceId || !ownerUserId || !account?.providerAccountId) return "";
  const rows = await optionalSupabaseRequest(
    `/connected_accounts?workspace_id=eq.${encodeURIComponent(workspaceId)}&user_id=eq.${encodeURIComponent(ownerUserId)}&platform=eq.elevenlabs&provider_account_id=eq.${encodeURIComponent(account.providerAccountId)}&select=id&limit=1`
  );
  return Array.isArray(rows) ? rows[0]?.id || "" : "";
}

async function claimElevenlabsQuota(user = {}, account = {}, bucket = "requests", limit = 1, windowSeconds = 1, units = 1) {
  if (!supabaseEnabled) return { allowed: true, used: units, remaining: Math.max(0, limit - units), retryAfterSeconds: 0, durable: false };
  const connectedAccountId = await normalizedElevenlabsAccountId(user, account);
  if (!connectedAccountId) throw new Error("ElevenLabs account storage is not ready for durable per-user metering. Reconnect the account and try again.");
  const result = await supabaseRequest("/rpc/social_cues_claim_provider_api_quota", {
    method: "POST",
    body: JSON.stringify({
      p_workspace_id: workspaceModelIdForUser(user),
      p_connected_account_id: connectedAccountId,
      p_provider: "elevenlabs",
      p_bucket: bucket,
      p_window_seconds: windowSeconds,
      p_limit: limit,
      p_units: units
    })
  });
  const decision = Array.isArray(result) ? result[0] : result;
  if (!decision?.allowed) {
    const retryAfterSeconds = Math.max(1, Number(decision?.retry_after_seconds || 1));
    const error = new Error(`ElevenLabs ${bucket} limit reached for this workspace. Retry in about ${retryAfterSeconds} seconds.`);
    error.status = 429;
    error.retryAfterSeconds = retryAfterSeconds;
    throw error;
  }
  return {
    allowed: true,
    used: Number(decision.used || 0),
    remaining: Number(decision.remaining || 0),
    retryAfterSeconds: 0,
    durable: true
  };
}

async function elevenlabsApiForAccount(user = {}, account = {}, pathname = "", params = {}, options = {}) {
  const apiKey = decryptedToken(account?.credential || account?.token);
  if (!apiKey) throw new Error("The stored ElevenLabs API key is missing or could not be decrypted.");
  await claimElevenlabsQuota(user, account, "requests:daily", elevenlabsDailyRequestLimit, 86400, 1);
  await claimElevenlabsQuota(user, account, "requests:minute", 10, 60, 1);
  if (options.characters) {
    await claimElevenlabsQuota(user, account, "characters:daily", elevenlabsDailyCharacterLimit, 86400, options.characters);
  }
  return elevenlabsApi(pathname, params, apiKey, options);
}

async function verifyDiscordInteractionSignature(signature = "", timestamp = "", rawBody = "") {
  const publicKey = String(discordPublicKey || "").trim();
  if (!/^[0-9a-f]{64}$/i.test(publicKey)) return false;
  if (!/^[0-9a-f]{128}$/i.test(String(signature || ""))) return false;
  if (!timestamp) return false;
  const timestampMs = Number(timestamp) * 1000;
  if (!Number.isFinite(timestampMs) || Math.abs(Date.now() - timestampMs) > 5 * 60 * 1000) return false;
  try {
    const key = await crypto.webcrypto.subtle.importKey(
      "raw",
      Buffer.from(publicKey, "hex"),
      { name: "Ed25519" },
      false,
      ["verify"]
    );
    return crypto.webcrypto.subtle.verify(
      { name: "Ed25519" },
      key,
      Buffer.from(signature, "hex"),
      Buffer.from(`${timestamp}${rawBody}`)
    );
  } catch {
    return false;
  }
}

function discordCommandPayloads({ global = false } = {}) {
  const cue = {
    name: "cue",
    type: 1,
    description: "Check Social Cues campaign, provider, and community workflows.",
    options: [
      {
        name: "action",
        description: "Choose the Social Cues check to run.",
        type: 3,
        required: false,
        choices: [
          { name: "Status", value: "status" },
          { name: "Launch room", value: "launch-room" },
          { name: "Support handoff", value: "support" },
          { name: "Community inbox", value: "community" }
        ]
      }
    ]
  };
  const captureMessage = {
    name: "Send to Social Cues",
    type: 3
  };
  const communityProfile = {
    name: "Community profile",
    type: 2
  };
  if (global) {
    for (const command of [cue, captureMessage, communityProfile]) {
      command.integration_types = [0, 1];
      command.contexts = [0, 1, 2];
    }
  }
  return [cue, captureMessage, communityProfile];
}

function discordCommandRegisterTarget(input = {}) {
  const guildId = String(input.guildId || input.guild_id || discordGuildId || "").trim();
  if (guildId) {
    return {
      guildId,
      global: false,
      path: `/applications/${discordClientId}/guilds/${guildId}/commands`,
      scope: "guild"
    };
  }
  return {
    guildId: "",
    global: true,
    path: `/applications/${discordClientId}/commands`,
    scope: "global"
  };
}

function discordInteractionResponse(payload = {}) {
  const command = payload.data?.name || "cue";
  if (command === "Send to Social Cues") {
    return {
      type: 4,
      data: {
        content: "Open Social Cues Responses to review this message before any reply or moderation action. This command does not copy the message into Social Cues yet.",
        flags: 64
      }
    };
  }
  if (command === "Community profile") {
    return {
      type: 4,
      data: {
        content: "Open Social Cues Responses to review this member in the selected server context. This command does not create a stored profile handoff yet.",
        flags: 64
      }
    };
  }
  const options = Array.isArray(payload.data?.options) ? payload.data.options : [];
  const action = options.find(item => item.name === "action")?.value || "status";
  const message = action === "launch-room"
    ? "Social Cues launch-room check is online. Open the app for approved media, provider gates, and publishing receipts."
    : action === "support"
      ? "Social Cues support handoff is ready. Open the app to route this community issue into the response queue."
      : action === "community"
        ? "Social Cues community inbox is ready. Open Responses to choose a server and channel, review messages, and approve replies."
      : "Social Cues Discord command lane is online. Open the app for provider readiness, campaign status, and analytics.";
  return {
    type: 4,
    data: {
      content: command === "cue" ? message : "Social Cues received the command.",
      flags: 64
    }
  };
}

