  return [
    { name: "DISCORD_CLIENT_ID", label: "Application / Client ID", required: true, ready: envPresent("DISCORD_CLIENT_ID") },
    { name: "DISCORD_CLIENT_SECRET", label: "OAuth2 Client Secret", required: true, ready: envPresent("DISCORD_CLIENT_SECRET") },
    { name: "DISCORD_PUBLIC_KEY", label: "Interactions Public Key", required: true, ready: envPresent("DISCORD_PUBLIC_KEY") },
    { name: "DISCORD_BOT_TOKEN", label: "Bot Token", required: true, ready: envPresent("DISCORD_BOT_TOKEN") },
    { name: "DISCORD_GUILD_ID", label: "Test / owner Discord server ID", required: true, ready: envPresent("DISCORD_GUILD_ID") },
    { name: "DISCORD_ANNOUNCEMENT_CHANNEL_ID", label: "Announcement channel ID", required: true, ready: envPresent("DISCORD_ANNOUNCEMENT_CHANNEL_ID") }
  ];
