async function exchangeMetaCode(code, redirectUri = metaRedirectUri()) {
  if (!metaAppId || !metaAppSecret) throw new Error("META_APP_ID and META_APP_SECRET are required for token exchange.");
  const shortLived = await metaGraph("/oauth/access_token", {
    client_id: metaAppId,
    client_secret: metaAppSecret,
    redirect_uri: redirectUri,
    code
  });
  const longLived = await metaGraph("/oauth/access_token", {
    grant_type: "fb_exchange_token",
    client_id: metaAppId,
    client_secret: metaAppSecret,
    fb_exchange_token: shortLived.access_token
  });
  return {
    accessToken: longLived.access_token || shortLived.access_token,
    tokenType: longLived.token_type || shortLived.token_type || "bearer",
    expiresIn: longLived.expires_in || shortLived.expires_in || null
  };
}

async function exchangeInstagramCode(code, redirectUri = instagramRedirectUri()) {
  if (!instagramAppId || !instagramAppSecret) throw new Error("INSTAGRAM_APP_ID and INSTAGRAM_APP_SECRET are required for Instagram Login token exchange.");
  const payload = new URLSearchParams({
    client_id: instagramAppId,
    client_secret: instagramAppSecret,
    grant_type: "authorization_code",
    redirect_uri: redirectUri,
    code: cleanOAuthCode(code)
  });
  const response = await fetch("https://api.instagram.com/oauth/access_token", {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: payload.toString()
  });
  const shortLived = await response.json().catch(() => ({}));
  if (!response.ok || shortLived.error) {
    const message = shortLived.error_message || shortLived.error?.message || shortLived.error || `Instagram OAuth ${response.status}`;
    throw new Error(`Instagram OAuth token exchange failed for redirect_uri ${redirectUri}: ${message}`);
  }
  let longLived = {};
  try {
    longLived = await instagramGraph("/access_token", {
      grant_type: "ig_exchange_token",
      client_secret: instagramAppSecret,
      access_token: shortLived.access_token
    });
  } catch (error) {
    longLived = { exchangeWarning: error.message };
  }
  const accessToken = longLived.access_token || shortLived.access_token;
  const profile = await instagramGraph("/me", {
    fields: "id,user_id,username,account_type,media_count"
  }, accessToken);
  return {
    accessToken,
    shortLivedAccessToken: shortLived.access_token,
    tokenType: longLived.token_type || shortLived.token_type || "bearer",
    expiresIn: longLived.expires_in || null,
    exchangeWarning: longLived.exchangeWarning || null,
    user: profile,
    rawUserId: shortLived.user_id || profile.user_id || profile.id || null
  };
}

