function patreonTokenError(body = {}, status = 0) {
  const firstError = Array.isArray(body.errors) && body.errors.length ? body.errors[0] || {} : {};
  const code = String(body.error || firstError.code_name || firstError.code || "").trim();
  const detail = String(
    body.error_description
      || body.message
      || firstError.detail
      || firstError.title
      || code
      || `Patreon token endpoint returned HTTP ${status}`
  ).trim();
  return {
    code: code.slice(0, 120),
    detail: detail.slice(0, 300)
  };
}

async function exchangePatreonCode(code, redirectUri = patreonRedirectUri()) {
  if (!patreonClientId || !patreonClientSecret) throw new Error("PATREON_CLIENT_ID and PATREON_CLIENT_SECRET are required for token exchange.");
  const payload = new URLSearchParams({
    code,
    grant_type: "authorization_code",
    client_id: patreonClientId,
    client_secret: patreonClientSecret,
    redirect_uri: redirectUri
  });
  const response = await fetch("https://www.patreon.com/api/oauth2/token", {
    method: "POST",
    headers: {
      Accept: "application/json",
      "Content-Type": "application/x-www-form-urlencoded"
    },
    body: payload.toString()
  });
  const responseText = await response.text();
  let token = {};
  try {
    token = responseText ? JSON.parse(responseText) : {};
  } catch {
    token = {};
  }
  if (!response.ok || token.error || (Array.isArray(token.errors) && token.errors.length)) {
    const providerError = patreonTokenError(token, response.status);
    oauthRuntimeLog("patreon", "token_exchange_http_error", {
      httpStatus: response.status,
      providerError: providerError.code,
      providerDetail: providerError.detail,
      responseContentType: response.headers.get("content-type") || "",
      responseWasJson: Boolean(responseText && Object.keys(token).length),
      requestFieldCount: [...payload.keys()].length,
      authorizationCodeLength: String(code || "").length,
      clientIdLength: patreonClientId.length,
      redirectUri,
      redirectMatchesConfigured: redirectUri === patreonRedirectUri()
    });
    const label = providerError.code && providerError.code !== providerError.detail
      ? `${providerError.code}: ${providerError.detail}`
      : providerError.detail;
    const error = new Error(`Patreon token exchange failed (${response.status}): ${label}`);
    error.status = response.status;
    error.providerCode = providerError.code;
    throw error;
  }
  oauthRuntimeLog("patreon", "token_exchange_http_success", {
    httpStatus: response.status,
    scopesReturned: [...scopeSet(token.scope || [])].length,
    accessTokenReceived: Boolean(token.access_token),
    refreshTokenReceived: Boolean(token.refresh_token),
    redirectMatchesConfigured: redirectUri === patreonRedirectUri()
  });
  const scopes = [...scopeSet(token.scope || patreonScopes)];
  const identity = await patreonApi("/identity", {
    include: "campaign",
    "fields[user]": "full_name,first_name,last_name,image_url,thumb_url,url,vanity",
    "fields[campaign]": "creation_name,name,summary,url,vanity,patron_count,published_at,image_url,image_small_url"
  }, token.access_token);
  let campaigns = [];
  if (scopes.includes("campaigns")) {
    const responseBody = await patreonApi("/campaigns", {
      include: "creator,tiers",
      "fields[campaign]": "creation_name,name,summary,url,vanity,patron_count,published_at,image_url,image_small_url,is_monthly",
      "fields[user]": "full_name,image_url,url,vanity",
      "fields[tier]": "title,amount_cents,patron_count,published,published_at"
    }, token.access_token).catch(() => ({ data: [], included: [] }));
    campaigns = Array.isArray(responseBody.data) ? responseBody.data : [];
  }
  return {
    accessToken: token.access_token,
    refreshToken: token.refresh_token || "",
    tokenType: token.token_type || "Bearer",
    expiresIn: token.expires_in || null,
    scope: scopes,
    identity,
    campaigns
  };
}

