function threadsTokenHealth(account = null) {
  const expiresAt = account?.tokenExpiresAt || null;
  const expiresMs = expiresAt ? Date.parse(expiresAt) : NaN;
  const remainingMs = Number.isFinite(expiresMs) ? expiresMs - Date.now() : null;
  return {
    stored: Boolean(account && hasStoredToken(account)),
    expiresAt,
    expired: remainingMs !== null ? remainingMs <= 0 : false,
    expiresSoon: remainingMs !== null ? remainingMs > 0 && remainingMs <= 14 * 24 * 60 * 60 * 1000 : false,
    daysRemaining: remainingMs !== null ? Math.max(0, Math.ceil(remainingMs / (24 * 60 * 60 * 1000))) : null,
    refreshSupported: false,
    action: remainingMs !== null && remainingMs <= 14 * 24 * 60 * 60 * 1000
      ? "Reconnect Threads before the stored token expires."
      : "No token action is currently required."
  };
}

function applyVerifiedThreadsProfile(account, profile = {}, user = null) {
  if (!account || !profile?.id) return false;
  const before = JSON.stringify(publicAccount(account));
  const username = String(profile.username || "").replace(/^@/, "");
  account.providerAccountId = String(profile.id);
  account.handle = username ? `@${username}` : account.handle || "";
  account.name = profile.name || username || account.name || "Threads";
  account.displayName = profile.name || account.displayName || account.name;
  account.profilePictureUrl = profile.threads_profile_picture_url || account.profilePictureUrl || "";
  account.biography = profile.threads_biography || account.biography || "";
  account.status = "connected";
  account.oauthProvider = "threads";
  account.connectedAt = account.connectedAt || new Date().toISOString();
  account.lastSyncedAt = new Date().toISOString();
  account.identityVerifiedAt = account.lastSyncedAt;
  account.connectionEvidence = `Threads /me verified ${account.handle || account.name} as provider account ${account.providerAccountId}.`;
  account.scopes = Array.from(new Set([...(Array.isArray(account.scopes) ? account.scopes : []), "threads_basic"]));
  if (user?.id) stampWorkspaceOwnership(account, user);
  return before !== JSON.stringify(publicAccount(account));
}

async function verifyThreadsAccountIdentity(account, user = null) {
  const accessToken = tokenForThreadsAccount(account);
  if (!accessToken) throw new Error("Stored Threads token is missing or could not be decrypted.");
  const health = threadsTokenHealth(account);
  if (health.expired) throw new Error("Stored Threads token has expired. Reconnect Threads OAuth.");
  if (syntheticProbeToken(accessToken)) {
    return { profile: null, changed: false, skipped: true, reason: "Synthetic test token; provider network verification skipped." };
  }
  const profile = await threadsApi("/me", { fields: "id,username,name,threads_profile_picture_url,threads_biography" }, accessToken);
  if (!profile?.id) throw new Error("Threads /me did not return a provider account id.");
  return { profile, changed: applyVerifiedThreadsProfile(account, profile, user), skipped: false };
}

function refreshTokenForYouTubeAccount(account) {
  return decryptedToken(account?.refreshCredential || account?.refreshToken);
}

function tokenExpiresSoon(isoValue, skewMs = 60_000) {
  if (!isoValue) return false;
  const time = Date.parse(isoValue);
  return Number.isFinite(time) && time <= Date.now() + skewMs;
}

function isLocalRegressionToken(accessToken = "") {
  return runtimeMode !== "vercel" && accessToken === "fake-test-token-marker";
}

function clearProviderTokenErrors(account = null) {
  if (!account) return account;
  delete account.lastTokenError;
  delete account.refreshError;
  delete account.needsReconnect;
  if (account.tokenValid === false) delete account.tokenValid;
  return account;
}

async function refreshXAccount(model, account, user = null) {
  if (!account) throw new Error("No X account is stored.");
  const refreshToken = refreshTokenForXAccount(account);
  if (!refreshToken) throw new Error("X refresh token is missing. Reconnect X OAuth.");
  const payload = new URLSearchParams({
    grant_type: "refresh_token",
    refresh_token: refreshToken,
    client_id: xClientId
  });
  const headers = { "Content-Type": "application/x-www-form-urlencoded" };
  if (xClientSecret) {
    headers.Authorization = `Basic ${Buffer.from(`${xClientId}:${xClientSecret}`).toString("base64")}`;
  }
  const response = await fetch("https://api.x.com/2/oauth2/token", {
    method: "POST",
    headers,
    body: payload.toString()
  });
  const token = await response.json().catch(() => ({}));
  if (!response.ok || token.error) {
    throw new Error(token.error_description || token.error || `X token refresh ${response.status}`);
  }
  account.credential = encryptedToken(token.access_token);
  account.credentialUpdatedAt = new Date().toISOString();
  if (token.refresh_token) account.refreshCredential = encryptedToken(token.refresh_token);
  account.tokenType = token.token_type || account.tokenType || "bearer";
  account.tokenExpiresAt = token.expires_in ? new Date(Date.now() + token.expires_in * 1000).toISOString() : null;
  account.scopes = String(token.scope || account.scopes?.join(" ") || "").split(/\s+/).filter(Boolean);
  account.status = "connected";
  account.connectedAt = account.connectedAt || new Date().toISOString();
  account.connectionEvidence = "X access token refreshed server-side.";
  clearProviderTokenErrors(account);
  await saveModelForUser(model, user);
  return account;
}

