async function usableDiscordAccount(model, options = {}) {
  const account = usableProviderAccount(model, "discord", { user: options.user || null });
  if (!account) return null;
  if (tokenExpiresSoon(account.tokenExpiresAt) || !tokenForDiscordAccount(account)) {
    if (!options.refresh) return account;
    try {
      return await refreshDiscordAccount(model, account, options.user || null);
    } catch (error) {
      await markProviderReconnectNeeded(model, account, "Discord", error.message, options.user || null);
      throw error;
    }
  }
  return account;
}

async function verifyXAccount(model, account, user = null) {
  if (!account) throw new Error("No X account is stored.");
  const accessToken = tokenForXAccount(account);
  if (!accessToken) throw new Error("X access token is missing.");
  if (isLocalRegressionToken(accessToken)) {
    account.status = "connected";
    account.connectedAt = account.connectedAt || new Date().toISOString();
    account.connectionEvidence = "X local regression token accepted without provider network validation.";
    await saveModelForUser(model, user);
    return account;
  }
  const userBody = await xApi("/users/me", { "user.fields": "id,name,username,verified,profile_image_url" }, accessToken);
  const profile = userBody?.data || null;
  if (profile?.id) account.providerAccountId = profile.id;
  if (profile?.username) account.handle = `@${profile.username}`;
  if (profile?.name) {
    account.name = profile.name;
    account.displayName = profile.name;
  }
  account.status = "connected";
  account.connectedAt = account.connectedAt || new Date().toISOString();
  account.connectionEvidence = "X access token verified server-side.";
  account.profile = { ...(account.profile || {}), ...(profile || {}) };
  clearProviderTokenErrors(account);
  await saveModelForUser(model, user);
  return account;
}

async function markProviderReconnectNeeded(model, account, provider, message, user = null) {
  if (!account) return null;
  account.status = "not connected";
  account.connectedAt = null;
  account.connectionEvidence = `${provider} token repair failed: ${message}`;
  account.lastTokenError = message;
  await saveModelForUser(model, user);
  return account;
}

