function usableProviderAccount(model, platform, options = {}) {
  const candidates = (model.connectedAccounts || []).filter(item =>
    item.platform === platform
    && (!options.user?.id || ownedByUser(item, options.user.id))
  );
  const selectedId = String(model.activeProviderAccounts?.[canonicalProviderAssetPlatform(platform)] || "");
  const usableFallback = account => {
    const state = providerAccountConnectionState(account);
    return state.connected || (state.identityVerified && state.tokenStored && state.refreshStored);
  };
  const selected = candidates.find(account =>
    String(account.providerAccountId || "") === selectedId
    && providerAccountConnectionState(account).connected
  );
  const fallback = bestProviderAccountFromList(candidates, platform);
  return selected || (fallback && usableFallback(fallback) ? fallback : null);
}

async function repairedProviderAccount(model, platform, user = null) {
  const account = usableProviderAccount(model, platform, { user });
  if (repairConnectedOAuthAccount(account, platform)) {
    if (user?.id) await saveModelForUser(model, user);
    else await saveModel(model);
  }
  return account;
}

