async function requireYouTubeAccountForRead(req, res, purpose = "read YouTube data", requiredScopes = ["youtube.readonly"]) {
  const sharedModel = await getModel();
  const session = await entitledSessionFromRequest(sharedModel, req);
  if (runtimeMode === "vercel" && !session) {
    appAccessRequiredResponse(res);
    return null;
  }
  const model = session?.user ? await modelForSession(session, sharedModel) : sharedModel;
  let account = null;
  try {
    account = await usableYouTubeAccount(model, { refresh: true, user: session?.user || null });
  } catch (error) {
    json(res, 409, { ok: false, error: `Reconnect YouTube OAuth before Social Cues can ${purpose}. ${error.message}`, connectRoute: "/api/oauth/youtube/start" });
    return null;
  }
  if (!account || !isRealConnectedAccount(account) || !tokenForYouTubeAccount(account)) {
    json(res, 409, {
      ok: false,
      error: `Connect YouTube OAuth before Social Cues can ${purpose}.`,
      connectRoute: "/api/oauth/youtube/start",
      requiredScopes
    });
    return null;
  }
  const missingScopes = requiredScopes.filter(scope => {
    const normalized = String(scope || "").trim();
    const aliases = normalized.startsWith("https://www.googleapis.com/auth/")
      ? [normalized, normalized.slice("https://www.googleapis.com/auth/".length)]
      : [normalized, `https://www.googleapis.com/auth/${normalized}`];
    return !hasAnyScope(account, aliases);
  });
  if (missingScopes.length) {
    json(res, 409, {
      ok: false,
      error: `Reconnect YouTube and approve ${missingScopes.join(", ")} before Social Cues can ${purpose}.`,
      connectRoute: "/api/oauth/youtube/start",
      requiredScopes,
      grantedScopes: account.scopes || [],
      missingScopes
    });
    return null;
  }
  return { sharedModel, model, session, account, accessToken: tokenForYouTubeAccount(account) };
}

