function publicKeyFingerprint(value = "") {
  if (!value) return null;
  return {
    prefix: value.slice(0, 4),
    suffix: value.slice(-4),
    sha256: crypto.createHash("sha256").update(value).digest("hex").slice(0, 12)
  };
}

function oauthRuntimeLog(provider, event, fields = {}) {
  const safe = {};
  for (const [key, value] of Object.entries(fields || {})) {
    if (value === undefined) continue;
    if (/token|secret|password|credential|code$/i.test(key)) continue;
    safe[key] = value;
  }
  console.log(JSON.stringify({
    type: "social-cues-oauth",
    provider,
    event,
    at: new Date().toISOString(),
    ...safe
  }));
}

function requestCorrelationId(req) {
  const supplied = String(req?.headers?.["x-request-id"] || "").trim();
  return /^[A-Za-z0-9._:-]{8,80}$/.test(supplied) ? supplied : crypto.randomUUID();
}

function requestPathForLog(req) {
  try {
    return new URL(req?.url || "/", "http://social-cues.local").pathname;
  } catch {
    return "/invalid-request-path";
  }
}

function runtimeRequestLog(level, event, req, fields = {}) {
  const safe = {};
  for (const [key, value] of Object.entries(fields || {})) {
    if (value === undefined || /token|secret|password|credential|authorization|cookie|code$/i.test(key)) continue;
    safe[key] = value;
  }
  const record = {
    type: "social-cues-runtime",
    level,
    event,
    requestId: req?.socialCuesRequestId || null,
    method: req?.method || null,
    path: requestPathForLog(req),
    at: new Date().toISOString(),
    ...safe
  };
  console.log(JSON.stringify(record));
  if (level === "error") logRuntimeError(event, record);
}

function oauthStateFingerprint(state = "") {
  const value = String(state || "");
  if (!value) return null;
  return {
    length: value.length,
    prefix: value.slice(0, 8),
    suffix: value.slice(-8),
    sha256: crypto.createHash("sha256").update(value).digest("hex").slice(0, 16)
  };
}

function safeOAuthEventDetails(fields = {}) {
  const safe = {};
  for (const [key, value] of Object.entries(fields || {})) {
    if (value === undefined || value === null) continue;
    if (/token|secret|password|credential|code$|codeVerifier|code_verifier|state$/i.test(key)) continue;
    if (typeof value === "string") safe[key] = value.slice(0, 300);
    else if (typeof value === "number" || typeof value === "boolean") safe[key] = value;
    else if (Array.isArray(value)) safe[key] = value.map(item => String(item).slice(0, 120)).slice(0, 20);
    else safe[key] = JSON.parse(JSON.stringify(value));
  }
  return safe;
}

function oauthRecordForState(model = {}, provider = "", state = "") {
  const states = model.oauthStates || [];
  const record = states.find(item => item.provider === provider && item.state === state);
  if (record) return record;
  const signed = validateSignedOAuthState(provider, state);
  return signed.ok ? signed.record : null;
}

function recordOAuthEvent(model = {}, input = {}) {
  if (!model || typeof model !== "object") return null;
  const record = input.record || {};
  const state = input.state || record.state || "";
  const ownerUserId = input.ownerUserId || record.ownerUserId || record.userId || "";
  const workspaceId = input.workspaceId || record.workspaceId || (ownerUserId ? "" : "local-dev-workspace");
  const event = {
    id: uid("oauth-event"),
    type: "oauth-event",
    at: new Date().toISOString(),
    provider: String(input.provider || record.provider || "unknown"),
    platform: String(input.platform || record.platform || input.provider || record.provider || "unknown"),
    event: String(input.event || "oauth_event"),
    outcome: String(input.outcome || ""),
    ownerUserId,
    workspaceId,
    deviceId: input.deviceId || record.deviceId || "",
    deviceName: input.deviceName || record.deviceName || "",
    callbackPath: input.callbackPath || "",
    redirectUri: input.redirectUri || record.redirectUri || "",
    oauthMode: input.oauthMode || record.oauthMode || "",
    scopes: Array.isArray(input.scopes) ? input.scopes : Array.isArray(record.requestedScopes) ? record.requestedScopes : [],
    stateFingerprint: oauthStateFingerprint(state),
    details: safeOAuthEventDetails(input.details || {})
  };
  if (input.error) event.details.error = String(input.error).slice(0, 300);
  if (input.message) event.details.message = String(input.message).slice(0, 300);
  model.oauthEvents = Array.isArray(model.oauthEvents) ? model.oauthEvents : [];
  model.oauthEvents.unshift(event);
  model.oauthEvents = model.oauthEvents.slice(0, 250);
  oauthRuntimeLog(event.provider, event.event, {
    outcome: event.outcome,
    ownerUserId: event.ownerUserId || null,
    workspaceId: event.workspaceId || null,
    stateHash: event.stateFingerprint?.sha256 || null
  });
  return event;
}

function recordOAuthCallbackIngress(model = {}, url = null, req = null) {
  if (!url || req?.method !== "GET") return null;
  const match = url.pathname.match(/^\/api\/oauth\/([^/]+)\/callback$/);
  if (!match) return null;
  const provider = match[1];
  const state = url.searchParams.get("state") || "";
  const record = state ? oauthRecordForState(model, provider, state) : null;
  const returnedError = url.searchParams.get("error_description") || url.searchParams.get("error") || "";
  const hasCode = url.searchParams.has("code");
  const outcome = returnedError ? "provider-error" : hasCode ? "code-received" : "missing-code";
  return recordOAuthEvent(model, {
    provider,
    platform: record?.platform || provider,
    event: "callback_received",
    outcome,
    state,
    record,
    callbackPath: url.pathname,
    details: {
      hasCode,
      hasState: Boolean(state),
      returnedError: returnedError || "",
      queryKeys: [...url.searchParams.keys()].filter(key => !/^code$/i.test(key)).slice(0, 12)
    }
  });
}

function oauthConnectedAccountForRecord(model = {}, record = {}, owner = null) {
  const platform = record.platform || record.provider || "";
  const accounts = model.connectedAccounts || [];
  return accounts.find(account => account.platform === platform && (!owner || ownedByUser(account, owner.id)) && isRealConnectedAccount(account))
    || accounts.find(account => account.oauthProvider === record.provider && (!owner || ownedByUser(account, owner.id)) && isRealConnectedAccount(account))
    || accounts.find(account => account.platform === platform && (!owner || ownedByUser(account, owner.id)))
    || null;
}

function canReadOAuthDebugLog(user = null) {
  if (!user) return runtimeMode !== "vercel";
  return Boolean(isSignupOwnerEmail(user.email));
}

function oauthDebugLog(model = {}, session = null) {
  const rows = visibleWorkspaceRecords(model.oauthEvents || [], session)
    .sort((a, b) => Date.parse(b.at || "") - Date.parse(a.at || ""))
    .slice(0, 100)
    .map(event => {
      const account = oauthConnectedAccountForRecord(model, event, session?.user || null);
      const currentState = providerAccountConnectionState(account || {});
      const resolvedByCurrentEvidence = event.event === "callback_complete"
        && event.outcome === "error"
        && currentState.connected;
      const details = { ...(event.details || {}) };
      if (resolvedByCurrentEvidence) {
        details.priorError = details.error || "Earlier callback persistence verification did not complete.";
        details.error = "";
        details.message = "Resolved: current encrypted-token and provider identity evidence is connected.";
      }
      return {
        id: event.id,
        at: event.at,
        provider: event.provider,
        platform: event.platform,
        event: event.event,
        outcome: resolvedByCurrentEvidence ? "resolved" : event.outcome,
        ownerUserId: event.ownerUserId || "",
        workspaceId: event.workspaceId || "",
        deviceName: event.deviceName || "",
        callbackPath: event.callbackPath || "",
        redirectUri: event.redirectUri || "",
        oauthMode: event.oauthMode || "",
        scopes: event.scopes || [],
        stateFingerprint: event.stateFingerprint || null,
        details,
        currentConnection: account ? publicAccount(account) : null
      };
    });
  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    adminOnly: true,
    summary: {
      total: rows.length,
      providers: [...new Set(rows.map(row => row.provider))].length,
      callbacks: rows.filter(row => row.event === "callback_received").length,
      stateAccepted: rows.filter(row => row.event === "state_validation" && row.outcome === "accepted").length,
      stateRejected: rows.filter(row => row.event === "state_validation" && row.outcome === "rejected").length,
      tokenResults: rows.filter(row => row.event === "token_exchange_result").length
    },
    rows
  };
}

