      const installationLink = safeManychatInstallationLink(verified?.data?.installation_link);
      if (!installationLink) throw new Error("Manychat accepted the profile key but did not return a safe template installation link.");
      const keyHash = crypto.createHash("sha256").update(apiKey).digest("hex").slice(0, 20);
      const now = new Date().toISOString();
      const profileAccount = upsertConnectedAccount(model, {
        id: `acct-manychat-profile-${keyHash}`,
        platform: "manychat_profile",
        oauthProvider: "manychat",
        providerAccountId: `profile-${keyHash}`,
        name: "Manychat Templates",
        displayName: "Manychat Profile Templates",
        handle: "Profile Public API",
        accountType: "profile-template",
        status: "connected",
        connectedAt: now,
        credentialUpdatedAt: now,
        credential: encryptedToken(apiKey),
        refreshCredential: null,
        tokenType: "Bearer API key",
        scopes: ["profile_public_api", "template_install_links"],
        apiAccessModel: "customer-profile-public-api-key",
        profile: { templateId, lastInstallationLink: installationLink, lastLinkCreatedAt: now },
        connectionEvidence: "Manychat Profile API generated a single-use installation link and the encrypted key was stored for this workspace.",
        ...accountOwnerPatch(session.user)
      });
      model.integrations = { ...(model.integrations || {}), manychatProfile: "Manychat Profile Template API connected" };
      await saveModelForUser(model, session.user);
