    const connectedAccountId = await normalizedElevenlabsAccountId(session.user, account);
    const rows = connectedAccountId ? await optionalSupabaseRequest(
      `/provider_api_rate_buckets?workspace_id=eq.${encodeURIComponent(workspaceModelIdForUser(session.user))}&connected_account_id=eq.${encodeURIComponent(connectedAccountId)}&provider=eq.elevenlabs&select=bucket,window_started_at,window_seconds,used,limit_value,updated_at&order=updated_at.desc&limit=100`
    ) : [];
    refreshSessionCookieIfNeeded(res, session);
