    if (input.live === true) return json(res, 409, { ok: false, error: "This route saves planning drafts only and cannot launch or spend money." });
    const provider = String(input.provider || "meta").trim().toLowerCase();
    if (!["meta", "google", "pinterest", "reddit", "x"].includes(provider)) {
      return json(res, 400, { ok: false, error: "Choose Meta, Google, Pinterest, Reddit, or X for this ad draft." });
    }
    const title = String(input.title || "").trim().slice(0, 200);
    const objective = String(input.objective || "").trim().slice(0, 160);
    const audience = String(input.audience || "").trim().slice(0, 2000);
    const creative = String(input.creative || input.copy || "").trim().slice(0, 5000);
    const dailyBudget = Number(input.dailyBudget || 0);
