    const raw = await bodyText(req);
    const signature = String(req.headers["x-li-signature"] || "");
    if (!validLinkedInWebhookSignature(raw, signature)) return json(res, 401, { ok: false, error: "Invalid LinkedIn webhook signature." });
    let payload = {};
    try {
      payload = raw ? JSON.parse(raw) : {};
    } catch {
      return json(res, 400, { ok: false, error: "Invalid LinkedIn webhook payload." });
    }
    if (payload.type !== "ORGANIZATION_SOCIAL_ACTION_NOTIFICATIONS" || !Array.isArray(payload.notifications)) {
      return json(res, 400, { ok: false, error: "Unsupported LinkedIn webhook event type." });
    }
    for (const notification of payload.notifications.slice(0, 10)) {
      const event = linkedInWebhookEvent(notification);
      let claim;
      try {
        claim = await claimDurableWebhookEvent("linkedin", event);
      } catch {
        return json(res, 503, { ok: false, error: "LinkedIn event ledger is temporarily unavailable. LinkedIn should retry this webhook." });
      }
      if (!claim.claimed) continue;
      try {
        await applyLinkedInWebhookEvent(notification);
        await completeDurableWebhookEvent("linkedin", event);
      } catch (error) {
        await completeDurableWebhookEvent("linkedin", event, error.message);
        return json(res, 500, { ok: false, error: "LinkedIn webhook notification could not be synchronized. LinkedIn should retry." });
      }
    }
    res.writeHead(204);
    return res.end();
